INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-9amhealth', '9amhealth', 'join9am.com', 'https://join9am.com/', '9amHealth', 'Virtual cardiometabolic specialty care for weight, diabetes, blood pressure, and labs.', 'Cardiometabolic care is scattered across prescriptions, labs, coaching, devices, and insurance. 9amHealth wraps those pieces into virtual specialty care with at-home tests, connected devices, GLP-1 support, care-team messaging, and employer programs. Unlike a narrow weight-loss app, it publishes outcome ranges for A1c, blood pressure, and weight. The risk is payer and employer adoption beyond early proof.', '{"verified_at": "2026-06-06", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://join9am.com/", "type": "official"}, {"id": "funding_1", "label": "9amHealth Series B announcement", "url": "https://www.prnewswire.com/news-releases/9amhealth-raises-26m-to-expand-into-chronic-conditions-driving-the-majority-of-employer-pharmacy-spend-302769972.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes virtual specialty care for weight loss, diabetes, and heart health, with care plans, prescriptions, labs, devices, and specialist support.", "source_ids": ["official_site"]}, {"claim": "9amHealth publishes outcome claims for GLP-1 and non-GLP-1 weight reduction, A1c improvement, and blood-pressure reduction on its public site.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Employers, benefits teams, and patients managing cardiometabolic conditions across prescriptions, labs, devices, and coaching.", "category": "HealthTech", "differentiation": "9amHealth bundles specialty care, pharmacy support, labs, connected devices, and care-team messaging instead of isolating weight, diabetes, or hypertension workflows.", "why_now": "The May 2026 Series B targets chronic conditions that drive a large share of employer pharmacy spend and demand virtual-first management."}, "risks": [{"claim": "The open question is whether employer and payer adoption expands enough to support broad chronic-care coverage beyond early measured cohorts.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 3, 'At-home cardiometabolic care', 'HealthTech', 'Series B', '$26M', NULL, NULL, NULL, 'US', 'virtual care,diabetes,weight loss,cardiometabolic,employers', 'Define Ventures', '{"careers": "https://jobs.ashbyhq.com/join9am"}', 0, '9amhealth.webp', 'ready', 'published', 'manual', '2026-06-06 05:56:19', '2026-06-06 05:56:19') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-airspeed', 'airspeed', 'www.goairspeed.com', 'https://www.goairspeed.com/', 'Airspeed', 'Revenue-team AI agents for customer understanding, prep, follow-up, and CRM work.', 'Revenue teams already have call recorders, CRM fields, and dashboards; the missing layer is action. Airspeed uses multi-model agents, customer memory, and integrations with Salesforce, HubSpot, Gmail, Outlook, Zoom, and Teams to prep calls, draft follow-ups, and keep CRM clean. Unlike alerts, it tries to close the workflow loop. The risk is proving buyers trust agents inside 200-customer revenue operations.', '{"verified_at": "2026-06-06", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.goairspeed.com/", "type": "official"}, {"id": "funding_1", "label": "Airspeed Series A story", "url": "https://www.goairspeed.com/blog/the-story-behind-airspeeds-20m-series-a", "type": "funding"}], "product_evidence": [{"claim": "The official site describes agents for call prep, follow-ups, CRM hygiene, coaching plans, and integrations with Salesforce, HubSpot, Slack, Gmail, Outlook, Zoom, and Teams.", "source_ids": ["official_site"]}, {"claim": "The Series A story says Airspeed is approaching 200 customers and frames the product around context layers, sub-agent orchestration, and Customer 360.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Revenue, sales, customer-success, and go-to-market teams with scattered customer context.", "category": "SaaS", "differentiation": "Airspeed sells an action layer that uses commercial memory and connected GTM tools rather than another sales-intelligence dashboard.", "why_now": "The June 2026 Series A follows fast customer growth as revenue teams test agentic workflows against CRM and meeting data."}, "risks": [{"claim": "The open question is whether enterprise buyers will allow autonomous agents to act inside revenue operations instead of keeping them in draft-only mode.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Revenue agents with memory', 'SaaS', 'Series A', '$20M', NULL, NULL, NULL, 'Europe', 'revenue operations,ai agents,crm,sales,customer data', 'DN Capital', '{"careers": "https://glyphic.jobs.personio.com/?language=en"}', 1, 'airspeed.webp', 'ready', 'published', 'manual', '2026-06-06 05:56:19', '2026-06-06 05:56:19') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-alcatraz', 'alcatraz', 'www.alcatraz.ai', 'https://www.alcatraz.ai', 'Alcatraz', 'Privacy-focused facial authentication for physical access control and tailgating detection.', 'The clever bet is that AI data centers need a better lock, not another badge reader. Alcatraz turns Face ID into building access with Rock X, edge authentication, 3D liveness, tailgating detection, and opt-in enrollment; it says 5M employees are protected. Unlike surveillance-first facial recognition, the pitch is authentication that forgets the face after the door opens. The risk is whether buyers trust the privacy distinction once regulators get involved.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.alcatraz.ai", "type": "official"}, {"id": "funding_1", "label": "Alcatraz", "url": "https://www.alcatraz.ai/press-release/alcatraz-raises-50-million-series-b", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Alcatraz: Privacy-focused facial authentication for physical access control and tailgating detection.", "source_ids": ["official_site"]}, {"claim": "Alcatraz turns Face ID into building access with Rock X, edge authentication, 3D liveness, tailgating detection, and opt-in enrollment; it says 5M employees are protected.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "Face ID for secure buildings", "why_now": "Recent source-backed funding and public product evidence make physical security, biometrics, ai infrastructure worth tracking."}, "risks": [{"claim": "The risk is whether buyers trust the privacy distinction once regulators get involved.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Face ID for secure buildings', 'Other', 'Series B', '$50M', NULL, NULL, NULL, 'US', 'physical security,biometrics,ai infrastructure,access control', 'BlackPeak Capital', '{"careers": "https://www.alcatraz.ai/company/careers"}', 1, 'alcatraz.webp', 'ready', 'published', 'manual', '2026-05-02 09:59:18', '2026-05-02 09:59:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-all3', 'all3', 'www.all3.com', 'https://www.all3.com', 'All3', 'AI design, robotic fabrication, and on-site assembly for buildings.', 'Construction robotics usually breaks between design software and the job site. Unlike prefab software, All3 is trying the harder route: AI-generated architecture, real-time fabrication software, timber components, and Mantis robots that install, fasten, finish, and inspect on site. The public pages claim 100+ in-house engineers and a cost-your-project flow, while TNW reports 100,000+ square meters processed for Germany. The risk is whether vertical integration survives permits and messy sites.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.all3.com", "type": "official"}, {"id": "funding_1", "label": "TNW", "url": "https://thenextweb.com/news/all3-25m-seed-construction-robots-ai-housing", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes All3: AI design, robotic fabrication, and on-site assembly for buildings.", "source_ids": ["official_site"]}, {"claim": "VentureDex product review notes that unlike prefab software, All3 is trying the harder route: AI-generated architecture, real-time fabrication software, timber components, and Mantis robots that install, fasten, finish, and inspect on site.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$25M Seed for construction robots", "why_now": "Recent source-backed funding and public product evidence make construction robotics, physical ai, robotic manufacturing worth tracking."}, "risks": [{"claim": "The risk is whether vertical integration survives permits and messy sites.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$25M Seed for construction robots', 'AI / ML', 'Seed', '$25M', NULL, NULL, NULL, 'Europe', 'construction robotics,physical ai,robotic manufacturing,housing', 'RTP Global', '{"linkedin": "https://www.linkedin.com/company/all3"}', 1, 'all3.webp', 'ready', 'published', 'manual', '2026-05-04 06:18:58', '2026-05-04 06:18:58') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-allo', 'allo', 'allo.restaurant', 'https://allo.restaurant/', 'allO', 'Restaurant operating system for POS, reservations, ordering, inventory, and payments.', 'The smart move is treating restaurant software as one floor plan instead of twenty tabs. allO shows POS, reservations, kitchen monitor, scan-to-order, webshop, delivery, inventory, payments, and an app login for German restaurants. Unlike generic POS suites, it narrows the workflow to table service, hotpot, buffets, and kitchen handoffs, with claims like 30% faster service.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://allo.restaurant/", "type": "official"}, {"id": "funding_1", "label": "Dealroom.co", "url": "https://app.dealroom.co/news/feed/allo-raises-14m-series-a-led-by-zigg-capital-to-scale-ai-native-restaurant-operating-system-across-europe", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes allO: Restaurant operating system for POS, reservations, ordering, inventory, and payments.", "source_ids": ["official_site"]}, {"claim": "allO shows POS, reservations, kitchen monitor, scan-to-order, webshop, delivery, inventory, payments, and an app login for German restaurants.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Restaurant OS with POS depth", "why_now": "Recent source-backed funding and public product evidence make restaurants, pos, inventory worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Restaurant OS with POS depth', 'SaaS', 'Series A', '$14M', NULL, NULL, NULL, 'Europe', 'restaurants,pos,inventory,payments,operations', 'Zigg Capital', '{"careers": "https://allo.restaurant/careers"}', 1, 'allo.webp', 'ready', 'published', 'manual', '2026-05-26 09:43:21', '2026-05-26 09:43:21') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-amperos', 'amperos', 'www.amperos.com', 'https://www.amperos.com', 'Amperos', 'AI denial management and insurance collections for providers.', 'Denial management usually dies in workqueues; this tries to make it an owned operating system. Amperos works claims from submission to payment, with AI agents handling payor portals, calls, corrected claims, records, and appeals while RCM specialists cover hard cases. Unlike tools that only draft letters or make calls, the bet is full workflow ownership, visible in 500,000+ claims and 3,000 clinical locations. The risk is healthcare edge cases pulling humans back into the loop.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.amperos.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/amperos-health-secures-16m-investment-as-it-launches-industrys-first-ai-native-denial-management-and-revenue-recovery-platform-302749446.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Amperos: AI denial management and insurance collections for providers.", "source_ids": ["official_site"]}, {"claim": "Amperos works claims from submission to payment, with AI agents handling payor portals, calls, corrected claims, records, and appeals while RCM specialists cover hard cases.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "$16M Series A for AI denials", "why_now": "Recent source-backed funding and public product evidence make healthcare ai, denial management, revenue cycle worth tracking."}, "risks": [{"claim": "The risk is healthcare edge cases pulling humans back into the loop.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$16M Series A for AI denials', 'HealthTech', 'Series A', '$16M', NULL, NULL, NULL, 'US', 'healthcare ai,denial management,revenue cycle,claims', 'Bessemer Venture Partners, Uncork Capital, Neo', '{"linkedin": "https://www.linkedin.com/company/amperos-health"}', 1, 'amperos.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-andera', 'andera', 'www.andera.ai', 'https://www.andera.ai/', 'Andera', 'Audit AI platform automating SOX control testing and workpapers.', 'Audit work dies in Excel because the evidence, test matrix, and sign-off trail live in different places. Andera says its Audit AI can automate SOX control testing, email control owners, flag exceptions, and save 70% of control-testing costs. Unlike GRC suites that manage checklists, it tries to produce auditor-ready workpapers. The risk is whether external auditors trust AI-generated evidence at scale.', '{"verified_at": "2026-06-19", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.andera.ai/", "type": "official"}, {"id": "funding_1", "label": "Lightspeed investment note", "url": "https://lsvp.com/stories/audits-moment-has-arrived-why-we-invested-in-andera/", "type": "funding"}], "product_evidence": [{"claim": "The homepage says Andera automates SOX control testing and saves 70% of control-testing costs with AI and no setup needed.", "source_ids": ["official_site"]}, {"claim": "The product surface shows Audit AI generating workpapers in auditor formats and reviewing Snowflake user-access control evidence.", "source_ids": ["official_site"]}, {"claim": "The site describes evidence gathering by emailing control owners, checking evidence relevance, and escalating non-responses.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, internal audit, SOX, and compliance teams that still assemble evidence, workpapers, and exception follow-up manually.", "category": "Audit and compliance automation", "differentiation": "Andera tries to generate auditor-ready control-testing workpapers rather than only tracking compliance tasks.", "why_now": "SOX teams are under pressure to cut repetitive testing cost while keeping review trails acceptable to external auditors."}, "risks": [{"claim": "The risk is that customers may still need substantial human review if external auditors resist relying on AI-generated testing evidence.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI SOX workpapers', 'SaaS', 'Series A', '$37M', NULL, NULL, NULL, 'US', 'audit,sox,compliance,finance automation', 'Lightspeed Venture Partners', '{"careers": "https://www.andera.ai/careers"}', 1, 'andera.webp', 'ready', 'published', 'manual', '2026-06-19 05:55:41', '2026-06-19 05:55:41') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-arcade', 'arcade', 'www.arcade.dev', 'https://www.arcade.dev/', 'Arcade', 'Authorization, tool execution, and audit runtime for production AI agents.', 'The bet is that agents need permissions before they need more demos. Arcade sits between models and business systems, adds OAuth and IDP-aware authorization, thousands of MCP tools, policy hooks, and an audit trail for every action. Unlike API wrappers that just hand agents a key, it treats each tool call as a governed act on behalf of a user. The hard part is whether security teams standardize on Arcade before the agent frameworks absorb this layer.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.arcade.dev/", "type": "official"}, {"id": "official_docs", "label": "Official documentation", "url": "https://docs.arcade.dev/", "type": "official"}, {"id": "funding_1", "label": "BusinessWire funding announcement", "url": "https://www.businesswire.com/news/home/20260615229631/en/Arcade-Raises-%2460M-to-Become-the-Secure-Action-Layer-Behind-Every-Production-AI-Agent", "type": "funding"}], "product_evidence": [{"claim": "The official homepage positions Arcade as the runtime between agents and business systems, combining auth, tools, and governance in one layer.", "source_ids": ["official_site"]}, {"claim": "Arcade describes agent authorization where agents act as real users with dynamic permissions, existing IDPs plug in, and credentials stay inside the runtime.", "source_ids": ["official_site"]}, {"claim": "The official site describes a central control plane that records what an agent did, on behalf of which user, in which system, with cloud, on-prem, air-gapped, and hybrid deployment options.", "source_ids": ["official_site"]}, {"claim": "The docs expose a broad tool catalog across productivity apps, communication tools, developer systems, payments, search, sales, databases, and customer support integrations.", "source_ids": ["official_docs"]}, {"claim": "The funding announcement says Arcade raised $60M Series A led by SYN Ventures and has shipped more than 8,000 MCP tools for delegated user authorization.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise AI platform teams, security engineers, and developers putting tool-using agents into production.", "category": "Agent Infrastructure", "differentiation": "Arcade focuses on the action layer after model choice, tying identity-aware authorization, tool execution, policy, and audit logs to each agent tool call.", "why_now": "Enterprise agent pilots are moving toward production, where security teams need evidence of who authorized each action and what system was touched."}, "risks": [{"claim": "The open question is whether Arcade can remain the neutral action runtime if MCP clients, cloud vendors, and agent frameworks add overlapping authorization and audit layers.", "basis": "VentureDex editorial assessment based on official product evidence, docs, and current Series A coverage."}]}', 5, '$60M Series A for agent action security', 'DevTools', 'Series A', '$60M', NULL, NULL, NULL, 'US', 'ai agents,mcp,authorization,security,developer tools', 'SYN Ventures', '{"careers": "https://jobs.ashbyhq.com/arcadeai"}', 1, 'arcade.webp', 'ready', 'published', 'manual', '2026-06-16 16:27:39', '2026-06-16 16:27:39') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-architect-labs', 'architect-labs', 'architectlabs.com', 'https://architectlabs.com/', 'Architect Labs', 'AI design partner for custom silicon and end-to-end chip verification.', 'The useful bet is that chip design needs a co-designer, not another EDA plug-in. Architect Labs says its AI flow designs and provably verifies chips end-to-end, and the founding team has taped out 80+ production chips. Unlike agent wrappers around brittle toolchains, it wants to work as a design partner for AI labs and fabless teams. The risk is whether a service-led model can scale past a few hard tapeouts.', '{"verified_at": "2026-06-19", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://architectlabs.com/", "type": "official"}, {"id": "funding_1", "label": "Official seed funding announcement", "url": "https://architectlabs.com/blog/seed", "type": "funding"}], "product_evidence": [{"claim": "The homepage says Architect Labs is building an AI system that explores, designs and provably verifies chips for demanding workloads.", "source_ids": ["official_site"]}, {"claim": "The seed announcement says the system is intended to design and provably verify chips end-to-end for custom silicon programs.", "source_ids": ["funding_1"]}, {"claim": "The announcement says Architect is not building EDA tools or wrappers, but a design partner that reasons about hardware, software, and manufacturing constraints.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Frontier AI labs, hyperscalers, OEMs, and fabless chip teams trying to build custom silicon faster.", "category": "AI silicon design infrastructure", "differentiation": "Architect aims to automate design and formal verification together, rather than adding an agent beside existing EDA workflows.", "why_now": "AI workloads are changing faster than traditional chip-design programs can safely predict and tape out new architectures."}, "risks": [{"claim": "The open question is whether end-to-end chip design can scale beyond high-touch expert engagements and still reach tapeout-quality reliability.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI silicon design partner', 'AI / ML', 'Seed', '$24M', NULL, NULL, NULL, 'US', 'ai chips,eda,formal verification,semiconductors', 'Kindred Ventures', '{"careers": "https://architectlabs.com/careers"}', 1, 'architect-labs.webp', 'ready', 'published', 'manual', '2026-06-19 05:55:41', '2026-06-19 05:55:41') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-arkeus', 'arkeus', 'arkeus.com', 'https://arkeus.com/products/the-warden', 'Arkeus', 'AI hyperspectral sensing systems for autonomous defense platforms.', 'The wager is visual intelligence for drones that can see when ordinary cameras give up. Arkeus exposes WARDEN, HSOR, S-HSOR, and optical terminal guidance, and says its sensors detected targets up to 8x farther in degraded conditions. Unlike generic autonomy software, the product bet is a sensing layer built for edge ISR. The public surface is thinner than the defense contracts, but the technical wedge is sharp.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://arkeus.com/products/the-warden", "type": "official"}, {"id": "funding_1", "label": "Arkeus", "url": "https://arkeus.com/news/tectonic-defense-covers-arkeus-series-a-and-the-technology-giving-autonomous-systems-a-sixth-sense", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Arkeus: AI hyperspectral sensing systems for autonomous defense platforms.", "source_ids": ["official_site"]}, {"claim": "Arkeus exposes WARDEN, HSOR, S-HSOR, and optical terminal guidance, and says its sensors detected targets up to 8x farther in degraded conditions.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "8x range in degraded vision", "why_now": "Recent source-backed funding and public product evidence make defense tech, hyperspectral sensing, autonomy worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '8x range in degraded vision', 'AI / ML', 'Series A', '$18M', NULL, NULL, NULL, 'Global / Remote', 'defense tech,hyperspectral sensing,autonomy,edge ai', 'QIC Ventures', '{"careers": "https://arkeus.com/careers"}', 1, 'arkeus.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-arpio', 'arpio', 'arpio.io', 'https://arpio.io/', 'Arpio', 'Automated cloud disaster recovery platform for AWS and Azure.', 'The useful bet is that disaster recovery should be rehearsed software, not a binder of runbooks. Arpio maps cloud dependencies, replicates infrastructure, tests failover, and automates failback across AWS and Azure, with customer evidence from Choice Hotels and Scotts Miracle-Gro. Unlike backup tools that stop at restore points, it owns the orchestration step. The risk is whether AI-native recovery claims stay credible under real outage pressure.', '{"verified_at": "2026-06-04", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://arpio.io/", "type": "official"}, {"id": "funding_1", "label": "citybiz funding report", "url": "https://www.citybiz.co/article/855011/arpio-raises-15-million-to-expand-cloud-recovery-automation-platform/", "type": "funding"}], "product_evidence": [{"claim": "The official site says Arpio provides cloud disaster recovery for AWS and Azure, including dependency mapping and infrastructure replication.", "source_ids": ["official_site"]}, {"claim": "The product copy lists safe failover testing, predictable RTO and RPO, push-button recovery, and automated failback workflows.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Cloud infrastructure, SRE, security, and business-continuity teams responsible for critical workloads.", "category": "DevTools", "differentiation": "Arpio owns failover orchestration, testing, dependency mapping, and failback rather than stopping at backup or restore points.", "why_now": "The June 2026 Series A arrives as cloud teams face ransomware, provider outages, and recovery-time scrutiny across AWS and Azure."}, "risks": [{"claim": "The open question is whether AI-native recovery claims remain credible during real outage pressure.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Cloud DR orchestration', 'DevTools', 'Series A', '$15M', NULL, NULL, NULL, 'US', 'cloud disaster recovery,aws,azure,ransomware,failover', 'S3 Ventures, Paladin Capital Group', '{"careers": "https://arpio.io/careers/"}', 1, 'arpio.webp', 'ready', 'published', 'manual', '2026-06-04 05:59:59', '2026-06-04 05:59:59') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-attention', 'attention', 'www.attention.com', 'https://www.attention.com/', 'Attention', 'AI revenue-operations platform that turns sales conversations into actions.', 'The useful move is that Attention refuses to stop at call notes. It records voice and sales touchpoints, then drafts follow-ups, updates CRM fields, runs agent actions, and keeps an audit trace for each decision. Compared to another Gong clone, the dataset compounds because the system does the next step. The risk is whether enterprise teams let it execute enough work to prove outcome lift.', '{"verified_at": "2026-06-24", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.attention.com/", "type": "official"}, {"id": "official_docs", "label": "Attention documentation", "url": "https://docs.attention.com/", "type": "product"}, {"id": "official_agents", "label": "AI sales agents product page", "url": "https://www.attention.com/product/ai-sales-agents", "type": "product"}, {"id": "funding_1", "label": "GlobeNewswire Series B announcement", "url": "https://www.globenewswire.com/news-release/2026/06/23/3315763/0/en/attention-raises-30m-series-b-to-build-the-ai-system-that-runs-revenue-teams-not-just-records-them.html", "type": "funding"}], "product_evidence": [{"claim": "The homepage describes agents that learn from sales conversations and handle follow-ups, CRM updates, next steps, and coaching.", "source_ids": ["official_site"]}, {"claim": "The product navigation exposes Super Agent, AI sales agents, Ask Attention Anything, call recording, forecasting, coaching, follow-up automation, and CRM auto-update modules.", "source_ids": ["official_site", "official_agents"]}, {"claim": "The documentation provides setup and workspace guidance for using Attention as a revenue intelligence system rather than a static transcript store.", "source_ids": ["official_docs"]}], "market_context": {"primary_user": "Revenue operations leaders, sales managers, and GTM teams trying to reduce CRM hygiene and follow-up work.", "category": "Revenue operations", "differentiation": "Attention closes the loop from conversation data to executed CRM, follow-up, coaching, and agent actions instead of stopping at call review.", "why_now": "Sales teams have more recorded customer data than they can process manually, and buyers expect faster follow-through across every touchpoint."}, "risks": [{"claim": "The open question is whether customers will let Attention agents execute enough workflow to create measurable lift beyond note taking.", "basis": "VentureDex editorial assessment based on the product surface, docs, and funding-source review."}]}', 4, '$30M Series B for sales agents', 'SaaS', 'Series B', '$30M', NULL, NULL, NULL, 'US', 'sales,crm,revenue operations,ai agents,conversation intelligence', 'RTP Global', '{"careers": "https://www.attention.com/careers"}', 1, 'attention.webp', 'ready', 'published', 'manual', '2026-06-24 06:00:32', '2026-06-24 06:00:32') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-balerion', 'balerion', 'balerion.ai', 'https://balerion.ai', 'Balerion', 'AI loan-intelligence platform for mortgage origination.', 'The smart move is starting where mortgage files actually break: income math, missing documents, NSF flags, and Fannie/Freddie overlays. Balerion Loan Intelligence is already used by FM Home Loans, a lender managing $2B+ in loan volume, and embeds into existing origination workflows. Unlike point AI tools, it wants to reason across the whole loan file. The risk is enterprise pilots turning into custom services.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://balerion.ai", "type": "official"}, {"id": "funding_1", "label": "Balerion", "url": "https://balerion.ai/press", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Balerion: AI loan-intelligence platform for mortgage origination.", "source_ids": ["official_site"]}, {"claim": "Balerion Loan Intelligence is already used by FM Home Loans, a lender managing $2B+ in loan volume, and embeds into existing origination workflows.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$2B lender using Loan Intelligence", "why_now": "Recent source-backed funding and public product evidence make mortgage, ai agents, fintech worth tracking."}, "risks": [{"claim": "The risk is enterprise pilots turning into custom services.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$2B lender using Loan Intelligence', 'Fintech', 'Seed', '$6M', NULL, NULL, NULL, 'US', 'mortgage,ai agents,fintech,loan origination', 'Kleiner Perkins', '{"twitter": "https://x.com/BalerionAI", "linkedin": "https://www.linkedin.com/company/balerion-ai/"}', 0, 'balerion.webp', 'ready', 'published', 'manual', '2026-05-03 06:28:30', '2026-05-03 06:28:30') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-basata', 'basata', 'www.basata.ai', 'https://www.basata.ai', 'Basata', 'AI referral intake and call handling for specialty practices.', 'Healthcare AI usually chases clinicians; this aims at the fax pile between referral and visit. Basata processes faxes, creates EHR charts, calls patients with voice agents, and claims 500,000 referrals processed with 100,000 in the last month. Unlike ambient scribes, the bet is owning the handoff before care starts. The risk is how much specialty-specific workflow knowledge has to be rebuilt practice by practice.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.basata.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/07/the-back-office-problem-that-explains-why-specialists-never-call-you-back/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Basata: AI referral intake and call handling for specialty practices.", "source_ids": ["official_site"]}, {"claim": "Basata processes faxes, creates EHR charts, calls patients with voice agents, and claims 500,000 referrals processed with 100,000 in the last month.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "$21M Series A for referral ops", "why_now": "Recent source-backed funding and public product evidence make healthcare ai, referrals, voice agents worth tracking."}, "risks": [{"claim": "The risk is how much specialty-specific workflow knowledge has to be rebuilt practice by practice.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$21M Series A for referral ops', 'HealthTech', 'Series A', '$21M', NULL, NULL, NULL, 'US', 'healthcare ai,referrals,voice agents,practice operations', 'Basis Set Ventures, Cowboy Ventures, Sofeon', NULL, 1, 'basata.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-bayshore', 'bayshore', 'www.bayshore.ai', 'https://www.bayshore.ai/', 'Bayshore', 'Governed AI front door for legal and compliance requests.', 'The bet is that compliance automation needs deterministic legal logic before another chat layer. Bayshore converts regulations and internal policies into machine-executable workflows, then routes requests through one front door with ISO 27001 controls, audit trails, and human escalation. Unlike generic contract assistants, it sells controlled rule execution for pharma, finance, and defense. The risk is whether expert configuration slows repeatable sales.', '{"verified_at": "2026-06-02", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.bayshore.ai/", "type": "official"}, {"id": "funding_1", "label": "TechFundingNews", "url": "https://techfundingnews.com/bayshore-earlybird-ai-agents-law-compliance/", "type": "funding"}], "product_evidence": [{"claim": "The official site describes a Legal & Compliance Frontdoor that runs every request from intake to decision with a full audit trail.", "source_ids": ["official_site"]}, {"claim": "The product page says regulations, policies, and expert interpretation become machine-executable logic with auto-resolution, escalation, and dashboards.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Legal, compliance, and risk teams inside regulated enterprises.", "category": "AI / ML", "differentiation": "Legal and policy logic is encoded into governed workflows rather than answered only through chat.", "why_now": "The June 2026 seed round funds enterprise legal-compliance automation as EU AI Act, DORA, NIS2, and audit-readiness demands increase."}, "risks": [{"claim": "The open question is whether Bayshore can turn expert-heavy legal configuration into a repeatable deployment model.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Legal compliance front door', 'AI / ML', 'Seed', '$8M', NULL, NULL, NULL, 'Europe', 'legal ai,compliance,agents,audit trails,regulated enterprise', 'Earlybird Venture Capital', NULL, 1, 'bayshore.webp', 'ready', 'published', 'manual', '2026-06-02 05:53:31', '2026-06-02 05:53:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-billables-ai', 'billables-ai', 'billables.ai', 'https://billables.ai/', 'Billables AI', 'AI timekeeping and task-intelligence platform for law firms.', 'The useful bet is that timekeeping should be inferred from work traces rather than reconstructed after the fact. Billables AI shows Microsoft 365, Teams, Adobe, Chrome, Edge, Zoom, and practice-platform integrations plus matter matching and narrative generation. Unlike passive timers, it focuses on task intelligence. The risk is lawyer adoption when privileged work and billing review meet AI suggestions.', '{"verified_at": "2026-06-11", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://billables.ai/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://billables.ai/careers", "type": "official"}, {"id": "funding_1", "label": "Billables AI Series A funding announcement", "url": "https://www.globenewswire.com/news-release/2026/06/09/3309069/0/en/billables-ai-raises-10-million-series-a-to-accelerate-ai-powered-operational-intelligence-for-law-firms.html", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Billables AI as automated timekeeping and task intelligence for lawyers, consultants, and professional services.", "source_ids": ["official_site"]}, {"claim": "Billables AI describes workflow tracking, AI matter matching, narrative generation, and daily customized billable activity reports.", "source_ids": ["official_site"]}, {"claim": "The product surface lists integrations with Microsoft 365, Teams, Adobe, Chrome, Edge, Zoom, and practice-management platforms.", "source_ids": ["official_site"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Lawyers, consultants, finance teams, and professional-services operators responsible for accurate billable-time capture.", "category": "SaaS", "differentiation": "Billables AI infers time and task context from work activity rather than relying on manual timers or after-the-fact reconstruction.", "why_now": "Professional-services firms are trying to reduce revenue leakage while maintaining review control over client, matter, and narrative entries."}, "risks": [{"claim": "The open question is how firms balance automated time suggestions with privileged context, lawyer review habits, and client billing trust.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Legal timekeeping AI', 'SaaS', 'Series A', '$10M', NULL, NULL, NULL, 'US', 'legaltech,timekeeping,ai agents,professional services,workflow automation', 'Avenue Growth Partners', '{"careers": "https://billables.ai/careers"}', 1, 'billables-ai.webp', 'ready', 'published', 'manual', '2026-06-11 06:04:13', '2026-06-11 06:04:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-bland', 'bland', 'www.bland.ai', 'https://www.bland.ai/', 'Bland', 'Enterprise voice AI platform for regulated, long-running phone conversations.', 'The bet is that voice AI only matters when it survives the ugly calls, not the appointment-demo script. Bland builds its own phone models, tests scenarios before rollout, supports Voice, SMS, iMessage, Web Chat, and plugs into Twilio, Salesforce, HubSpot, Genesys, Five9, and Amazon Connect. Unlike call-center bots tuned for short routing, it is aiming at 30-minute regulated conversations. The risk is whether compliance-heavy customers accept enough automation to justify the operational lift.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.bland.ai/", "type": "official"}, {"id": "official_docs", "label": "Official documentation", "url": "https://docs.bland.ai/welcome-to-bland", "type": "official"}, {"id": "funding_1", "label": "PRNewswire funding announcement", "url": "https://www.prnewswire.com/news-releases/bland-surpasses-100m-funding-with-new-series-c-to-advance-voice-ai-for-complex-high-stakes-conversations-302801583.html", "type": "funding"}], "product_evidence": [{"claim": "The official homepage positions Bland as voice AI for regulated industries and high-stakes phone calls where security and trust matter.", "source_ids": ["official_site"]}, {"claim": "Bland describes build, test, rollout, omnichannel deployment, observability, and integrations across telephony, CRM, scheduling, contact center, and automation tools.", "source_ids": ["official_site"]}, {"claim": "The official site lists SOC 2, HIPAA BAA, GDPR DPA, PCI DSS v4.0, AES-256 at rest, TLS 1.3 in transit, HSM-backed keys, data residency, MFA, and self-hosted or on-premises deployment options.", "source_ids": ["official_site"]}, {"claim": "The docs describe inbound and outbound calls, live API calls during calls, personas, batch calls, embedded agents, API keys, and starter guides.", "source_ids": ["official_docs"]}, {"claim": "The funding announcement says Bland raised a $50M Series C led by Dell Technologies Capital and handles millions of long conversations per week across regulated industries.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise operations, support, healthcare, insurance, and financial-services teams that run complex inbound and outbound phone workflows.", "category": "Voice AI", "differentiation": "Bland pairs in-house voice models with testing, omnichannel memory, compliance controls, and contact-center integrations for long regulated conversations rather than simple call deflection.", "why_now": "Voice AI buyers are moving from scripted appointment booking toward higher-liability calls where latency, interruption handling, audit trails, and security review matter."}, "risks": [{"claim": "The open question is whether regulated customers automate enough long, high-stakes calls to justify deep deployment work while managing false escalations and compliance review.", "basis": "VentureDex editorial assessment based on official product evidence, official docs, and current Series C coverage."}]}', 4, '$50M Series C for regulated voice AI', 'AI / ML', 'Series C', '$50M', NULL, NULL, NULL, 'US', 'voice ai,contact center,enterprise ai,regulated industries,automation', 'Dell Technologies Capital, HubSpot Ventures', '{"careers": "https://jobs.ashbyhq.com/bland"}', 1, 'bland.webp', 'ready', 'published', 'manual', '2026-06-16 16:27:39', '2026-06-16 16:27:39') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-boolsi', 'boolsi', 'boolsi.com', 'https://boolsi.com/', 'BoolSi', 'Compiler that turns software hotspots into verified FPGA co-processors.', 'This is software-to-silicon with the abstraction pointed at developers, not RTL teams. BoolSi marks a hot C/C++ function, emits a co-processor, driver and bitstream, then checks it against source behavior; its regex demo goes from 2.66 ms on ARM to 0.042 ms with 8 agents. Unlike HLS tools for chip specialists, the bet is that hardware becomes a build artifact. The risk is private-beta reality versus the benchmark.', '{"verified_at": "2026-06-19", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://boolsi.com/", "type": "official"}, {"id": "funding_1", "label": "Official seed announcement", "url": "https://boolsi.com/seed-announcement.html", "type": "funding"}], "product_evidence": [{"claim": "The homepage says BoolSi marks a hot C or C++ function and synthesizes it into custom digital logic beside the CPU.", "source_ids": ["official_site"]}, {"claim": "The site says the platform maps API calls, updates the BSP, produces the hardware bitstream, and verifies each generated agent against source behavior.", "source_ids": ["official_site"]}, {"claim": "The seed announcement says BoolSi trains ML models to learn program behavior and converge into analyzable digital circuits for FPGAs.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Embedded software teams in robotics and devices whose C or C++ workloads are bottlenecked on CPUs or microcontrollers.", "category": "Compiler and hardware-acceleration tooling", "differentiation": "BoolSi exposes hardware acceleration as a compiler output for software developers instead of an HDL project for chip specialists.", "why_now": "Robotics and edge devices need lower latency without every software team becoming a custom silicon team."}, "risks": [{"claim": "The key open question is whether private-beta customers see reliable gains outside controlled benchmark workloads and FPGA-friendly functions.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Software-to-FPGA compiler', 'DevTools', 'Seed', '$6M', NULL, NULL, 'Boston, MA', 'US', 'compilers,fpgas,embedded,hardware acceleration', 'Fine Structure Ventures', '{"careers": "https://boolsi.com/careers.html"}', 1, 'boolsi.webp', 'ready', 'published', 'manual', '2026-06-19 05:55:41', '2026-06-19 05:55:41') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-branchlab', 'branchlab', 'branchlab.com', 'https://branchlab.com/pathwai', 'BranchLab', 'AI audience platform for pharma commercialization.', 'The sharper idea is removing PHI from pharma targeting instead of pretending healthcare marketing is ordinary ads. Pathwai learns from de-identified health signals, clusters patient journeys, and cites outcomes like 2,000 extra patients reached in three weeks and 90% lower cost per patient. Compared with static audience files, it sells a learning system for commercial teams. The risk is whether better targeting feels like better healthcare to anyone outside pharma.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://branchlab.com/pathwai", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/branchlab-raises-26m-series-a-led-by-mckesson-ventures-to-bring-ai-to-pharma-commercialization-302770272.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes BranchLab: AI audience platform for pharma commercialization.", "source_ids": ["official_site"]}, {"claim": "Pathwai learns from de-identified health signals, clusters patient journeys, and cites outcomes like 2,000 extra patients reached in three weeks and 90% lower cost per patient.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "2,000 patients in 3 weeks", "why_now": "Recent source-backed funding and public product evidence make pharma, healthcare ai, audience targeting worth tracking."}, "risks": [{"claim": "The risk is whether better targeting feels like better healthcare to anyone outside pharma.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '2,000 patients in 3 weeks', 'HealthTech', 'Series A', '$26M', NULL, NULL, NULL, 'US', 'pharma,healthcare ai,audience targeting,commercialization', 'McKesson Ventures', '{"careers": "https://branchlab.com/careers"}', 1, 'branchlab.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-byron', 'byron', 'www.usebyron.com', 'https://www.usebyron.com/', 'Byron', 'AI tax-prep agents for CPA business-tax workflows.', 'The point is not a tax chatbot; it is a controlled worker inside CPA prep. Byron processes PDFs and K-1s, rolls prior-year returns into Excel workbooks, and keeps reviewer approval gates before export. Unlike horizontal agents that stop at document Q&A, it maps to SALY workpapers, trial balances, and book-to-tax reconciliation. The risk is whether demo-led CPA adoption scales before incumbents copy the narrow workflows.', '{"verified_at": "2026-06-02", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.usebyron.com/", "type": "official"}, {"id": "funding_1", "label": "Capital Brief", "url": "https://www.capitalbrief.com/briefing/ai-enabled-tax-platform-byron-secures-9m-seed-round-led-by-square-peg-96d44ac9-daba-4370-9a99-5935bc03480b/", "type": "funding"}], "product_evidence": [{"claim": "The official site says Byron agents help CPAs complete tax returns from document processing through reviewed returns.", "source_ids": ["official_site"]}, {"claim": "The product surface lists PDF processing, PBC requests, SALY workpapers, partnership allocations, Excel workbooks, trial balances, and K-1 processing.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "CPA firms and business-tax teams handling complex return preparation.", "category": "Fintech", "differentiation": "Purpose-built agents for tax workpapers and K-1 processing instead of generic document automation.", "why_now": "The 2026 seed round arrives as accounting firms face labor pressure and need reviewer-controlled automation for recurring tax workflows."}, "risks": [{"claim": "The open question is whether demo-led CPA workflows become repeatable software sales across firms with different tax processes.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'CPA tax-prep agents', 'Fintech', 'Seed', '$6.5M', NULL, NULL, NULL, 'US', 'tax prep,accounting,ai agents,cpa workflows,workpapers', 'Square Peg', NULL, 1, 'byron.webp', 'ready', 'published', 'manual', '2026-06-02 05:53:31', '2026-06-02 05:53:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cal-com', 'cal-com', 'cal.com', 'https://cal.com', 'Cal.com', 'Open source scheduling infrastructure.', 'The interesting move was not cloning Calendly in public. It was treating scheduling as infrastructure: a self-hosted option, API hooks, and a hosted product for teams that do not want to run it themselves. That is a sharper bet than generic booking software. Cal.com is selling control, not just calendar pages.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://cal.com", "type": "official"}, {"id": "funding_1", "label": "Cal.com", "url": "https://cal.com/blog", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Cal.com: Open source scheduling infrastructure.", "source_ids": ["official_site"]}, {"claim": "It was treating scheduling as infrastructure: a self-hosted option, API hooks, and a hosted product for teams that do not want to run it themselves.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Open source done right", "why_now": "Recent source-backed funding and public product evidence make scheduling, open source, calendar worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Open source done right', 'SaaS', 'Series A', '$25M', 2021, '30-50', 'San Francisco', 'US', 'scheduling,open source,calendar,productivity', 'Dick Costolo, Joseph Jacks (OSS Capital), Peer Richelsen', '{"github": "https://github.com/calcom/cal.com", "twitter": "https://x.com/calabordar", "linkedin": "https://linkedin.com/company/cal-com", "careers": "https://cal.com/jobs"}', 0, 'cal-com.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-canals', 'canals', 'www.canals.ai', 'https://www.canals.ai/', 'Canals', 'AI workflow automation for distributor orders, quotes, invoices, purchasing, and ERP data.', 'The bet is that distributors do not need another ERP module; they need agents inside the inbox-to-warehouse gap. Canals names the ugly work directly: sales-order intake, quote generation, invoice processing, purchasing, customer service, and structured ERP handoff, with 100+ distributor partners cited. Unlike generic RPA, it starts with wholesale documents and supplier workflows. The risk is whether ERP edge cases pull it back into services.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.canals.ai/", "type": "official"}, {"id": "funding_1", "label": "The SaaS News", "url": "https://www.thesaasnews.com/news/canals-raises-35m-series-a/", "type": "funding"}, {"id": "official_funding", "label": "Canals funding announcement", "url": "https://www.canals.ai/blog/canals-series-a-funding-announcement", "type": "funding"}], "product_evidence": [{"claim": "Official material positions Canals as AI workflow automation for industrial supply-chain transactions across distributors, manufacturers, and contractors.", "source_ids": ["official_site", "official_funding"]}, {"claim": "Funding coverage says the workflow suite handles sales order entry, quote generation, invoice processing, purchasing, and customer service for distributors.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Wholesale distributors and industrial suppliers with email, PDF, spreadsheet, portal, and ERP handoff work.", "category": "SaaS", "differentiation": "Vertical workflow agents for distributor transaction documents instead of a horizontal RPA layer.", "why_now": "The May 28, 2026 Series A gives Canals capital to expand its AI workflow suite for wholesale distribution."}, "risks": [{"claim": "The main risk is whether ERP and supplier edge cases require heavy services work that slows software margins.", "basis": "VentureDex editorial assessment based on official product and funding-source review."}]}', 4, 'Distributor ERP workflow agents', 'SaaS', 'Series A', '$35M', NULL, NULL, NULL, 'US', 'distribution,workflow automation,ai agents,erp,order entry', 'Base10 Partners', '{"careers": "https://www.canals.ai/careers"}', 1, 'canals.webp', 'ready', 'published', 'manual', '2026-05-31 02:16:09', '2026-05-31 02:16:09') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-capsa-ai', 'capsa-ai', 'capsa.ai', 'https://capsa.ai/product', 'Capsa AI', 'AI workflow platform for private capital deal teams.', 'The useful bet is that private-capital teams need memory that compounds inside deal work rather than another document vault. Capsa shows sourcing-to-IC workflows, domain-specific integrations, source transparency, and a prompt surface tied to CRM and data tools. Unlike generic copilots, it is shaped around investment committee output. The risk is whether firms trust one AI layer across confidential deal history.', '{"verified_at": "2026-06-11", "sources": [{"id": "official_site", "label": "Official company site", "url": "https://capsa.ai/", "type": "official"}, {"id": "product_page", "label": "Official product page", "url": "https://capsa.ai/product", "type": "product"}, {"id": "careers_page", "label": "Official careers page", "url": "https://capsa.ai/careers", "type": "official"}, {"id": "funding_1", "label": "Capsa AI Series A announcement", "url": "https://capsa.ai/news/announcing-our-18m-series-a", "type": "funding"}], "product_evidence": [{"claim": "The product page frames Capsa as workflow software for private-capital teams, from sourcing to investment committee work.", "source_ids": ["product_page"]}, {"claim": "Capsa describes custom domain-specific workflows, integrations into deal-stack tools, and full source transparency.", "source_ids": ["product_page"]}, {"claim": "The product surface shows a prompt workflow that can produce a four-page analysis from firm intelligence and comparable companies.", "source_ids": ["product_page"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Private equity, growth equity, and credit investment teams managing sourcing, diligence, and committee materials.", "category": "Fintech", "differentiation": "Capsa ties firm memory, integrations, and cited sources to private-capital workflows rather than serving as a generic document assistant.", "why_now": "Private-market teams are trying to use AI against proprietary deal history while preserving source traceability and investment-process controls."}, "risks": [{"claim": "The open question is whether private-capital firms will centralize confidential deal memory in a new AI workflow layer.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Private-capital memory', 'Fintech', 'Series A', '$18M', NULL, NULL, NULL, 'US', 'fintech,private capital,deal workflows,ai agents,knowledge management', 'TX Ventures, Pivot Investment Partners', '{"careers": "https://capsa.ai/careers"}', 1, 'capsa-ai.webp', 'ready', 'published', 'manual', '2026-06-11 06:04:13', '2026-06-11 06:04:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cargofy', 'cargofy', 'cargofy.com', 'https://cargofy.com/', 'Cargofy', 'AI digital workforce for freight quoting, dispatch, tracking, and load closing.', 'Freight teams lose hours in calls, emails, WhatsApp threads, and tool switching between quote and delivery. Cargofy says its AI workers call, email, dispatch, track, close loads, and operate in 28 languages across existing logistics tools. Unlike broker software that mainly stores records, the product is framed as labor for daily operations. The risk is whether autonomous agents can handle exceptions, compliance, and carrier trust at scale.', '{"verified_at": "2026-06-20", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://cargofy.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://careers.cargofy.com/", "type": "official"}, {"id": "funding_1", "label": "Tech.eu Series A report", "url": "https://tech.eu/2026/06/18/cargofy-lands-6m-to-scale-ai-workers-for-logistics/", "type": "funding"}], "product_evidence": [{"claim": "The homepage says Cargofy provides a digital workforce for logistics that handles jobs from quote to delivery through calls, email, and WhatsApp.", "source_ids": ["official_site"]}, {"claim": "The official site says its AI workers quote, dispatch, track, and close loads for forwarders, brokers, carriers, 3PLs, and shippers.", "source_ids": ["official_site"]}, {"claim": "The careers page says Cargofy builds an AI-native operating system for global freight with autonomous agents for procurement, dispatching, and operations.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Freight forwarders, brokers, carriers, shippers, 3PLs, dispatch teams, and logistics operations managers.", "category": "Logistics automation", "differentiation": "Cargofy sells AI workers that communicate and execute operational steps across channels, rather than only workflow software for freight records.", "why_now": "Freight operations remain fragmented across phone, email, WhatsApp, documents, and legacy tools while teams face pressure to move faster with fewer manual touches."}, "risks": [{"claim": "The risk is that freight exceptions, compliance steps, and carrier relationships may still require human operators despite automation claims.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI freight workforce', 'SaaS', 'Series A', '$11M', NULL, NULL, NULL, 'Europe', 'logistics,freight,ai agents,dispatch,operations', 'u.ventures', '{"careers": "https://careers.cargofy.com/"}', 1, 'cargofy.webp', 'ready', 'published', 'manual', '2026-06-20 06:02:12', '2026-06-20 06:02:12') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-certo', 'certo', 'www.askcerto.com', 'https://www.askcerto.com/', 'Certo', 'AI compliance agents for ingredient, formula, label, and market-entry checks.', 'The useful idea is turning compliance into product-specific checks instead of another spreadsheet of regulations. Certo shows ingredient extraction, CAS mapping, formula checks, SDS/PIF/CPSR generation, market readiness, audit trails, and daily regulatory feeds across 70+ countries. Unlike generic legal copilots, it narrows the agent to consumer-product labels and supplier documents.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.askcerto.com/", "type": "official"}, {"id": "funding_1", "label": "Tech Funding News", "url": "https://techfundingnews.com/certo-4m-seed-ai-compliance-cpg/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Certo: AI compliance agents for ingredient, formula, label, and market-entry checks.", "source_ids": ["official_site"]}, {"claim": "Certo shows ingredient extraction, CAS mapping, formula checks, SDS/PIF/CPSR generation, market readiness, audit trails, and daily regulatory feeds across 70+ countries.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Consumer compliance agents", "why_now": "Recent source-backed funding and public product evidence make compliance, consumer goods, regulatory worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Consumer compliance agents', 'SaaS', 'Seed', '$4M', NULL, NULL, NULL, 'Europe', 'compliance,consumer goods,regulatory,ai agents,workflow', 'daphni', NULL, 1, 'certo.webp', 'ready', 'published', 'manual', '2026-05-26 09:43:21', '2026-05-26 09:43:21') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-champ-ai', 'champ-ai', 'www.champ.ai', 'https://www.champ.ai/', 'Champ AI', 'AI operations agents for repetitive back-office workflows.', 'The useful bet is that operations teams want agents that run messy workflows, not narrow chatbots. Champ AI shows agents that use browsers, documents, and voice-like interactions across invoice, scheduling, data-entry, and support tasks. Unlike RPA suites, it sells outcomes that map to team workflows instead of scripts. The risk is whether each customer still needs heavy setup to make the agents dependable.', '{"verified_at": "2026-06-10", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.champ.ai/", "type": "official"}, {"id": "careers_page", "label": "Official Dover jobs board linked by Champ", "url": "https://app.dover.com/jobs/champ", "type": "official"}, {"id": "funding_1", "label": "Champ AI seed funding announcement", "url": "https://www.globenewswire.com/news-release/2026/05/13/3294553/0/en/champ-ai-emerges-from-stealth-with-8-5m-in-new-funding.html", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Champ AI as AI agents for operations teams that complete repetitive workflows across business systems.", "source_ids": ["official_site"]}, {"claim": "The product surface shows agents using browsers, documents, and voice-like interactions for invoice, scheduling, support, and data-entry work.", "source_ids": ["official_site"]}, {"claim": "Champ AI publishes security, comparison, customer-use-case, and careers pages, giving buyers more than a launch-only placeholder.", "source_ids": ["official_site", "careers_page"]}, {"claim": "The funding announcement says Champ AI emerged from stealth with $8.5M in new funding led by Redpoint Ventures.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Operations leaders and back-office teams trying to automate repetitive browser, document, scheduling, and support workflows.", "category": "SaaS", "differentiation": "Champ AI packages agents around operations outcomes rather than asking teams to build every automation as a script.", "why_now": "Agentic browser and document models make it more plausible to automate workflows that were too variable for traditional RPA."}, "risks": [{"claim": "The open question is how much implementation work is needed before Champ AI agents can handle customer-specific edge cases safely.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Ops agents over RPA', 'SaaS', 'Seed', '$8.5M', NULL, NULL, NULL, 'US', 'operations,ai agents,workflow automation,rpa,back office', 'Redpoint Ventures', '{"careers": "https://app.dover.com/jobs/champ"}', 1, 'champ-ai.webp', 'ready', 'published', 'manual', '2026-06-10 05:57:38', '2026-06-10 05:57:38') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cinder', 'cinder', 'cinder.ai', 'https://cinder.ai/', 'Cinder', 'Trust and safety operations platform for AI-era abuse workflows.', 'The bet is that AI abuse needs an operations system, not another moderation queue. Cinder gives trust and safety teams agents, QA, integrations, audit trails, and incident intelligence in one command center, with OpenAI and Character.AI named as customers. Unlike generic CRM-based review tooling, it treats policy decisions as reusable intelligence. The risk is whether enterprise safety teams can adopt that depth without heavy services work.', '{"verified_at": "2026-06-04", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://cinder.ai/", "type": "official"}, {"id": "funding_1", "label": "Cinder Series B announcement", "url": "https://cinder.ai/resources/blog/cinder-raises-41m-series-b-ai-abuse", "type": "funding"}], "product_evidence": [{"claim": "The official site describes infrastructure that protects platforms from abuse, fraud, manipulation, and AI-driven attacks.", "source_ids": ["official_site"]}, {"claim": "The product surface lists agents, QA, third-party integrations, audit trails, incident intelligence, and explainability for safety teams.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Trust and safety, policy, and platform-operations teams protecting AI and consumer platforms.", "category": "AI / ML", "differentiation": "Cinder turns moderation, agent decisions, QA, integrations, and audit trails into an operations layer rather than a review queue.", "why_now": "The May 2026 Series B follows rising AI-powered abuse and gives the company capital to sell safety operations as platform infrastructure."}, "risks": [{"claim": "The open question is whether complex trust-and-safety deployments can become repeatable software rollouts rather than services projects.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AI safety command center', 'AI / ML', 'Series B', '$41M', NULL, NULL, NULL, 'US', 'trust and safety,ai safety,moderation,abuse operations,agents', 'Radical Ventures', '{"careers": "https://cinder.ai/careers"}', 1, 'cinder.webp', 'ready', 'published', 'manual', '2026-06-04 05:59:59', '2026-06-04 05:59:59') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ciridae', 'ciridae', 'www.ciridae.com', 'https://www.ciridae.com', 'Ciridae', 'AI operating systems for real-economy businesses.', 'The sharper bet is that mid-market operators need rebuilt workflows, not another AI sidebar. Ciridae shows AP invoices, CRM, reporting, project management, and Knight case metrics like $5M revenue uplift and 100% of A/P invoices processed. Unlike horizontal copilots, it embeds into how restoration or logistics companies already run. The risk is whether services work scales without becoming consulting.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.ciridae.com", "type": "official"}, {"id": "funding_1", "label": "Fortune", "url": "https://fortune.com/2026/05/11/a16z-apple-alums-20m-ai-real-businesses/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Ciridae: AI operating systems for real-economy businesses.", "source_ids": ["official_site"]}, {"claim": "Ciridae shows AP invoices, CRM, reporting, project management, and Knight case metrics like $5M revenue uplift and 100% of A/P invoices processed.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "100% AP invoices processed", "why_now": "Recent source-backed funding and public product evidence make ai operations, industrial services, private equity worth tracking."}, "risks": [{"claim": "The risk is whether services work scales without becoming consulting.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '100% AP invoices processed', 'AI / ML', 'Seed', '$20M', NULL, NULL, NULL, 'US', 'ai operations,industrial services,private equity,workflow automation', 'Accel, Andreessen Horowitz, General Catalyst', NULL, 1, 'ciridae.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-clario', 'clario', 'www.clarioclean.com', 'https://www.clarioclean.com/', 'Clario', 'Enterprise data ROT cleanup platform for redundant, obsolete, and trivial unstructured files.', 'AI readiness often fails before the model ever sees a prompt. Clario scans 5 work surfaces: Google Drive, SharePoint, OneDrive, Box, and Confluence for redundant, obsolete, and trivial files, then pushes keep, archive, or delete workflows through Slack and Teams. Unlike data catalogs that mostly describe the mess, it only gets paid when customers decide what to remove. The risk is whether cleanup decisions can become autonomous without scaring legal and IT teams.', '{"verified_at": "2026-06-18", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.clarioclean.com/", "type": "official"}, {"id": "funding_1", "label": "BusinessWire funding announcement", "url": "https://www.businesswire.com/news/home/20260617473639/en/Clario-Launches-with-%246M-Seed-Funding-to-Rid-Enterprises-of-Garbage-Data", "type": "funding"}], "product_evidence": [{"claim": "The official site says Clario identifies and eliminates redundant, obsolete, and trivial unstructured data to reduce waste and risk.", "source_ids": ["official_site"]}, {"claim": "The homepage frames the workflow as keep what matters and eliminate the rest, with outcomes for token cost, AI quality, search risk, and security.", "source_ids": ["official_site"]}, {"claim": "BusinessWire says Clario analyzes Google Drive, SharePoint, OneDrive, Box, and Confluence and routes decisions through Slack and Teams.", "source_ids": ["funding_1"]}, {"claim": "BusinessWire reports a $6M seed round led by Preface Ventures for cleaning enterprise unstructured data.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise IT, data governance, security, legal, and AI-readiness teams managing unstructured collaboration data.", "category": "Data governance", "differentiation": "Clario focuses on removing low-value unstructured files rather than only indexing or cataloging them for search.", "why_now": "Enterprise AI rollouts make stale collaboration files more expensive because bad data now affects search quality, token spend, and model context."}, "risks": [{"claim": "The open question is whether legal and IT teams will trust automated recommendations enough to delete or archive sensitive files at scale.", "basis": "VentureDex editorial assessment based on official product and funding-source review."}]}', 4, '$6M seed to delete data ROT', 'SaaS', 'Seed', '$6M', NULL, NULL, 'Menlo Park', 'US', 'data governance,ai readiness,unstructured data,enterprise it,slack', 'Preface Ventures', NULL, 1, 'clario.webp', 'ready', 'published', 'manual', '2026-06-18 14:59:42', '2026-06-18 14:59:42') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cleatus', 'cleatus', 'www.cleat.ai', 'https://www.cleat.ai/', 'CLEATUS', 'Agentic GovCon platform for opportunity discovery, bids, and proposal workflows.', 'The bet is that government contracting needs an operating workflow, not another bid-search inbox. CLEATUS watches SAM.gov, 40,000+ SLED sources, DIBBS, and Grants.gov, then scores compliance, drafts proposals, manages pursuit CRM, and exposes REST plus Claude and ChatGPT connectors. Unlike generic proposal tools, it works where the data and paperwork actually live. The risk is whether smaller contractors can trust agentic write access on high-stakes bids.', '{"verified_at": "2026-06-01", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.cleat.ai/", "type": "official"}, {"id": "api_docs", "label": "CLEATUS API docs", "url": "https://api.cleat.ai/api/docs", "type": "product"}, {"id": "funding_1", "label": "CLEATUS seed announcement", "url": "https://www.cleat.ai/blog/cleatus-4m-seed-funding", "type": "funding"}], "product_evidence": [{"claim": "The official site says CLEATUS finds opportunities across SAM.gov, 40,000+ SLED sources, DLA DIBBS, and Grants.gov.", "source_ids": ["official_site"]}, {"claim": "The product surface covers compliance scoring, proposal drafting, contract analysis, pursuit management, AI workflows, Claude and ChatGPT connectors, and a public REST API.", "source_ids": ["official_site", "api_docs"]}], "market_context": {"primary_user": "Small and mid-sized government contractors managing discovery, compliance review, and proposal work.", "category": "SaaS", "differentiation": "GovCon-specific agentic workflow across source discovery, compliance, proposals, pursuit CRM, connectors, and API access.", "why_now": "The May 2026 seed round funds an AI platform for contractors facing expanding public-sector opportunity data and heavy proposal labor."}, "risks": [{"claim": "The open question is whether smaller contractors will trust agentic write access and generated proposal work on high-stakes bids.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Agentic GovCon workflow', 'SaaS', 'Seed', '$4M', NULL, NULL, NULL, 'US', 'government contracting,proposal automation,agents,crm,compliance', 'Las Olas Venture Capital, REVO Capital', '{"api": "https://api.cleat.ai/api/docs"}', 1, 'cleatus.webp', 'ready', 'published', 'manual', '2026-06-01 05:58:46', '2026-06-01 05:58:46') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-codeintegrity', 'codeintegrity', 'www.codeintegrity.ai', 'https://www.codeintegrity.ai/', 'CodeIntegrity', 'Runtime control plane for AI agent tool calls and data movement.', 'The bet is that agent security belongs between intent and tool execution, not in another model judging after the fact. CodeIntegrity turns every tool call into sandboxed code, records provenance, and blocks email.send-style PII moves before execution. Unlike human approval queues or LLM-as-judge defenses, it is selling deterministic control for nondeterministic agents. The risk is whether pilots in regulated industries become a repeatable deployment pattern.', '{"verified_at": "2026-06-01", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.codeintegrity.ai/", "type": "official"}, {"id": "funding_1", "label": "GeekWire", "url": "https://www.geekwire.com/2026/codeintegrity-raises-4-8m-to-put-permanent-guardrails-on-unpredictable-ai-agents/", "type": "funding"}], "product_evidence": [{"claim": "The official site positions CodeIntegrity as a runtime layer that evaluates intent, data provenance, destination, and risk before agent tool calls execute.", "source_ids": ["official_site"]}, {"claim": "The product surface shows an email.send policy example where PII from a support ticket is blocked before execution and recorded as action evidence.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Security and platform teams deploying AI agents with access to enterprise tools and data.", "category": "AI / ML", "differentiation": "Deterministic policy checks between agent intent and tool execution, with provenance and action records.", "why_now": "The May 2026 seed round funds a control layer for MCP and tool-using AI agents as regulated teams move from experiments into deployments."}, "risks": [{"claim": "The open question is whether runtime agent controls become default infrastructure before agent frameworks standardize their own policy layers.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Runtime controls for AI agents', 'AI / ML', 'Seed', '$4.8M', NULL, NULL, NULL, 'US', 'ai security,agents,tool calls,data loss,mcp', 'SYN Ventures', '{"careers": "https://www.codeintegrity.ai/careers"}', 1, 'codeintegrity.webp', 'ready', 'published', 'manual', '2026-06-01 05:58:46', '2026-06-01 05:58:46') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-conduct', 'conduct', 'conduct.ai', 'https://conduct.ai/', 'Conduct', 'AI operating system for enterprise software modernization and S/4HANA migration.', 'Legacy ERP work usually starts with consultants mapping code, dependencies, and process gaps by hand. Conduct says its AI operating system reads custom software, builds S/4HANA migration plans, and automates fit-gap analysis, refactoring, and validation. Unlike generic code assistants, it is aimed at enterprise transformation programs. The risk is whether outputs remain trusted when SAP estates are highly customized.', '{"verified_at": "2026-06-20", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://conduct.ai/", "type": "official"}, {"id": "funding_1", "label": "Official Series A announcement", "url": "https://conduct.ai/blog/series-a", "type": "funding"}], "product_evidence": [{"claim": "The homepage positions Conduct as an AI operating system for enterprise software, including S/4HANA migration, code analysis, planning, development, and testing.", "source_ids": ["official_site"]}, {"claim": "The site says Conduct reads custom code, dependencies, and downstream effects so teams can map legacy software to business functions before modernization.", "source_ids": ["official_site"]}, {"claim": "The Series A note says Conduct automates template creation, fit-gap analysis, structured refactoring, and validation for complex SAP transformation programs.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise CIO, transformation, SAP, and systems-integrator teams trying to understand and modernize customized ERP estates.", "category": "Enterprise software modernization", "differentiation": "Conduct focuses on translating legacy enterprise implementations into migration plans and executable transformation work, not only generating code snippets.", "why_now": "SAP customers face migration deadlines while large companies still depend on heavily customized systems that are hard to inspect manually."}, "risks": [{"claim": "The open question is whether enterprise teams and auditors will trust AI-generated migration maps across highly customized SAP environments.", "basis": "VentureDex editorial assessment based on the official product surface and Series A announcement."}]}', 4, 'AI ERP modernization', 'SaaS', 'Series A', '$60M', NULL, NULL, NULL, 'Europe', 'enterprise software,sap,erp modernization,ai agents,systems integration', 'Index Ventures', '{"careers": "https://conduct.ai/about"}', 1, 'conduct.webp', 'ready', 'published', 'manual', '2026-06-20 06:02:12', '2026-06-20 06:02:12') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-config', 'config', 'config.inc', 'https://config.inc/product', 'Config', 'Robot training-data platform for robotics foundation models.', 'The strongest bet is that robot data should be fabricated like semiconductors, not collected one lab at a time. Config''s platform walks from gripper design to data strategy, acquisition, labeling, action estimation, model training, and evaluation; CFG-1 claims 100K in-house human-data hours, 2B parameters, and sub-50ms RTX 5090 latency. Compared with robot builders chasing hardware, this sells the data foundry. The risk is that customers still need proof on their own factory tasks.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://config.inc/product", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/11/koreas-biggest-manufacturers-back-config-the-tsmc-of-robot-data/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Config: Robot training-data platform for robotics foundation models.", "source_ids": ["official_site"]}, {"claim": "Config''s platform walks from gripper design to data strategy, acquisition, labeling, action estimation, model training, and evaluation; CFG-1 claims 100K in-house human-data hours, 2B parameters, and sub-50ms RTX 5090 latency.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "100K hours of robot data", "why_now": "Recent source-backed funding and public product evidence make robotics, training data, foundation models worth tracking."}, "risks": [{"claim": "The risk is that customers still need proof on their own factory tasks.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '100K hours of robot data', 'AI / ML', 'Seed', '$27M', NULL, NULL, NULL, 'China / Asia', 'robotics,training data,foundation models,physical ai', 'Samsung Venture Investment', '{"careers": "https://config.inc/careers"}', 0, 'config.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-convey', 'convey', 'convey.dev', 'https://convey.dev/', 'Convey', 'AI teammates that learn operational workflows and execute business processes for enterprises.', 'The sharp move is calling the worker a teammate, not a chatbot. Convey says operators can share a screen and train digital teammates in about 3 hours, then hand off invoices, reconciliation, reporting, and ad-ops work in the background. Unlike copilots that wait beside one employee, it sells outcome ownership to the whole operations team. The question is how often messy exceptions pull humans back into the loop.', '{"verified_at": "2026-06-18", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://convey.dev/", "type": "official"}, {"id": "funding_1", "label": "BusinessWire funding announcement", "url": "https://www.businesswire.com/news/home/20260617486214/en/Convey-Raises-%2438-Million-Series-A-Led-by-Andreessen-Horowitz-to-Automate-Enterprise-Operations-with-AI-Teammates", "type": "funding"}], "product_evidence": [{"claim": "The homepage says operators can describe a process or share their screen so an AI teammate observes, learns, and takes over execution.", "source_ids": ["official_site"]}, {"claim": "Convey reports more than 1,045,000 hours of background work executed since Q3 2025 and shows enterprise customer logos and case studies.", "source_ids": ["official_site"]}, {"claim": "The product page positions the platform as a way to train and manage enterprise-grade digital teammates across operational work.", "source_ids": ["official_site"]}, {"claim": "BusinessWire reports a $38M Series A led by Andreessen Horowitz for automating enterprise operations with AI teammates.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise operations, finance, revenue, support, and admin teams with repeatable back-office workflows.", "category": "Enterprise workflow automation", "differentiation": "Convey emphasizes trained digital teammates that own background execution, rather than chat copilots that only advise a single user.", "why_now": "Enterprises are moving from AI experimentation to measurable labor substitution in operational queues and repetitive admin work."}, "risks": [{"claim": "The risk is that high-exception workflows may still require human judgment often enough to cap automation ROI.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$38M Series A for AI teammates', 'SaaS', 'Series A', '$38M', 2025, NULL, 'San Francisco', 'US', 'ai agents,workflow automation,enterprise operations,no-code,back office', 'Andreessen Horowitz', '{"careers": "https://www.linkedin.com/company/conveyai/jobs/"}', 1, 'convey.webp', 'ready', 'published', 'manual', '2026-06-18 14:59:42', '2026-06-18 14:59:42') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-copilotkit', 'copilotkit', 'www.copilotkit.ai', 'https://www.copilotkit.ai', 'CopilotKit', 'Open-source framework for app-native AI agents and generative UI.', 'Most agent products still end at a chat box; the sharper bet is giving agents a front end. CopilotKit exposes React and Angular SDKs, AG-UI, MCP Apps, threads, GitHub-backed docs, and a one-command npx path. Unlike Vercel''s AI SDK or ChatGPT Apps, it is trying to be the neutral UI layer enterprises can self-host. The risk is that protocol gravity is hard to keep once platform vendors bundle the same primitives.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.copilotkit.ai", "type": "official"}, {"id": "funding_1", "label": "CopilotKit", "url": "https://www.copilotkit.ai/blog/series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes CopilotKit: Open-source framework for app-native AI agents and generative UI.", "source_ids": ["official_site"]}, {"claim": "CopilotKit exposes React and Angular SDKs, AG-UI, MCP Apps, threads, GitHub-backed docs, and a one-command npx path.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "AG-UI for app-native agents", "why_now": "Recent source-backed funding and public product evidence make ai agents, generative ui, developer tools worth tracking."}, "risks": [{"claim": "The risk is that protocol gravity is hard to keep once platform vendors bundle the same primitives.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AG-UI for app-native agents', 'DevTools', 'Series A', '$27M', NULL, NULL, NULL, 'US', 'ai agents,generative ui,developer tools,open source', 'Glilot Capital, NFX, SignalFire', '{"github": "https://github.com/CopilotKit/CopilotKit", "twitter": "https://x.com/CopilotKit", "linkedin": "https://www.linkedin.com/company/copilotkit/", "careers": "https://www.copilotkit.ai/careers"}', 1, 'copilotkit.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-corgi', 'corgi', 'www.corgi.insure', 'https://www.corgi.insure', 'Corgi', 'Instant startup insurance quotes and modular coverage.', 'Startup insurance usually feels like paperwork wearing a broker''s suit; this is closer to checkout. Corgi exposes instant quotes, 4 stage-based coverage paths, D&O, Cyber, Tech E&O, and customer proof from Deel, Bland, Intryc, and other startups. Unlike Vouch or Embroker, the bet is that founders want insurance to feel as fast as buying compute. The risk is that underwriting speed has to survive messier companies than YC-style software teams.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.corgi.insure", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/06/insurance-startup-corgi-hits-1-3b-valuation-4-months-after-its-series-a/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Corgi: Instant startup insurance quotes and modular coverage.", "source_ids": ["official_site"]}, {"claim": "Corgi exposes instant quotes, 4 stage-based coverage paths, D&O, Cyber, Tech E&O, and customer proof from Deel, Bland, Intryc, and other startups.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$160M Series B for instant insurance", "why_now": "Recent source-backed funding and public product evidence make insurance, fintech, startups worth tracking."}, "risks": [{"claim": "The risk is that underwriting speed has to survive messier companies than YC-style software teams.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$160M Series B for instant insurance', 'Fintech', 'Series B', '$160M', NULL, NULL, NULL, 'US', 'insurance,fintech,startups,founder tools', 'TCV, Kindred Ventures, Leblon Capital, First Order Fund', '{"twitter": "https://x.com/UseCorgi", "linkedin": "https://www.linkedin.com/company/corgi-insurance", "careers": "https://www.ycombinator.com/companies/corgi-insurance/jobs"}', 1, 'corgi.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-crew-carbon', 'crew-carbon', 'crewcarbon.com', 'https://crewcarbon.com', 'CREW Carbon', 'Wastewater process optimization that also delivers measured carbon removal.', 'This is climate tech with an operator''s wedge: make sewage plants cheaper before selling carbon removal. CREW uses calcium carbonate dosing, closed-system measurement, and projects at nearly 10 facilities; one utility may defer a $350M upgrade. Unlike credits-first carbon removal, the buyer also gets better pH, settleability, and chemical spend. That dual value is why it feels less fragile than most climate markets.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://crewcarbon.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/crew-raises-25m-of-funding-to-scale-wastewater-treatment-optimization-technology-as-climate-solution-302772585.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes CREW Carbon: Wastewater process optimization that also delivers measured carbon removal.", "source_ids": ["official_site"]}, {"claim": "CREW uses calcium carbonate dosing, closed-system measurement, and projects at nearly 10 facilities; one utility may defer a $350M upgrade.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Climate, infrastructure, or operations teams evaluating measurable sustainability workflows.", "category": "Climate / Sustainability", "differentiation": "$350M plant upgrade deferred", "why_now": "Recent source-backed funding and public product evidence make water tech, carbon removal, wastewater worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$350M plant upgrade deferred', 'Climate / Sustainability', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'water tech,carbon removal,wastewater,climate', 'Burnt Island Ventures', '{"careers": "https://crewcarbon.com/careers/"}', 1, 'crew-carbon.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-crimson', 'crimson', 'www.crimson.law', 'https://www.crimson.law/', 'Crimson', 'AI case-intelligence platform for litigation teams working through evidence and disputes.', 'Litigation AI gets more interesting when the unit is a case record, not a blank prompt. Crimson builds a case-intelligence workspace that reads evidence, answers with citations, surfaces case insights, and wraps it in AES-256 security controls. Unlike general legal chat tools, it narrows the product around disputes and arbitration. The hard part is proving citation quality when every matter has messy files.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.crimson.law/", "type": "official"}, {"id": "security_page", "label": "Crimson security page", "url": "https://www.crimson.law/security", "type": "product"}, {"id": "funding_1", "label": "Crimson seed announcement", "url": "https://www.crimson.law/press/seed-round-us-expansion", "type": "funding"}], "product_evidence": [{"claim": "The official site describes a case-intelligence platform that ingests evidence, answers questions, and returns case insights for litigation and disputes.", "source_ids": ["official_site"]}, {"claim": "Crimson positions outputs as accurate and verifiable, with answers tied back to case materials rather than a free-form legal chatbot.", "source_ids": ["official_site"]}, {"claim": "The security page lists AES-256 encryption and enterprise infrastructure controls for law-firm case data.", "source_ids": ["security_page"]}], "market_context": {"primary_user": "Litigators, disputes lawyers, arbitration teams, and legal professionals reviewing case evidence.", "category": "SaaS", "differentiation": "Matter-specific case intelligence and cited evidence workflows instead of a general legal assistant.", "why_now": "The May 28, 2026 seed announcement says Crimson will use the round to expand from the UK into the US litigation market."}, "risks": [{"claim": "The open question is whether citation quality holds up across messy case files, scanned exhibits, and adversarial legal review.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Case-linked legal AI', 'SaaS', 'Seed', '$2.5M', NULL, NULL, NULL, 'Europe', 'legaltech,litigation,ai search,evidence,case intelligence', 'Y Combinator', '{"security": "https://www.crimson.law/security", "press": "https://www.crimson.law/press/seed-round-us-expansion", "careers": "https://www.crimson.law/careers"}', 1, 'crimson.webp', 'ready', 'published', 'manual', '2026-05-31 06:05:47', '2026-05-31 06:05:47') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cursor', 'cursor', 'cursor.com', 'https://cursor.com', 'Cursor', 'The AI-first code editor.', 'The right bet was not copilot-inside-VSCode, but an editor rebuilt around the model. Tab completion, inline diffs, and cmd-K feel native rather than bolted on. By forking VS Code instead of starting from scratch, Cursor kept the muscle memory and changed the center of gravity. That is why it feels sticky instead of merely novel.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://cursor.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2024/08/09/anysphere-a-github-copilot-rival-has-raised-60m-series-a-at-400m-valuation-from-a16z-thrive-sources-say/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Cursor: The AI-first code editor.", "source_ids": ["official_site"]}, {"claim": "Tab completion, inline diffs, and cmd-K feel native rather than bolted on.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Changed how developers write code", "why_now": "Recent source-backed funding and public product evidence make ai, code editor, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Changed how developers write code', 'AI / ML', 'Series A', '$60M', 2022, '50-100', 'San Francisco', 'US', 'ai,code editor,developer tools,productivity', 'Andreessen Horowitz, Thrive Capital, OpenAI Startup Fund', '{"github": "https://github.com/getcursor", "twitter": "https://x.com/cursor_ai", "linkedin": "https://linkedin.com/company/cursor-ai", "careers": "https://cursor.com/careers"}', 1, 'cursor.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cvrd-health', 'cvrd-health', 'www.becvrd.com', 'https://www.becvrd.com', 'CVRD Health', 'Fringe benefit optimization and ICHRA compliance platform for government contractors.', 'Someone finally treated fringe benefits for federal contractors as an operating system, not a broker spreadsheet. CVRD models SCA/DBRA obligations, tracks H&W dollars in real time, manages ICHRAs, and shows an Aptive case with $536,870 annual savings across 151 enrolled employees. Unlike generic benefits software, the bet is owning the narrow compliance math where margins leak. The risk is whether service-heavy advocacy scales beyond early GovCon accounts.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.becvrd.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/cvrd-health-announces-5m-seed-round-led-by-upfront-ventures-to-modernize-benefits-compliance-for-federal-government-contractors-302779218.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes CVRD Health: Fringe benefit optimization and ICHRA compliance platform for government contractors.", "source_ids": ["official_site"]}, {"claim": "CVRD models SCA/DBRA obligations, tracks H&W dollars in real time, manages ICHRAs, and shows an Aptive case with $536,870 annual savings across 151 enrolled employees.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "151-enrollee GovCon case study", "why_now": "Recent source-backed funding and public product evidence make benefits, govcon, compliance worth tracking."}, "risks": [{"claim": "The risk is whether service-heavy advocacy scales beyond early GovCon accounts.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '151-enrollee GovCon case study', 'SaaS', 'Seed', '$5M', NULL, NULL, NULL, 'US', 'benefits,govcon,compliance,healthcare,hr tech', 'Upfront Ventures', '{"linkedin": "https://www.linkedin.com/company/cvrdhealth/", "careers": "https://www.becvrd.com/careers"}', 1, 'cvrd-health.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-daloopa', 'daloopa', 'daloopa.com', 'https://daloopa.com/', 'Daloopa', 'Source-linked financial data layer for analysts, models, APIs, MCP, and AI agents.', 'The sharp bet is that financial AI fails at the spreadsheet cell, not the chat box. Daloopa covers 5,500+ public companies with source-linked numbers, Excel add-ins, Scout, API, MCP, cloud delivery, and an agent benchmark. Unlike generic market-data feeds, it is selling audit trails for every answer. The open question is whether analysts trust agents when a filing source is one click away.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://daloopa.com/", "type": "official"}, {"id": "mcp_page", "label": "Daloopa MCP product page", "url": "https://daloopa.com/products/mcp", "type": "product"}, {"id": "api_page", "label": "Daloopa API product page", "url": "https://daloopa.com/products/api", "type": "product"}, {"id": "funding_1", "label": "Daloopa Series C announcement", "url": "https://daloopa.com/blog/press-release/47-million-series-c", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Daloopa as a source-linked financial data layer with Data Sheets, Excel add-ins, Scout, API, MCP, and cloud integrations.", "source_ids": ["official_site"]}, {"claim": "The MCP page says Daloopa covers 5,500+ public-company tickers, exposes 5-10x more data points, and preserves document attribution.", "source_ids": ["mcp_page"]}, {"claim": "The API product page presents Daloopa data as a programmatic feed for financial models, research workflows, and downstream AI systems.", "source_ids": ["api_page"]}], "market_context": {"primary_user": "Investment analysts, financial-data teams, and builders of source-grounded finance agents.", "category": "Fintech", "differentiation": "Filing-linked audit trails and analyst workflow integrations instead of a generic market-data or chat interface.", "why_now": "The May 28, 2026 Series C led by Brighton Park Capital funds the trusted data layer Daloopa is pitching for financial AI agents."}, "risks": [{"claim": "The risk is whether finance teams will let agents act on source-linked data, or keep the product as analyst-side evidence infrastructure.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Source-linked finance data', 'Fintech', 'Series C', '$47M', NULL, NULL, NULL, 'US', 'financial data,ai agents,mcp,api,investment research', 'Brighton Park Capital', '{"mcp": "https://daloopa.com/products/mcp", "scout": "https://daloopa.com/products/scout", "api": "https://daloopa.com/products/api", "careers": "https://daloopa.com/careers"}', 1, 'daloopa.webp', 'ready', 'published', 'manual', '2026-05-31 06:05:47', '2026-05-31 06:05:47') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-dapple', 'dapple', 'dapple.co', 'https://dapple.co/', 'Dapple', 'Dedicated in-country AI cloud environments for regulated enterprises.', 'The bet is that enterprise AI needs a control plane between hyperscaler queues and private data centers. Dapple packages dedicated, single-tenant, in-country GPU environments with governance, residency, and performance promises, and claims two live customers plus $100M+ contracted five months from launch. Unlike raw GPU rental, the product is sold as an operating layer for production AI workloads. The risk is whether execution keeps up with infrastructure demand.', '{"verified_at": "2026-06-12", "sources": [{"id": "official_site", "label": "Official company site", "url": "https://dapple.co/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://dapple.co/careers", "type": "official"}, {"id": "funding_1", "label": "Dapple seed announcement", "url": "https://dapple.co/newsroom/dapple-closes-30m-seed", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Dapple as enterprise AI infrastructure between public cloud and private data centers.", "source_ids": ["official_site"]}, {"claim": "Dapple describes dedicated, single-tenant, in-country AI environments with governance, residency, and performance controls.", "source_ids": ["official_site"]}, {"claim": "The official announcement says Dapple had two live customers and more than $100M contracted five months after launch.", "source_ids": ["funding_1"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Regulated enterprises deploying AI workloads that require data residency, dedicated capacity, and governance controls.", "category": "AI / ML", "differentiation": "Dapple sells dedicated AI cloud environments as managed operating infrastructure rather than generic GPU rental.", "why_now": "Enterprise AI demand is pushing buyers to seek capacity, sovereignty, and operational control outside shared hyperscaler queues."}, "risks": [{"claim": "The open question is whether a young infrastructure company can keep execution and capacity ahead of contracted enterprise demand.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Single-tenant AI cloud', 'AI / ML', 'Seed', '$30M', NULL, NULL, NULL, 'US', 'ai infrastructure,gpu cloud,enterprise ai,data residency,governance', 'The Raptor Group, Ion Pacific', '{"careers": "https://dapple.co/careers", "linkedin": "https://linkedin.com/company/dappleco", "twitter": "https://x.com/dapple_co", "press": "https://dapple.co/newsroom/dapple-closes-30m-seed"}', 1, 'dapple.webp', 'ready', 'published', 'manual', '2026-06-12 06:00:05', '2026-06-12 06:00:05') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-definic', 'definic', 'definic.ai', 'https://definic.ai/', 'Definic', 'Vendor intelligence platform for IT procurement, RFP scoping, and market benchmarking.', 'Procurement suites usually record vendor data after the choice; this tries to make the choice itself computable. The official product shows RFP assessment, vendor matching from real delivery data, market benchmarking, spend dashboards, and delivery tracking. The bet is that external IT work should be bought like a measured supply chain, not a relationship spreadsheet. The risk is whether its savings claims hold outside its early European banking proof points.', '{"verified_at": "2026-06-14", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://definic.ai/", "type": "official"}, {"id": "funding_1", "label": "Definic press announcement", "url": "https://definic.ai/press", "type": "funding"}], "product_evidence": [{"claim": "The official product site describes dashboard, assessment, intelligence, benchmarking, management, and marketplace workflows for enterprise IT vendor selection.", "source_ids": ["official_site"]}, {"claim": "The product copy says Definic turns vague project ideas into structured RFPs, matches vendors using real delivery data, benchmarks market rates, and tracks delivery performance.", "source_ids": ["official_site"]}, {"claim": "The official press announcement says Definic gives procurement teams visibility into vendor fit, project requirements, and live market pricing.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise procurement, IT sourcing, and vendor-management teams buying external IT services.", "category": "Procurement Software", "differentiation": "Definic narrows procurement intelligence to IT services selection, combining requirement scoping, vendor matching, market pricing, spend visibility, and delivery tracking instead of a generic supplier database.", "why_now": "The company is using its seed round and rename from Nordics to expand from regional IT marketplace roots into a broader Vendor Intelligence platform for DACH, UK, and US buyers."}, "risks": [{"claim": "Definic''s strongest proof points come from early client examples, so the open question is whether savings and cycle-time reductions repeat across more sectors and geographies.", "basis": "VentureDex editorial assessment based on official product evidence and Definic''s official funding announcement."}]}', 4, '$2.9M seed for IT procurement', 'SaaS', 'Seed', '$2.9M', NULL, NULL, NULL, 'Europe', 'procurement,vendor intelligence,it services,rfp,benchmarking', 'J&T Ventures', '{"linkedin": "https://www.linkedin.com/company/definic-ai/", "careers": "https://definic.ai/careers"}', 1, 'definic.webp', 'ready', 'published', 'manual', '2026-06-14 05:48:21', '2026-06-14 05:48:21') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-devplan', 'devplan', 'devplan.com', 'https://devplan.com/', 'Devplan', 'Product intelligence graph for engineering status, risks, and decisions.', 'The sharp bet is that AI coding makes coordination, not execution, the bottleneck. Devplan''s Weaver turns GitHub, tickets, meetings, Slack, Notion, Google Workspace and customer signals into a live product graph, with Slack and MCP answers tied back to source. Unlike generic enterprise search, it is tuned for product and engineering drift. The risk is whether teams trust one graph across messy roadmap politics.', '{"verified_at": "2026-06-19", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://devplan.com/", "type": "official"}, {"id": "funding_1", "label": "PRWeb funding announcement", "url": "https://www.prweb.com/releases/devplan-emerges-from-stealth-with-2-5m-to-build-the-intelligence-layer-for-product-and-engineering-organizations-302804259.html", "type": "funding"}], "product_evidence": [{"claim": "The homepage describes Daily Digest, Automated Status, Ask Devplan, Change History, and Weaver as product intelligence workflows.", "source_ids": ["official_site"]}, {"claim": "The site says Weaver converts commits, tickets, meetings, Slack, Notion, Google Workspace, and customer feedback into a shared product graph.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Weaver connects GitHub, Jira, Linear, Slack, Notion, Google Workspace, meeting notes, and customer feedback.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Product managers, engineering managers, and leaders trying to keep roadmap status and decisions current across fragmented tools.", "category": "Product intelligence software", "differentiation": "Devplan focuses the knowledge graph on product and engineering coordination rather than general enterprise search.", "why_now": "AI-assisted coding increases the amount of shipped work while making cross-team status, risk, and decision tracking harder to keep current."}, "risks": [{"claim": "The risk is that organizational politics and incomplete tool coverage limit how much teams accept one generated graph as the source of truth.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Team-wide product graph', 'SaaS', 'Seed', '$2.5M', NULL, NULL, NULL, 'US', 'product management,engineering management,knowledge graph,mcp', 'AI2 Incubator', NULL, 1, 'devplan.webp', 'ready', 'published', 'manual', '2026-06-19 05:55:41', '2026-06-19 05:55:41') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-didit', 'didit', 'didit.me', 'https://didit.me/', 'Didit', 'One API for KYC, KYB, AML, fraud monitoring, wallets, and agent-native identity flows.', 'The useful bet is making identity a programmable API instead of a pile of vendor checks. Didit puts KYC, KYB, AML, liveness, transaction monitoring, wallet screening, public pricing, SDKs, and an MCP server behind one workflow. Unlike legacy verification suites that sell opaque modules, it exposes enough controls for a developer or coding agent to wire a flow in minutes. The risk is whether global data coverage stays defensible as regulators and fraud patterns move.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://didit.me/", "type": "official"}, {"id": "docs_api", "label": "Didit Sessions API docs", "url": "https://docs.didit.me/sessions-api/overview", "type": "product"}, {"id": "docs_mcp", "label": "Didit MCP docs", "url": "https://docs.didit.me/mcp", "type": "product"}, {"id": "pricing", "label": "Didit pricing", "url": "https://didit.me/pricing/", "type": "product"}, {"id": "funding_1", "label": "Didit seed announcement", "url": "https://didit.me/blog/didit-7-5m-seed-infrastructure-identity-fraud/", "type": "funding"}], "product_evidence": [{"claim": "The official site shows a single API surface for KYC, KYB, AML, liveness, transaction monitoring, wallet screening, and identity workflows across 220+ countries.", "source_ids": ["official_site"]}, {"claim": "The public docs expose Sessions API flows, SDKs, an MCP server, integration prompts, and sandbox setup for developer-led identity verification.", "source_ids": ["docs_api", "docs_mcp"]}, {"claim": "The pricing page publishes pay-per-call tiers for verification, AML, wallet screening, age estimation, and fraud-intelligence checks.", "source_ids": ["pricing"]}], "market_context": {"primary_user": "Developers, risk teams, compliance operators, and fintech product teams building identity and fraud workflows.", "category": "Fintech", "differentiation": "Agent- and API-native breadth across identity, fraud, KYC, KYB, AML, and wallet screening instead of a narrow verification module.", "why_now": "The May 27, 2026 seed announcement funds Didit after it opened public docs, pricing, sandbox access, and MCP integration paths."}, "risks": [{"claim": "The open question is whether broad global coverage remains accurate and compliant as fraud patterns and local verification rules change.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Agent-native identity API', 'Fintech', 'Seed', '$7.5M', NULL, NULL, NULL, 'Global / Remote', 'identity verification,fraud,kyc,api,regtech', 'Y Combinator', '{"docs": "https://docs.didit.me/", "api": "https://docs.didit.me/sessions-api/overview", "mcp": "https://docs.didit.me/mcp", "pricing": "https://didit.me/pricing/", "careers": "https://didit.jobs.personio.com/"}', 1, 'didit.webp', 'ready', 'published', 'manual', '2026-05-31 06:05:47', '2026-05-31 06:05:47') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-dust', 'dust', 'app.dust.tt', 'https://app.dust.tt', 'Dust', 'Multiplayer AI workspace where teams build and run shared workplace agents.', 'The useful bet is making enterprise AI collaborative instead of a private chat window. Dust gives teams shared agents, Slack/GitHub/Drive connectors, model choice, RBAC, audit logs, and a semantic layer that improves from use. Unlike one-off copilots, the workspace makes agent behavior visible to teammates. The risk is whether agent sprawl becomes the new collaboration tax.', '{"verified_at": "2026-06-10", "sources": [{"id": "official_site", "label": "Official product docs", "url": "https://docs.dust.tt/docs/welcome-to-dust", "type": "official"}, {"id": "official_access_controls", "label": "Official access controls docs", "url": "https://docs.dust.tt/docs/access-controls-and-permissions", "type": "official"}, {"id": "official_audit_logs", "label": "Official audit logs docs", "url": "https://docs.dust.tt/docs/audit-logs", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/18/3296726/0/en/Dust-raises-40M-to-make-AI-multiplayer-inside-the-enterprise.html", "type": "funding"}], "product_evidence": [{"claim": "Dust''s official docs describe a unified AI-powered workspace that integrates with enterprise tools and data sources including Slack, Google Drive, Notion, Confluence, and GitHub.", "source_ids": ["official_site"]}, {"claim": "Dust''s official docs define workspaces as collaborative environments for teams and AI agents with spaces, tool connections, access roles, and enterprise audit logs for significant workspace actions.", "source_ids": ["official_access_controls", "official_audit_logs"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Shared agents for teams", "why_now": "Recent source-backed funding and public product evidence make ai agents, enterprise ai, collaboration worth tracking."}, "risks": [{"claim": "The risk is whether agent sprawl becomes the new collaboration tax.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Shared agents for teams', 'AI / ML', 'Series B', '$40M', NULL, NULL, NULL, 'Global / Remote', 'ai agents,enterprise ai,collaboration,knowledge management', 'Sequoia Capital', '{"careers": "https://dust.tt/jobs"}', 1, 'dust.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-eleven-labs', 'eleven-labs', 'elevenlabs.io', 'https://elevenlabs.io', 'ElevenLabs', 'AI voice generation and speech synthesis platform.', 'The surprising thing is not that voice cloning works. It is that 30 seconds of audio can already get you something commercially usable. ElevenLabs is betting this becomes infrastructure for dubbing, audiobooks, and accessibility, not just a viral demo. That is a narrower and more durable business than AI voice as spectacle.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://elevenlabs.io", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2024/01/22/voice-cloning-startup-elevenlabs-lands-80m-achieves-unicorn-status/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes ElevenLabs: AI voice generation and speech synthesis platform.", "source_ids": ["official_site"]}, {"claim": "It is that 30 seconds of audio can already get you something commercially usable.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Voice AI that actually sounds human", "why_now": "Recent source-backed funding and public product evidence make voice ai, speech synthesis, text to speech worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Voice AI that actually sounds human', 'AI / ML', 'Series B', '$80M', 2022, '50-100', 'New York', 'US', 'voice ai,speech synthesis,text to speech,artificial intelligence', 'Andreessen Horowitz, Nat Friedman, Daniel Gross', '{"github": "https://github.com/elevenlabs", "twitter": "https://x.com/elevenlabsio", "linkedin": "https://linkedin.com/company/elevenlabs", "careers": "https://elevenlabs.io/careers"}', 0, 'eleven-labs.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-endra', 'endra', 'www.endra.ai', 'https://www.endra.ai/', 'Endra', 'AI-powered MEP design platform for model and documentation generation.', 'The bet is that MEP engineering can become model generation instead of manual drafting. Endra turns fire-alarm and building-system inputs into 2D and 3D documentation, supports Revit, DXF, PDF, RVT, and IFC exports, and claims a 300-hour project can compress to 30 minutes. Unlike generic CAD copilots, it starts inside one regulated engineering workflow. The risk is whether coverage expands beyond fire alarm without losing compliance precision.', '{"verified_at": "2026-06-04", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.endra.ai/", "type": "official"}, {"id": "funding_1", "label": "Andreessen Horowitz investment announcement", "url": "https://a16z.com/announcement/investing-in-endra/", "type": "funding"}], "product_evidence": [{"claim": "The official site describes a purpose-built MEP platform that generates 2D drawings and 3D models and syncs with Revit.", "source_ids": ["official_site"]}, {"claim": "The product surface lists DXF, PDF, RVT, and IFC exports plus fire-alarm standards and a 300-hours-versus-30-minutes case study.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "MEP engineers, fire-alarm designers, and construction-design teams producing regulated building documentation.", "category": "AI / ML", "differentiation": "Endra starts with narrow MEP generation, standards support, and Revit-ready outputs instead of a general CAD copilot.", "why_now": "The June 2026 a16z-led Series A gives Endra capital to industrialize AI design generation for building systems."}, "risks": [{"claim": "The open question is whether coverage expands beyond fire alarm while preserving compliance precision.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'MEP design generation', 'AI / ML', 'Series A', '$50M', NULL, NULL, NULL, 'Europe', 'construction,engineering,mep design,revit,ai design', 'Andreessen Horowitz', '{"careers": "https://www.endra.ai/careers"}', 1, 'endra.webp', 'ready', 'published', 'manual', '2026-06-04 05:59:59', '2026-06-04 05:59:59') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ent', 'ent', 'ent.ai', 'https://ent.ai/', 'Ent', 'Intent-aware endpoint security that intervenes before risky human or AI-agent actions complete.', 'The bet is that endpoint security should read intent, not just processes. Ent watches human and AI-agent activity across apps, AI tools, and workflows, then can nudge or block before a risky action completes. Compared with EDR tools that reconstruct what happened after the breach, this is prevention at the moment of work. The question is whether enterprises will trust a new agent this close to the desktop.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://ent.ai/", "type": "official"}, {"id": "official_platform", "label": "Official platform page", "url": "https://ent.ai/platform", "type": "official"}, {"id": "funding_1", "label": "BusinessWire funding announcement", "url": "https://www.businesswire.com/news/home/20260616680280/en/Ent-Emerges-from-Stealth-to-Bring-Prevention-Back-to-Cybersecurity", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Ent as an intent-aware workspace security platform for human, AI, and application activity across enterprise workflows.", "source_ids": ["official_site"]}, {"claim": "The platform page says Ent runs as one AI-native agent across endpoints, reading intent behind actions and stepping in with plain-language guidance or hard blocks before risky work completes.", "source_ids": ["official_platform"]}, {"claim": "Ent lists integrations with EDR, SIEM, SOAR, IAM, collaboration, and service-management systems including CrowdStrike, Defender, Splunk, Okta, Google Workspace, Jira, ServiceNow, and Slack.", "source_ids": ["official_platform"]}, {"claim": "The funding announcement says Ent is generally available for Windows, macOS, Linux, and browser-extension deployments and is backed by a $100M seed round led by Decibel.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise CISOs, security operations teams, insider-risk teams, and AI platform owners responsible for endpoint and agent activity.", "category": "Cybersecurity", "differentiation": "Ent focuses on interpreting user and agent intent at the endpoint, then intervening before an action completes rather than only reconstructing incidents after detection.", "why_now": "AI agents and faster exploit discovery compress the response window for security teams, making prevention and policy enforcement at the work surface more valuable."}, "risks": [{"claim": "The open question is whether enterprises will accept an endpoint agent that interprets intent without creating privacy, false-positive, or workforce-trust backlash.", "basis": "VentureDex editorial assessment based on official product pages and current funding-source review."}]}', 5, '$100M seed for intent-aware security', 'SaaS', 'Seed', '$100M', 2025, NULL, 'San Francisco', 'US', 'cybersecurity,endpoint security,ai agents,insider risk,dlp', 'Decibel, Sequoia Capital, Crosspoint Capital, Craft Ventures, Shield Capital, Felicis, In-Q-Tel', '{"linkedin": "https://www.linkedin.com/company/ent-security", "twitter": "https://x.com/Ent_Security", "careers": "https://ent.ai/joinus"}', 0, 'ent.webp', 'ready', 'published', 'manual', '2026-06-17 05:54:00', '2026-06-17 05:54:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-enzo-health', 'enzo-health', 'www.enzo.health', 'https://www.enzo.health', 'Enzo Health', 'Home health intake, scribe, and QA workflows with AI.', 'Home health software often treats the nurse as the data-entry layer; this pushes the paperwork into the visit itself. Enzo shows Intake, Scribe, and QA modules with OASIS validation, referral checks, secure messaging, and 5-minute intake-to-admission claims. Unlike generic medical scribes, the bet is one thread from bedside note to reimbursement. The risk is integrating deeply enough with fragmented agency systems.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.enzo.health", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/enzo-health-raises-26m-to-deploy-ai-across-home-health-to-meet-unprecedented-nationwide-demand-for-post-acute-care-302760538.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Enzo Health: Home health intake, scribe, and QA workflows with AI.", "source_ids": ["official_site"]}, {"claim": "Enzo shows Intake, Scribe, and QA modules with OASIS validation, referral checks, secure messaging, and 5-minute intake-to-admission claims.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "$20M Series A for home health AI", "why_now": "Recent source-backed funding and public product evidence make home health, clinical documentation, intake worth tracking."}, "risks": [{"claim": "The risk is integrating deeply enough with fragmented agency systems.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$20M Series A for home health AI', 'HealthTech', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'home health,clinical documentation,intake,quality assurance', 'N47, Gradient, Tandem Ventures, Rigby Watts', '{"careers": "https://www.enzo.health/careers"}', 1, 'enzo-health.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-equal-ai', 'equal-ai', 'www.equal.in', 'https://www.equal.in/', 'Equal AI', 'AI call assistant that screens unknown calls and explains caller intent before pickup.', 'Call screening is not new, but India makes it harder: delivery calls, finance spam, and code-mixed speech all collide on one phone. Equal AI shows Android call answering, live transcripts, quick replies, recordings, 10+ languages, and 300K daily active users. Unlike caller-ID apps that only name the number, the bet is to make the phone conversation itself inspectable before you join.', '{"verified_at": "2026-06-20", "sources": [{"id": "official_site", "label": "Official Equal company site", "url": "https://www.equal.in/", "type": "official"}, {"id": "app_store", "label": "Equal AI Google Play listing", "url": "https://play.google.com/store/apps/details?id=in.equal.ai.assistant", "type": "product"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/06/11/equal-ai-raises-30m-to-screen-calls-so-indians-dont-have-to/", "type": "funding"}], "product_evidence": [{"claim": "The Google Play listing describes Equal AI as an AI call assistant that picks up, speaks, and screens unknown calls for the user.", "source_ids": ["app_store"]}, {"claim": "The Google Play listing describes live call-screening transcripts, caller-intent summaries, one-tap joining, typed messages read by the assistant, full recordings, and post-call summaries.", "source_ids": ["app_store"]}, {"claim": "TechCrunch reports the app has more than one million monthly active users, more than 300,000 daily active users, and support for over 10 languages.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Indian smartphone users deciding whether to answer unknown delivery, finance, work, and marketing calls.", "category": "AI / ML", "differentiation": "Equal AI moves beyond caller ID by holding the first part of the conversation, exposing transcript and intent before the user joins.", "why_now": "The Series B gives the company capital to expand a consumer voice assistant that already has meaningful daily usage in a call-heavy local market."}, "risks": [{"claim": "The product still has to prove it can defend privacy expectations and keep call-handling quality high as it expands beyond unknown-number screening.", "basis": "VentureDex editorial assessment based on official product evidence, Google Play copy, and TechCrunch''s note that known-number screening and paid tiers remain planned."}]}', 5, '300K daily call assistant', 'AI / ML', 'Series B', '$30M', NULL, NULL, NULL, 'China / Asia', 'ai assistant,voice ai,consumer,call screening,india', 'Prosus Ventures', '{"product": "https://play.google.com/store/apps/details?id=in.equal.ai.assistant", "linkedin": "https://www.linkedin.com/company/myequalai"}', 1, 'equal-ai.webp', 'ready', 'published', 'manual', '2026-06-13 05:49:00', '2026-06-13 05:49:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-equipifi', 'equipifi', 'www.equipifi.com', 'https://www.equipifi.com', 'equipifi', 'White-label BNPL and installment-lending platform for banks and credit unions.', 'The better BNPL bet is hiding inside the bank app, not at checkout. equipifi gives credit unions and banks pre-approved pay-over-time offers, debit-card installment loans, eligibility controls, reporting, and launch paths that need about 10 team hours. Unlike consumer BNPL brands, it sells the rails to institutions that already hold the relationship. The product is more useful than beautiful, which keeps the rating grounded.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.equipifi.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/equipifi-secures-34-million-series-b-to-accelerate-buy-now-pay-later-across-us-financial-institutions-302771649.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes equipifi: White-label BNPL and installment-lending platform for banks and credit unions.", "source_ids": ["official_site"]}, {"claim": "equipifi gives credit unions and banks pre-approved pay-over-time offers, debit-card installment loans, eligibility controls, reporting, and launch paths that need about 10 team hours.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "Bank-native BNPL rails", "why_now": "Recent source-backed funding and public product evidence make fintech, bnpl, credit unions worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 3, 'Bank-native BNPL rails', 'Fintech', 'Series B', '$34M', NULL, NULL, NULL, 'US', 'fintech,bnpl,credit unions,banking', 'Left Lane Capital', '{"careers": "https://www.equipifi.com/careers"}', 0, 'equipifi.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ethos', 'ethos', 'agent.askethos.com', 'https://agent.askethos.com', 'Ethos', 'AI-matched expert network with voice-based onboarding.', 'The sharper idea is that expert networks should know what people can do, not just what titles they held. Ethos uses voice onboarding, public-source enrichment, paid opportunity cards, and 35,000 weekly expert joins to build a deeper matching layer. Unlike LinkedIn search or GLG-style forms, the bet is that interviews create a better skill graph than resumes. The risk is quality control once the network scales faster than its eight-person team.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://agent.askethos.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/06/ethos-raises-22-75m-from-a16z-for-its-expert-network-with-voice-onboarding/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Ethos: AI-matched expert network with voice-based onboarding.", "source_ids": ["official_site"]}, {"claim": "Ethos uses voice onboarding, public-source enrichment, paid opportunity cards, and 35,000 weekly expert joins to build a deeper matching layer.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Supply-and-demand operators evaluating marketplace coordination workflows.", "category": "Marketplace", "differentiation": "35K experts joining each week", "why_now": "Recent source-backed funding and public product evidence make expert network, ai matching, voice onboarding worth tracking."}, "risks": [{"claim": "The risk is quality control once the network scales faster than its eight-person team.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '35K experts joining each week', 'Marketplace', 'Series A', '$22.75M', NULL, NULL, NULL, 'Europe', 'expert network,ai matching,voice onboarding,marketplace', 'Andreessen Horowitz, General Catalyst, XTX Markets, Evantic Capital, Common Magic', NULL, 1, 'ethos.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-exa', 'exa', 'exa.ai', 'https://exa.ai/', 'Exa', 'Search API, content extraction, answer, research, and vertical indexes built for AI agents.', 'The bet is that agents need a search engine built for machines rather than a prettier SERP for humans. Exa exposes `/search`, `/contents`, `/answer`, research APIs, category indexes for companies, people, papers, and news, and latency tiers down to ~250 ms. Unlike wrappers over Google or Bing, it is building the crawler, embeddings, and vector databases itself.', '{"verified_at": "2026-05-27", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://exa.ai/", "type": "official"}, {"id": "docs_search", "label": "Exa Search API docs", "url": "https://exa.ai/docs/reference/search-api-guide", "type": "product"}, {"id": "docs_getting_started", "label": "Exa API overview docs", "url": "https://exa.ai/docs/reference/getting-started", "type": "product"}, {"id": "funding_1", "label": "Exa", "url": "https://exa.ai/blog/announcing-series-c", "type": "funding"}], "product_evidence": [{"claim": "Docs describe four core API surfaces: `/search`, `/contents`, `/answer`, and `/research` for retrieval, parsed content, answers, and cited structured research.", "source_ids": ["docs_getting_started"]}, {"claim": "The Search API guide lists latency-tiered search modes, token-efficient highlights, and category indexes for companies, people, research papers, and news.", "source_ids": ["docs_search"]}], "market_context": {"primary_user": "Developers building agents, RAG workflows, research tools, and AI products that need web retrieval.", "category": "DevTools", "differentiation": "Own crawler and embedding models for agent search instead of wrapping Google or Bing results.", "why_now": "Exa''s May 20, 2026 Series C announcement says a16z led a $250M round to scale search infrastructure for AI agents."}, "risks": [{"claim": "The open question is whether independent search infrastructure can keep quality, latency, and cost advantages as model labs and cloud platforms add native retrieval.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Agent-native search API', 'DevTools', 'Series C', '$250M', NULL, NULL, NULL, 'US', 'ai search,api,agents,retrieval,web crawling', 'Andreessen Horowitz', '{"careers": "https://exa.ai/careers"}', 1, 'exa.webp', 'ready', 'published', 'manual', '2026-05-27 06:15:57', '2026-05-27 06:15:57') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-fazeshift', 'fazeshift', 'www.fazeshift.com', 'https://www.fazeshift.com', 'Fazeshift', 'AI accounts receivable agents for finance teams.', 'The bet is boring on purpose: automate the cash cycle inside the systems finance teams already trust, not replace them. Fazeshift shows cash application, collections, contract review, Stripe/NetSuite/Sage Intacct billing, SOC 1/2, and customer claims like 50% DSO reduction. Unlike generic finance copilots, each agent maps to a stubborn AR job. The test is whether invoice edge cases stay tractable at scale.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.fazeshift.com", "type": "official"}, {"id": "funding_1", "label": "Fazeshift", "url": "https://www.fazeshift.com/newsroom", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Fazeshift: AI accounts receivable agents for finance teams.", "source_ids": ["official_site"]}, {"claim": "Fazeshift shows cash application, collections, contract review, Stripe/NetSuite/Sage Intacct billing, SOC 1/2, and customer claims like 50% DSO reduction.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$22M Series A for AR agents", "why_now": "Recent source-backed funding and public product evidence make accounts receivable, finance ops, ai agents worth tracking."}, "risks": [{"claim": "The test is whether invoice edge cases stay tractable at scale.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$22M Series A for AR agents', 'Fintech', 'Series A', '$22M', NULL, NULL, NULL, 'US', 'accounts receivable,finance ops,ai agents,billing automation', 'F-Prime Capital', '{"careers": "https://www.fazeshift.com/careers"}', 1, 'fazeshift.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-fearn', 'fearn', 'fearn.ai', 'https://fearn.ai/', 'Fearn', 'AI-assisted patent drafting workflow with attorney review.', 'The useful bet is that patent drafting can become a guided technical workflow rather than a blank attorney memo. Fearn shows invention-note upload, AI extraction, patent preview, attorney review, a fixed $2,000 filing path, and standards checks tied to 35 USC and MPEP rules. Unlike broad legal copilots, it narrows the job to patent construction. The risk is whether expert review catches edge cases before filing.', '{"verified_at": "2026-06-11", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://fearn.ai/", "type": "official"}, {"id": "funding_1", "label": "Fearn seed funding coverage", "url": "https://www.businessinsider.com/a16z-backed-fearn-raises-5-million-legal-ai-patent-drafting-2026-6", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Fearn as patent-drafting software that can turn invention notes into a complete patent draft.", "source_ids": ["official_site"]}, {"claim": "Fearn describes upload, AI extraction, patent preview, attorney review, and a fixed $2,000 filing path.", "source_ids": ["official_site"]}, {"claim": "The product surface cites patent-law checks tied to 35 USC, 37 CFR, and MPEP rules, plus enterprise deployment and security controls.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Founders, technical teams, patent attorneys, and IP operators preparing draft patents from invention notes.", "category": "SaaS", "differentiation": "Fearn narrows AI drafting to patent construction with attorney review rather than offering broad legal chat.", "why_now": "AI-native technical teams are filing more inventions and want faster IP workflows without removing expert legal review."}, "risks": [{"claim": "The open question is whether Fearn''s review path catches specification, claim-scope, and prior-art issues before filing.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Patent drafting workflow', 'SaaS', 'Seed', '$5.5M', NULL, NULL, NULL, 'US', 'legaltech,patent drafting,ai agents,intellectual property,enterprise software', 'Kindred Ventures, Andreessen Horowitz', NULL, 1, 'fearn.webp', 'ready', 'published', 'manual', '2026-06-11 06:04:13', '2026-06-11 06:04:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-featherless', 'featherless', 'featherless.ai', 'https://featherless.ai', 'Featherless', 'Serverless API access to 30,000+ open-weight AI models.', 'The bet is open-model inference without renting a GPU box or accepting a closed API. Featherless exposes 30,000+ models through one API, docs for chat completions, embeddings, tool calling, vision, and a live model library with usage counts. Unlike raw GPU clouds, it sells model choice and predictable pricing as the product. The hard part is keeping that promise when every niche model wants different hardware.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://featherless.ai", "type": "official"}, {"id": "funding_1", "label": "Featherless", "url": "https://featherless.ai/blog/series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Featherless: Serverless API access to 30,000+ open-weight AI models.", "source_ids": ["official_site"]}, {"claim": "Featherless exposes 30,000+ models through one API, docs for chat completions, embeddings, tool calling, vision, and a live model library with usage counts.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "$20M Series A for 30K models", "why_now": "Recent source-backed funding and public product evidence make ai infrastructure, inference, open models worth tracking."}, "risks": [{"claim": "The hard part is keeping that promise when every niche model wants different hardware.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$20M Series A for 30K models', 'DevTools', 'Series A', '$20M', NULL, NULL, NULL, 'Global / Remote', 'ai infrastructure,inference,open models,developer tools', 'AMD Ventures', NULL, 1, 'featherless.webp', 'ready', 'published', 'manual', '2026-05-03 06:28:30', '2026-05-03 06:28:30') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-findigs', 'findigs', 'www.findigs.com', 'https://www.findigs.com/', 'Findigs', 'AI-native rental screening decisions for property managers and residential operators.', 'Resident screening has too often been a score that pushes hard calls back to leasing teams. Findigs turns the workflow into an automated yes/no decision, with the site publishing 3.4-hour median decisions, 80% average eviction reduction, and policy, fraud, and pet-screening modules. Unlike a background-check vendor, it sells revenue quality across the full application process. The risk is whether those outcome claims hold for operators beyond the 400K+ units cited in the funding release.', '{"verified_at": "2026-06-07", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.findigs.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://www.findigs.com/careers", "type": "official"}, {"id": "funding_1", "label": "Findigs Series C announcement", "url": "https://www.globenewswire.com/news-release/2026/06/02/3305372/0/en/findigs-raises-32m-series-c-funding-to-redefine-leasing-decisioning.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes an AI-native resident screening platform that takes manual applicant screening work off property managers'' plates.", "source_ids": ["official_site"]}, {"claim": "The public site publishes metrics for 3.4-hour median decision time, 80% average eviction-rate reduction, 45% of decisions outside business hours, and 8 hours saved per leasing agent weekly.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Findigs generates automated yes/no decisions, supports LIHTC and Section 8 workflows, and covers 400,000+ units.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Residential property operators and leasing teams that need faster applicant decisions without increasing fraud, delinquency, or eviction risk.", "category": "SaaS", "differentiation": "Findigs models post-lease performance and returns an operator-ready decision instead of handing over a generic screening score.", "why_now": "Higher vacancies and operating costs make revenue quality and faster leasing decisions more valuable for multifamily operators."}, "risks": [{"claim": "The open question is whether Findigs can keep outcome guarantees and low manual review rates as it expands across more housing types and operator policies.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '3.4-hour leasing decisions', 'SaaS', 'Series C', '$32M', NULL, NULL, NULL, 'US', 'proptech,screening,leasing,fraud,property management', 'RPM Ventures', '{"careers": "https://www.findigs.com/careers"}', 1, 'findigs.webp', 'ready', 'published', 'manual', '2026-06-07 06:05:50', '2026-06-07 06:05:50') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-flexprice', 'flexprice', 'flexprice.io', 'https://flexprice.io/', 'Flexprice', 'Open-source usage billing infrastructure for AI and API-first companies.', 'The bet is that AI pricing breaks before product-market fit does. Flexprice exposes metering, credits, hybrid plans, SDKs, MCP support, a CLI, GitHub repo, and case-study proof around 20B events/month. Unlike seat-based billing tools, it treats event streams and pricing experiments as the product surface. The risk is whether finance teams trust open-source billing when revenue recognition gets messy.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://flexprice.io/", "type": "official"}, {"id": "funding_1", "label": "ET Entrepreneur", "url": "https://entrepreneur.economictimes.indiatimes.com/news/funding/flexprice-secures-15-million-in-seed-funding-to-revolutionize-ai-billing-solutions/131320984", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Flexprice: Open-source usage billing infrastructure for AI and API-first companies.", "source_ids": ["official_site"]}, {"claim": "Flexprice exposes metering, credits, hybrid plans, SDKs, MCP support, a CLI, GitHub repo, and case-study proof around 20B events/month.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "AI usage billing stack", "why_now": "Recent source-backed funding and public product evidence make billing, usage metering, pricing worth tracking."}, "risks": [{"claim": "The risk is whether finance teams trust open-source billing when revenue recognition gets messy.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AI usage billing stack', 'DevTools', 'Seed', '$1.5M', NULL, NULL, NULL, 'Global / Remote', 'billing,usage metering,pricing,developer tools,ai infrastructure', 'Shastra VC', '{"github": "https://github.com/flexprice/flexprice"}', 1, 'flexprice.webp', 'ready', 'published', 'manual', '2026-05-26 09:43:21', '2026-05-26 09:43:21') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-freshflow', 'freshflow', 'freshflow.ai', 'https://freshflow.ai/', 'Freshflow', 'AI replenishment platform for fresh-grocery forecasting, ordering, and waste reduction.', 'Fresh departments are not normal inventory problems: shelf life, scan errors, spoilage, promotions, and weather distort demand every day. Freshflow models 120+ signals and gives buyers exception-based order proposals instead of another BI screen. The useful proof is operational: customers cite 93% proposal acceptance, up to 30% less waste, and up to 4% more sales. The risk is whether retailer data quality can keep the model honest.', '{"verified_at": "2026-06-06", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://freshflow.ai/", "type": "official"}, {"id": "funding_1", "label": "Freshflow Series A announcement", "url": "https://www.worldfund.vc/articles/freshflow-brings-ai-to-europes-fresh-aisles-and-closes-10m-series-a", "type": "funding"}], "product_evidence": [{"claim": "The official site breaks the product into Forecast, Inventory, Optimization, and Freshflow App modules for fresh-food replenishment decisions.", "source_ids": ["official_site"]}, {"claim": "Freshflow publishes customer-facing outcome claims including 120+ demand signals, 93% order-proposal acceptance, up to 30% less waste, and up to 4% more revenue.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "European grocery retailers and fresh-department buyers balancing availability, waste, and daily order proposals.", "category": "AI / ML", "differentiation": "Freshflow optimizes fresh ordering around shelf life and store-level demand instead of treating produce like durable inventory.", "why_now": "The June 2026 Series A gives the company capital to expand across a European grocery market under waste and margin pressure."}, "risks": [{"claim": "The open question is whether each retailer''s POS, spoilage, promotion, and scan-error data is clean enough for reliable store-level automation.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Fresh-replenishment AI', 'AI / ML', 'Series A', '$10M', NULL, NULL, NULL, 'Europe', 'grocery,forecasting,inventory,waste reduction,retail', 'Reimann Investors', '{"careers": "https://freshflow.ai/careers/"}', 1, 'freshflow.webp', 'ready', 'published', 'manual', '2026-06-06 05:56:19', '2026-06-06 05:56:19') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-frontier-health', 'frontier-health', 'www.frontierhealth.ai', 'https://www.frontierhealth.ai/', 'Frontier Health', 'AI teammate automating high-volume healthcare administration workflows.', 'Healthcare operations often fail in the handoff between scheduling systems, patient messages, and back-office queues. Frontier Health says Juno works across existing systems to book, validate, track, chase, update, and communicate on admin tasks. Unlike point bots for one inbox, it is selling an operational teammate for NHS-style workflows. The risk is whether safe handback and governance stay reliable across clinical-adjacent exceptions.', '{"verified_at": "2026-06-20", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.frontierhealth.ai/", "type": "official"}, {"id": "funding_1", "label": "TNW seed funding report", "url": "https://thenextweb.com/news/frontier-health-16m-seed-atomico-nhs-admin-ai-juno", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Juno as a supportive AI teammate for healthcare administration teams, automating repetitive high-volume work across existing systems.", "source_ids": ["official_site"]}, {"claim": "The public workflow examples cover outpatient referrals, waiting-list management, appointment booking and rescheduling, patient communications, and patient tracking.", "source_ids": ["official_site"]}, {"claim": "TNW says Frontier Health deployed in an NHS environment in eight weeks and reported 221 staff days saved plus a 22 percent median emergency-department time reduction.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Healthcare operations, NHS administration, scheduling, referral, rota, and patient-communication teams.", "category": "Healthcare operations automation", "differentiation": "Juno is positioned as a cross-system admin teammate that executes steps and hands back exceptions, not just a patient chatbot.", "why_now": "Health systems are trying to reduce administrative backlogs without replacing core clinical systems or adding more manual coordination."}, "risks": [{"claim": "The open question is whether healthcare buyers can validate safety, escalation, and audit controls fast enough for broader workflow automation.", "basis": "VentureDex editorial assessment based on official product evidence and NHS deployment coverage."}]}', 4, 'AI healthcare admin', 'HealthTech', 'Seed', '$16M', NULL, NULL, NULL, 'Europe', 'healthcare,admin automation,nhs,ai agents,operations', 'Atomico', '{"careers": "https://www.frontierhealth.ai/careers"}', 1, 'frontier-health.webp', 'ready', 'published', 'manual', '2026-06-20 06:02:12', '2026-06-20 06:02:12') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-geordie-ai', 'geordie-ai', 'www.geordie.ai', 'https://www.geordie.ai/', 'Geordie AI', 'Security and governance platform for enterprise AI agents and their runtime behavior.', 'The bet is that AI-agent risk lives in what agents decide to do between prompt and output. Geordie maps agents across cloud, code, endpoint, tools, permissions, MCP connections, and runtime behavior; its Series A post says one POC surfaced 327% more agents than existing inventories. Unlike prompt firewalls, it is watching agent operations. The risk is whether security teams can enforce controls without slowing adoption.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.geordie.ai/", "type": "official"}, {"id": "product_page", "label": "Geordie product page", "url": "https://www.geordie.ai/product/", "type": "product"}, {"id": "funding_1", "label": "Geordie AI", "url": "https://www.geordie.ai/resources/geordie-ai-raises-30m-series-a-as-enterprises-race-to-govern-autonomous-ai-agents", "type": "funding"}], "product_evidence": [{"claim": "The product page says Geordie discovers agents across cloud, code, and endpoint environments and maps tools, permissions, MCP connections, skills, prompts, models, and sub-tools.", "source_ids": ["product_page"]}, {"claim": "The Series A post describes Beam runtime remediation and says one customer POC found 327% more agents than existing inventories, plus MCP command injection and credential-leakage risks.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Security and governance teams responsible for enterprise AI-agent adoption.", "category": "AI / ML", "differentiation": "Agent-native visibility and runtime controls rather than prompt-only or network-only guardrails.", "why_now": "The May 28, 2026 Series A followed RSAC Innovation Sandbox momentum and enterprise demand for AI-agent governance."}, "risks": [{"claim": "The risk is whether agent governance becomes a standalone buying category or gets absorbed into existing security suites.", "basis": "VentureDex editorial assessment based on official product and funding-source review."}]}', 5, 'AI-agent security control', 'AI / ML', 'Series A', '$30M', NULL, NULL, NULL, 'Europe', 'ai security,ai agents,governance,mcp,runtime controls', 'Balderton Capital', '{"careers": "https://jobs.ashbyhq.com/geordieai"}', 1, 'geordie-ai.webp', 'ready', 'published', 'manual', '2026-05-31 02:16:09', '2026-05-31 02:16:09') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gizmo', 'gizmo', 'gizmo.ai', 'https://gizmo.ai', 'Gizmo', 'AI study app that turns notes into flashcards, quizzes, and streak-based learning loops.', 'Most study apps still behave like digital stationery; the sharper move is designing for the attention span TikTok trained instead. Gizmo pairs AI-generated flashcards with streaks, leaderboards, limited lives, and social challenges; it reaches 13 million users in 120 countries. Instead of asking students to become more disciplined, it is betting that better habits can piggyback on addictive product design. The risk is that engagement mechanics outrun learning depth once the novelty wears off.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://gizmo.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/15/ai-learning-app-gizmo-levels-up-with-13m-users-and-a-22m-investment/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Gizmo: AI study app that turns notes into flashcards, quizzes, and streak-based learning loops.", "source_ids": ["official_site"]}, {"claim": "Gizmo pairs AI-generated flashcards with streaks, leaderboards, limited lives, and social challenges; it reaches 13 million users in 120 countries.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Learners, educators, or training teams evaluating learning and study workflows.", "category": "EdTech", "differentiation": "TikTok loops for studying", "why_now": "Recent source-backed funding and public product evidence make education, study tools, flashcards worth tracking."}, "risks": [{"claim": "The risk is that engagement mechanics outrun learning depth once the novelty wears off.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'TikTok loops for studying', 'EdTech', 'Series A', '$22M', NULL, NULL, NULL, 'Europe', 'education,study tools,flashcards,consumer app', 'Shine Capital, Ada Ventures, Seek Investments, GSV, NFX', '{"careers": "https://apply.workable.com/gizmo/"}', 1, 'gizmo.webp', 'ready', 'published', 'manual', '2026-04-20 11:02:55', '2026-04-20 11:02:55') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-govwell', 'govwell', 'www.govwell.com', 'https://www.govwell.com', 'GovWell', 'AI permitting and licensing platform for local governments.', 'This is civic software with a painfully concrete wedge: permits, inspections, licenses, and code enforcement instead of vague government change. GovWell shows AI AutoCheck, 5,000+ processes, 100+ agencies, 35+ states, and processing that can move from 10 days to under an hour. Unlike legacy municipal systems, the product sells speed without making staff change departments. Procurement pace is the obvious drag.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.govwell.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/govwell-raises-25m-series-a-led-by-insight-partners-to-build-the-ai-operating-system-for-modern-government-302770627.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes GovWell: AI permitting and licensing platform for local governments.", "source_ids": ["official_site"]}, {"claim": "GovWell shows AI AutoCheck, 5,000+ processes, 100+ agencies, 35+ states, and processing that can move from 10 days to under an hour.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "100+ agencies, $25M Series A", "why_now": "Recent source-backed funding and public product evidence make civic software, permitting, licensing worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '100+ agencies, $25M Series A', 'SaaS', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'civic software,permitting,licensing,local government', 'Insight Partners', '{"careers": "https://www.govwell.com/careers"}', 1, 'govwell.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gradial', 'gradial', 'www.gradial.com', 'https://www.gradial.com/', 'Gradial', 'AI marketing agents for brief-to-live campaign execution across enterprise content supply chains.', 'Marketing ops has a funny failure mode: the strategy is approved, then execution disappears into tickets. Gradial maps 4 agent jobs across brief, asset execution, generative engine optimization, and journey insights, with customer stories for T-Mobile, AWS, Prudential, and Cisco. Unlike CMS plugins that fix one publishing step, it sits across the content supply chain. The test is whether governance keeps up when agents touch brand risk.', '{"verified_at": "2026-06-18", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.gradial.com/", "type": "official"}, {"id": "official_docs", "label": "Official documentation", "url": "https://docs.gradial.com/", "type": "product"}, {"id": "funding_1", "label": "Axios funding coverage", "url": "https://www.axios.com/2026/06/18/gradial-ai-agents-marketing", "type": "funding"}], "product_evidence": [{"claim": "The official homepage says Gradial creates execution velocity from brief to live across the enterprise content supply chain.", "source_ids": ["official_site"]}, {"claim": "The site names agent jobs for content and campaign execution, asset execution, generative engine optimization, and insights and journeys.", "source_ids": ["official_site"]}, {"claim": "Gradial shows enterprise customer stories and logos including T-Mobile, AWS, Prudential, Cisco, Microsoft, Electronic Arts, and Weber.", "source_ids": ["official_site"]}, {"claim": "Axios reports a $65M Series C led by Insight Partners for Gradial AI agents that help brands create marketing campaigns.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise marketing, digital operations, content supply-chain, and brand governance teams.", "category": "Marketing operations AI", "differentiation": "Gradial spans brief, production, optimization, and insight workflows instead of limiting AI to copy generation or CMS publishing.", "why_now": "Marketing teams are under pressure to launch more personalized campaigns while keeping brand, legal, and channel governance intact."}, "risks": [{"claim": "The risk is that brand governance and approval complexity may limit how much campaign execution agents can own without human review.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$65M Series C for marketing agents', 'SaaS', 'Series C', '$65M', NULL, NULL, 'Seattle', 'US', 'marketing ops,ai agents,content supply chain,enterprise ai,campaigns', 'Insight Partners', '{"docs": "https://docs.gradial.com/", "careers": "https://job-boards.greenhouse.io/gradial"}', 1, 'gradial.webp', 'ready', 'published', 'manual', '2026-06-18 14:59:42', '2026-06-18 14:59:42') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gradient-labs', 'gradient-labs', 'gradient-labs.ai', 'https://gradient-labs.ai/', 'Gradient Labs', 'AI-native customer operations agents for financial services teams.', 'The sharp choice is to automate regulated customer operations before chasing general support. Gradient Labs shows finance-specific agents for collections, fraud, and outbound workflows, with the site foregrounding a live fraud-attempt demo and secure design. Unlike broad chatbot vendors, it sells the handoff-heavy work banks cannot casually outsource. The risk is whether accuracy and compliance reviews slow expansion across institutions.', '{"verified_at": "2026-06-04", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://gradient-labs.ai/", "type": "official"}, {"id": "funding_1", "label": "Gradient Labs Series A announcement", "url": "https://gradient-labs.ai/blog/weve-raised-26m-to-bring-autonomous-customer-operations-to-financial-services", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Gradient Labs as AI-native customer operations for financial-services teams.", "source_ids": ["official_site"]}, {"claim": "The homepage shows finance-specific agent workflows including fraud response, collections, outbound outreach, and handoff-heavy support work.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Banks, lenders, fintechs, and regulated financial-services operations leaders.", "category": "Fintech", "differentiation": "Gradient Labs narrows autonomous agents to finance-specific operations where fraud, collections, and regulated handoffs matter.", "why_now": "The June 2026 Series A expansion gives the company fresh capital as financial institutions test specialist agents beyond generic support bots."}, "risks": [{"claim": "The open question is whether accuracy, escalation, and compliance reviews slow cross-institution expansion.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Finance ops agents', 'Fintech', 'Series A', '$26M', NULL, NULL, NULL, 'Europe', 'financial services,customer operations,ai agents,fraud,collections', 'Octopus Ventures, CommerzVentures', NULL, 1, 'gradient-labs.webp', 'ready', 'published', 'manual', '2026-06-04 05:59:59', '2026-06-04 05:59:59') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-grai', 'grai', 'www.grai.fm', 'https://www.grai.fm', 'GRAI', 'Social AI music app for remixing songs with friends while keeping artist control in the loop.', 'Most AI music tools treat listeners like failed producers; the better consumer bet is participation without pretending everyone wants a DAW. GRAI is live as an iPhone app and raised a $9M seed round, letting people react to friends'' tracks and flip songs into new moods. Unlike Suno or Udio, it starts from existing music and artist opt-in rather than blank-page generation. The hard part is whether labels give enough catalog access for the social loop to matter.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.grai.fm", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/21/grai-believes-ai-can-make-music-more-social-not-replace-artists/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes GRAI: Social AI music app for remixing songs with friends while keeping artist control in the loop.", "source_ids": ["official_site"]}, {"claim": "GRAI is live as an iPhone app and raised a $9M seed round, letting people react to friends'' tracks and flip songs into new moods.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Creative teams and individual creators evaluating production workflows.", "category": "Creator Tools", "differentiation": "Social remix, not song gen", "why_now": "Recent source-backed funding and public product evidence make music, ai, remix worth tracking."}, "risks": [{"claim": "The hard part is whether labels give enough catalog access for the social loop to matter.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Social remix, not song gen', 'Creator Tools', 'Seed', '$9M', NULL, NULL, NULL, 'Europe', 'music,ai,remix,social apps,creator tools', 'Khosla Ventures, Inovo VC', '{"linkedin": "https://www.linkedin.com/company/grai-fm/"}', 1, 'grai.webp', 'ready', 'published', 'manual', '2026-04-22 08:26:09', '2026-04-22 08:26:09') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-granola', 'granola', 'www.granola.ai', 'https://www.granola.ai', 'Granola', 'AI meeting notes that turn transcripts into searchable team context.', 'Meeting notes only looked saturated until someone removed the bot and treated meetings as company memory instead. Granola''s local transcription, MCP server, and new personal plus enterprise APIs make it feel closer to context infrastructure than another transcript widget. Where most note-takers sell recall, this is betting that shared context matters more than summaries. The risk is that the product loses elegance as it stretches from a sharp Mac app into enterprise workflow plumbing.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.granola.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/03/25/granola-raises-125m-hits-1-5b-valuation-as-it-expands-from-meeting-notetaker-to-enterprise-ai-app/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Granola: AI meeting notes that turn transcripts into searchable team context.", "source_ids": ["official_site"]}, {"claim": "Meeting notes only looked saturated until someone removed the bot and treated meetings as company memory instead.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Bot-free meeting context layer", "why_now": "Recent source-backed funding and public product evidence make meeting notes, productivity, knowledge management worth tracking."}, "risks": [{"claim": "The risk is that the product loses elegance as it stretches from a sharp Mac app into enterprise workflow plumbing.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Bot-free meeting context layer', 'SaaS', 'Series C', '$125M', NULL, NULL, NULL, 'Europe', 'meeting notes,productivity,knowledge management,ai assistant', 'Index Ventures, Kleiner Perkins, Lightspeed Venture Partners, Spark Capital, NFDG', '{"twitter": "https://x.com/meetgranola", "linkedin": "https://www.linkedin.com/company/meetgranola", "careers": "https://www.granola.ai/jobs"}', 1, 'granola.webp', 'ready', 'published', 'manual', '2026-04-20 11:02:55', '2026-04-20 11:02:55') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gray-swan', 'gray-swan', 'www.grayswan.ai', 'https://www.grayswan.ai/', 'Gray Swan', 'AI security platform for agent red teaming, runtime defense, and adversarial evaluation.', 'The bet is that AI security needs an adversarial operating loop, not a static checklist. Gray Swan combines Cygnal runtime protection, Shade automated red teaming, and Arena''s 15,000-person attack network into one platform. Unlike compliance-first AI safety tools, its evidence comes from frontier-lab evaluations and real attack trajectories. The risk is whether enterprise teams can turn findings into production controls quickly.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.grayswan.ai/", "type": "official"}, {"id": "funding_1", "label": "Gray Swan", "url": "https://www.grayswan.ai/news/gray-swan-announces-series-a", "type": "funding"}], "product_evidence": [{"claim": "Gray Swan''s platform is described as Cygnal for real-time AI monitoring and protection, Shade for automated adversarial testing, and Arena for a global red-team community.", "source_ids": ["funding_1"]}, {"claim": "The funding post says Arena includes more than 15,000 researchers and over one million real-world attack trajectories used to train Cygnal and Shade.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Frontier labs and enterprise security teams evaluating and protecting AI models, agents, and applications.", "category": "AI / ML", "differentiation": "Security product telemetry fed by adversarial research, frontier-lab evaluations, and live red-team attacks.", "why_now": "The May 28, 2026 Series A gives Gray Swan funding to scale enterprise AI security as agents move into production."}, "risks": [{"claim": "The execution risk is whether enterprises can operationalize adversarial findings faster than AI applications expand.", "basis": "VentureDex editorial assessment based on official product and funding-source review."}]}', 5, 'Frontier-lab AI red teaming', 'AI / ML', 'Series A', '$40M', NULL, NULL, NULL, 'US', 'ai security,red teaming,runtime protection,model evaluation,agent security', 'Wing Venture Capital, Madrona', '{"careers": "https://www.grayswan.ai/careers"}', 1, 'gray-swan.webp', 'ready', 'published', 'manual', '2026-05-31 02:16:09', '2026-05-31 02:16:09') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gridcare', 'gridcare', 'www.gridcare.ai', 'https://www.gridcare.ai/', 'GridCARE', 'AI-native power activation platform for data-center grid capacity.', 'The interesting bet is that AI infrastructure is constrained by interconnection, not just GPUs. GridCARE turns grid utilization, congestion, outages, weather, and flexible-load dispatch into Power Finder, Activation, and Operations workflows. Unlike energy dashboards, it sells under-12-month time to power and 650 MW connection capacity evidence. The risk is whether utility partnerships scale city by city.', '{"verified_at": "2026-06-05", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.gridcare.ai/", "type": "official"}, {"id": "funding_1", "label": "GridCARE Series A announcement", "url": "https://www.businesswire.com/news/home/20260514546216/en/GridCARE-Raises-%2464-Million-Series-A-from-Leading-AI-and-Energy-Investors-to-Create-a-New-Category-Power-Acceleration-for-AI", "type": "funding"}], "product_evidence": [{"claim": "The official site presents Power Finder, Power Activation, and Power Operations as platform modules for data-center energy activation and delivery.", "source_ids": ["official_site"]}, {"claim": "GridCARE publishes evidence for under-12-month activated power, 650 MW of identified New York connection capacity, and hundreds of megawatts unlocked for AI infrastructure.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI data-center developers, utilities, and energy operators trying to connect large flexible loads faster.", "category": "Climate / Sustainability", "differentiation": "GridCARE applies AI and grid modeling to latent capacity and flexible interconnection rather than waiting for new transmission buildout.", "why_now": "The May 2026 Series A comes as power availability becomes a binding constraint for AI data centers and local grid planning."}, "risks": [{"claim": "The open question is whether utility-by-utility approvals and local grid constraints let the model scale beyond early marquee projects.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Grid capacity engine', 'Climate / Sustainability', 'Series A', '$64M', NULL, NULL, NULL, 'US', 'energy,ai infrastructure,data centers,grid,utilities', 'Sutter Hill Ventures', '{"careers": "https://jobs.ashbyhq.com/gridcare"}', 1, 'gridcare.webp', 'ready', 'published', 'manual', '2026-06-05 05:53:18', '2026-06-05 05:53:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-h3-zoom', 'h3-zoom', 'www.h3zoom.ai', 'https://www.h3zoom.ai/', 'H3 Zoom', 'AI inspection intelligence for buildings, infrastructure, and regulated assets.', 'The bet worth tracking is that inspection evidence should flow from drones and 360 cameras into audit-ready reports, not slide decks and site photos. H3 Zoom localizes defects, grades severity, attaches confidence, and exports remediation packages into BIM or CMMS workflows. That is more concrete than a generic computer-vision pitch because the buyer has compliance risk. The open question is whether robotics-enabled capture stays cheap enough across older buildings.', '{"verified_at": "2026-06-23", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.h3zoom.ai/", "type": "official"}, {"id": "official_company", "label": "Official company page", "url": "https://www.h3zoom.ai/company", "type": "official"}, {"id": "funding_1", "label": "PR Newswire Series A announcement", "url": "https://www.prnewswire.com/news-releases/h3-zoom-closes-oversubscribed-usd3-6-million-series-a-round-to-scale-ai-powered-inspection-intelligence-across-asia-302806186.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes software modules for facade inspection, interior inspection, custom AI integrations, and robotics-enabled capture that feed directly into the H3 Zoom platform.", "source_ids": ["official_site"]}, {"claim": "The site maps the workflow from sensor capture to automated diagnostics, severity-graded defects, confidence scores, audit-ready reports, remediation plans, and BIM or CMMS exports.", "source_ids": ["official_site"]}, {"claim": "The company page says H3 Zoom captures visual and sensor data from drones, 360 cameras, robotics, and existing workflows, then turns it into structured regulator-defensible reports.", "source_ids": ["official_company"]}], "market_context": {"primary_user": "Asset owners, facility managers, engineers, infrastructure operators, and regulators responsible for building condition reviews.", "category": "Built-environment inspection intelligence", "differentiation": "H3 Zoom links physical capture, AI diagnostics, defect localization, remediation planning, and defensible reporting in one inspection system.", "why_now": "Aging buildings, compliance pressure, drone capture, and computer-vision models make manual inspection workflows increasingly slow and expensive relative to auditable digital evidence."}, "risks": [{"claim": "The open question is whether robotics-enabled capture and site-specific inspection setup can scale economically across older, heterogeneous building portfolios.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$3.6M Series A, inspectable AI reports', 'SaaS', 'Series A', '$3.6M', NULL, NULL, 'Singapore', 'China / Asia', 'inspection,computer vision,built environment,asset management,compliance', 'JRE Ventures, SGInnovate, M7 Holdings, AC S525, Moringa Ventures, Lotus One Investment', NULL, 1, 'h3-zoom.webp', 'ready', 'published', 'manual', '2026-06-23 05:54:27', '2026-06-23 05:54:27') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-hellbender', 'hellbender', 'hellbender.com', 'https://hellbender.com/hellbender-products/', 'Hellbender', 'Edge AI camera systems and carrier boards for robotics and physical AI teams.', 'The useful bet is putting more physical AI on the camera instead of in a remote demo stack. Hellbender sells stereo AI cameras, 64-camera Vine systems, carrier boards, and CVaaS for teams that would rather test robots than wire processors. Unlike many defense-adjacent AI pitches, the product catalog is visible and shippable. Manufacturing discipline may matter more here than model cleverness.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://hellbender.com/hellbender-products/", "type": "official"}, {"id": "funding_1", "label": "Hellbender", "url": "https://hellbender.com/hellbender-secures-12-5m-seed-round-to-accelerate-domestic-manufacturing-of-physical-ai-and-launch-its-on-edge-camera-line/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Hellbender: Edge AI camera systems and carrier boards for robotics and physical AI teams.", "source_ids": ["official_site"]}, {"claim": "Hellbender sells stereo AI cameras, 64-camera Vine systems, carrier boards, and CVaaS for teams that would rather test robots than wire processors.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Stereo cameras for edge AI", "why_now": "Recent source-backed funding and public product evidence make edge ai, robotics, computer vision worth tracking."}, "risks": [{"claim": "Manufacturing discipline may matter more here than model cleverness.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Stereo cameras for edge AI', 'AI / ML', 'Seed', '$12.5M', NULL, NULL, NULL, 'US', 'edge ai,robotics,computer vision,hardware', 'Magarac Venture Partners, Veredas Partners', '{"careers": "https://hellbender.com/careers"}', 1, 'hellbender.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-hilbert', 'hilbert', 'hilberts.ai', 'https://hilberts.ai', 'Hilbert', 'AI growth infrastructure for B2C revenue decisions.', 'Growth analytics usually stops at dashboards; this is trying to become the decision layer after the chart. Hilbert shows anomaly detection, root-cause analysis, counterfactuals, pLTV targeting, and agent-driven growth tasks in one product surface. Unlike BI tools or in-house ML projects, the bet is that B2C teams want actions tied to cohorts and unit economics, not another report. The risk is proving those actions move revenue outside the demo data.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://hilberts.ai", "type": "official"}, {"id": "funding_1", "label": "Gunderson Dettmer", "url": "https://www.gunder.com/en/news-insights/client-news/hilbert-announces-28-million-usd-series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Hilbert: AI growth infrastructure for B2C revenue decisions.", "source_ids": ["official_site"]}, {"claim": "Hilbert shows anomaly detection, root-cause analysis, counterfactuals, pLTV targeting, and agent-driven growth tasks in one product surface.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$28M Series A for growth infra", "why_now": "Recent source-backed funding and public product evidence make growth analytics, b2c ai, decision intelligence worth tracking."}, "risks": [{"claim": "The risk is proving those actions move revenue outside the demo data.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$28M Series A for growth infra', 'AI / ML', 'Series A', '$28M', NULL, NULL, NULL, 'US', 'growth analytics,b2c ai,decision intelligence,marketing', 'Andreessen Horowitz', '{"careers": "https://jobs.ashbyhq.com/hilberts"}', 1, 'hilbert.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-isometric', 'isometric', 'isometric.com', 'https://isometric.com/', 'Isometric', 'AI certification platform for industrial, carbon, energy, and materials claims.', 'The interesting bet is that certification can become a software workflow without pretending auditors disappear. Certify agents read evidence, cross-check sensor, satellite, supply-chain, and lab data, then route judgment calls to experts. That is sharper than another ESG dashboard because the output is an issued, traceable certificate. The risk is whether industrial buyers accept faster AI-assisted reviews when liability still lands on human sign-off.', '{"verified_at": "2026-06-23", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://isometric.com/", "type": "official"}, {"id": "official_announcement", "label": "Isometric Series A announcement", "url": "https://isometric.com/writing-articles/isometric-raises-40m-to-bring-agentic-certification-to-the-industrial-economy", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Certify, Registry, and Protocols for carbon removal, industrial emissions, energy, fuel, materials, and data-center certification.", "source_ids": ["official_site"]}, {"claim": "The product page says Certify agents read evidence, cross-check millions of data points, surface judgment cases to experts, publish certificates with chain of custody, and connect through APIs and MCP.", "source_ids": ["official_site"]}, {"claim": "The Series A announcement says Isometric agents review sensor readings, satellite imagery, supply-chain records, and lab results to move certification work from months to hours.", "source_ids": ["official_announcement"]}], "market_context": {"primary_user": "Industrial project owners, sustainability teams, auditors, buyers, and regulators that need defensible certificates.", "category": "Industrial certification", "differentiation": "Isometric turns evidence review into an AI-assisted certification workflow with human expert judgment and public certificate traceability.", "why_now": "Industrial decarbonization, data-center energy demand, and new materials claims are increasing the volume of evidence that must be certified before buyers or regulators trust it."}, "risks": [{"claim": "The open question is whether buyers and regulators trust faster AI-assisted certification when legal and commercial liability still depends on expert sign-off.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$40M Series A, agentic certificates', 'Climate / Sustainability', 'Series A', '$40M', 2022, NULL, 'London', 'Europe', 'certification,industrial ai,climate,compliance,registry', 'AVP, Plural, Lowercarbon Capital, John Doerr, Walter Kortschak', '{"careers": "https://isometric.com/careers"}', 1, 'isometric.webp', 'ready', 'published', 'manual', '2026-06-23 05:54:27', '2026-06-23 05:54:27') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-jedify', 'jedify', 'jedify.com', 'https://jedify.com/', 'Jedify', 'Context graph platform for enterprise AI agents.', 'The useful bet is that enterprise agents need a shared context graph rather than another metadata catalog. Jedify shows Semantic Fusion, data-source connections, contextual MCP, conversational analytics, Smart Scenarios, and security controls like SOC 2 Type II. Unlike dashboard tools, it tries to make business terms executable by agents. The risk is proving graph quality across messy enterprise data.', '{"verified_at": "2026-06-11", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://jedify.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://jedify.com/careers/", "type": "official"}, {"id": "funding_1", "label": "Jedify Series A announcement", "url": "https://jedify.com/heres-why-context-graphs-are-the-next-must-have-for-enterprise-ai/", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Jedify as a data platform for contextual AI agents with a business context layer.", "source_ids": ["official_site"]}, {"claim": "Jedify describes Semantic Fusion that learns from structured, semi-structured, and unstructured sources while connecting data sources.", "source_ids": ["official_site"]}, {"claim": "The product surface shows Ask Jedify conversational analytics, a contextual MCP server, Smart Scenarios workflows, and an insights library.", "source_ids": ["official_site"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Enterprise data, analytics, and AI teams that need agents to understand business terms, KPIs, and internal context.", "category": "AI / ML", "differentiation": "Jedify builds a context graph and MCP surface for agents rather than stopping at catalog metadata or dashboard answers.", "why_now": "Agentic applications need trusted business context before they can act on enterprise data without constant human translation."}, "risks": [{"claim": "The open question is whether Jedify can keep its context graph accurate as enterprise data models, KPIs, and permissions change.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Context graph for agents', 'AI / ML', 'Series A', '$24M', NULL, NULL, NULL, 'US', 'context graph,ai agents,data platform,analytics,enterprise ai', 'Norwest', '{"careers": "https://jedify.com/careers/"}', 1, 'jedify.webp', 'ready', 'published', 'manual', '2026-06-11 06:04:13', '2026-06-11 06:04:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-juliahub', 'juliahub', 'juliahub.com', 'https://juliahub.com', 'JuliaHub', 'Agentic simulation and digital-twin tooling for hardware engineering teams.', 'Someone finally treated engineering simulation like a software workflow, not a CAD afterthought. Dyad 3.0 turns Julia models, SciML, case studies, and cloud runs into an AI-native workspace for physical systems, with public proof from ASML, Boeing, NASA, and Williams Racing. The bet is that hardware teams want agents constrained by equations rather than chatbots guessing at parts. The risk is whether that craft reaches engineers outside the Julia faithful.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://juliahub.com", "type": "official"}, {"id": "funding_1", "label": "JuliaHub", "url": "https://juliahub.com/blog/juliahub-raises-65m-series-b-launches-dyad-3.0", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes JuliaHub: Agentic simulation and digital-twin tooling for hardware engineering teams.", "source_ids": ["official_site"]}, {"claim": "Someone finally treated engineering simulation like a software workflow, not a CAD afterthought.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$65M Series B for Dyad 3.0", "why_now": "Recent source-backed funding and public product evidence make scientific ai, simulation, digital twins worth tracking."}, "risks": [{"claim": "The risk is whether that craft reaches engineers outside the Julia faithful.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$65M Series B for Dyad 3.0', 'AI / ML', 'Series B', '$65M', NULL, NULL, NULL, 'US', 'scientific ai,simulation,digital twins,hardware engineering', 'Dorilton Ventures', '{"careers": "https://juliahub.com/company/jobs"}', 1, 'juliahub.webp', 'ready', 'published', 'manual', '2026-05-04 06:18:58', '2026-05-04 06:18:58') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-justai', 'justai', 'www.getjust.ai', 'https://www.getjust.ai/', 'JustAI', 'AI lifecycle marketing platform for personalization and experimentation.', 'The best part is that lifecycle marketing is treated as a decision system, not a copy generator. JustAI splits the job across strategy, creative, decisioning, and data agents that find cohorts, generate variants, route traffic, and feed learnings back into campaigns. Compared with manual AB testing, the bet is continuous personalization with guardrails. The risk is whether brands keep enough human judgment in the loop when the system optimizes every send.', '{"verified_at": "2026-06-24", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.getjust.ai/", "type": "official"}, {"id": "official_blog", "label": "JustAI Series A blog post", "url": "https://www.getjust.ai/blog/justai-seriesa", "type": "official"}, {"id": "funding_1", "label": "PR Newswire Series A announcement", "url": "https://www.prnewswire.com/news-releases/justai-raises-17m-series-a-to-build-an-agentic-marketing-platform-302807090.html", "type": "funding"}], "product_evidence": [{"claim": "The official site presents always-on AI agents for one-to-one lifecycle marketing personalization at scale.", "source_ids": ["official_site"]}, {"claim": "The homepage names strategy, data, creative, and decisioning agents that identify segments, create personalized content, and route campaign decisions.", "source_ids": ["official_site"]}, {"claim": "The Series A announcement describes an agentic marketing platform with coordinated strategy, creative, decisioning, and data agents.", "source_ids": ["funding_1", "official_blog"]}], "market_context": {"primary_user": "Lifecycle marketing, growth, and CRM teams running high-volume messaging programs.", "category": "Marketing automation", "differentiation": "JustAI treats personalization as a decisioning loop across cohorts, content variants, and campaign routing rather than a copy assistant.", "why_now": "Marketing teams are being asked to personalize more customer journeys while privacy limits and channel fatigue make manual testing slower and less precise."}, "risks": [{"claim": "The open question is whether brands can keep enough governance over a system that optimizes audience, content, and send decisions together.", "basis": "VentureDex editorial assessment based on official product evidence and the funding announcement."}]}', 4, '$17M Series A for lifecycle AI', 'SaaS', 'Series A', '$17M', NULL, NULL, NULL, 'US', 'marketing automation,lifecycle marketing,personalization,ai agents,experimentation', 'Base10 Partners', '{"careers": "https://www.getjust.ai/careers"}', 1, 'justai.webp', 'ready', 'published', 'manual', '2026-06-24 06:00:32', '2026-06-24 06:00:32') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-kin-health', 'kin-health', 'www.meetkin.com', 'https://www.meetkin.com', 'Kin Health', 'Patient app that records doctor visits and turns them into clear next steps.', 'The bet is that the missing layer in care is memory, not another portal. Kin records doctor visits, extracts next steps, and lets a patient share the summary with family before the next appointment. Unlike clinician scribes, it starts with the person who forgets 80% of instructions by the parking lot. Free patient distribution is elegant; consent norms in exam rooms are the hard part.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.meetkin.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/18/kin-health-raises-9m-to-build-an-ai-notetaker-for-patients/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Kin Health: Patient app that records doctor visits and turns them into clear next steps.", "source_ids": ["official_site"]}, {"claim": "VentureDex product review notes that unlike clinician scribes, it starts with the person who forgets 80% of instructions by the parking lot.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "Patient-owned visit memory", "why_now": "Recent source-backed funding and public product evidence make healthtech, patient notes, care coordination worth tracking."}, "risks": [{"claim": "Free patient distribution is elegant; consent norms in exam rooms are the hard part.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Patient-owned visit memory', 'HealthTech', 'Seed', '$9M', NULL, NULL, NULL, 'US', 'healthtech,patient notes,care coordination,ai scribe', 'Maveron', '{"careers": "https://www.meetkin.com/careers"}', 1, 'kin-health.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-kodesage', 'kodesage', 'kodesage.ai', 'https://kodesage.ai/', 'Kodesage', 'AI legacy-modernization platform for secure enterprise codebases.', 'The bet is that legacy modernization starts with codebase understanding, not another rewrite plan. Kodesage shows repository ingestion, source-code search, documentation, ticket analysis, diagrams, and on-prem Docker deployment for regulated teams. Unlike generic coding assistants, it is built around Oracle Forms, PL/SQL, COBOL, PowerBuilder, and RPG estates where old context is the product. The risk is whether its suggestions stay trustworthy on undocumented systems with weak tests.', '{"verified_at": "2026-06-08", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://kodesage.ai/", "type": "official"}, {"id": "docs_intro", "label": "Kodesage documentation introduction", "url": "https://docs.kodesage.ai/welcome-to-kodesage/introduction", "type": "official"}, {"id": "docs_ask", "label": "Ask Kodesage feature documentation", "url": "https://docs.kodesage.ai/key-features/ask-kodesage", "type": "product"}, {"id": "docs_git", "label": "Git integration documentation", "url": "https://docs.kodesage.ai/integrations/git", "type": "product"}, {"id": "docs_engine", "label": "Kodesage engine architecture documentation", "url": "https://docs.kodesage.ai/welcome-to-kodesage/the-kodesage-engine", "type": "product"}, {"id": "funding_1", "label": "Kodesage seed funding article", "url": "https://siliconangle.com/2026/06/04/startup-kodesage-secures-seed-funding-accelerate-premises-app-modernization-ai/", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Kodesage around codebase understanding, automatic documentation updates, natural-language answers, dependency diagrams, and ticket suggestions for legacy systems.", "source_ids": ["official_site"]}, {"claim": "The documentation says Kodesage integrates code repositories, issue trackers, wikis, and documentation into a context-aware knowledge base for legacy software teams.", "source_ids": ["docs_intro"]}, {"claim": "The Git integration docs show codebase upload via ZIP, SSH Git repository, or HTTPS Git repository before Kodesage processes repository content for analysis and documentation generation.", "source_ids": ["docs_git"]}, {"claim": "Ask Kodesage lets users query a legacy system with natural-language questions, limit searches by resource type, generate diagrams, and customize prompt templates.", "source_ids": ["docs_ask"]}, {"claim": "The architecture docs describe on-premises Docker deployment, ingestion services, a searchable vector database, a knowledge graph, and issue-ticketing integration.", "source_ids": ["docs_engine"]}], "market_context": {"primary_user": "Engineering leaders and modernization teams responsible for old enterprise applications in regulated environments.", "category": "DevTools", "differentiation": "Kodesage starts from repository ingestion, knowledge graphs, documentation, and ticket workflows instead of treating modernization as a generic code-generation prompt.", "why_now": "Enterprises are trying to reduce legacy migration risk while AI coding tools move from greenfield generation into maintenance-heavy software estates."}, "risks": [{"claim": "The open question is whether Kodesage suggestions remain reliable on undocumented legacy systems where tests and institutional knowledge are weakest.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}, {"claim": "bb-browser verification surfaced a React hydration mismatch on the official homepage while the product content still rendered.", "basis": "Browser-side verification on 2026-06-08; treated as external site polish risk, not a VentureDex publish blocker."}]}', 4, 'Legacy modernization engine', 'DevTools', 'Seed', '$6.6M', NULL, NULL, NULL, 'Europe', 'devtools,legacy modernization,code analysis,enterprise software,ai', 'VentureFriends', '{"docs": "https://docs.kodesage.ai/", "twitter": "https://x.com/KodeSage", "linkedin": "https://www.linkedin.com/company/kodesage/", "careers": "https://kodesage.ai/careers"}', 1, 'kodesage.webp', 'ready', 'published', 'manual', '2026-06-08 05:57:12', '2026-06-08 05:57:12') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-kosmos', 'kosmos', 'kosmoslabs.ai', 'https://kosmoslabs.ai/', 'Kosmos', 'Operational intelligence layer for enterprise IT incidents.', 'The useful bet is that IT incidents fail from missing context, not missing alerts. Kosmos correlates Jira, Salesforce, GitHub, and other work systems into structured risk events, escalation maps, and RCA workflows. Unlike observability dashboards, it starts from business-impact clues and ownership paths. The risk is whether customers expose enough cross-system data for the model to beat established incident platforms.', '{"verified_at": "2026-06-10", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://kosmoslabs.ai/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://kosmoslabs.ai/company/careers/", "type": "official"}, {"id": "funding_1", "label": "Kosmos seed funding announcement", "url": "https://www.prnewswire.com/news-releases/kosmos-raises-5-million-seed-round-led-by-norwest-to-bring-operational-intelligence-to-enterprise-it-302788014.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Kosmos as an operational-intelligence platform that turns fragmented enterprise IT signals into action.", "source_ids": ["official_site"]}, {"claim": "The product surface shows correlation across Jira, Salesforce, GitHub, support tickets, ownership metadata, risk events, and escalation maps.", "source_ids": ["official_site"]}, {"claim": "Kosmos presents RCA workflows, demo requests, and a 14-day trial path for enterprise IT teams reviewing incidents and operational risk.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Kosmos raised a $5M seed round led by Norwest to bring operational intelligence to enterprise IT.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise IT, SRE, operations, and support leaders who need to connect incidents to owners, customers, and business impact.", "category": "SaaS", "differentiation": "Kosmos emphasizes a cross-system operational graph and RCA workflow rather than alert streams alone.", "why_now": "Enterprise systems create more ticket, repo, CRM, and observability data than incident teams can manually connect during escalations."}, "risks": [{"claim": "The open question is whether Kosmos can access and normalize enough enterprise systems without becoming a long integration project.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Incident context graph', 'SaaS', 'Seed', '$5M', NULL, NULL, NULL, 'US', 'enterprise it,incident response,operational intelligence,ai agents,workflow automation', 'Norwest', '{"careers": "https://kosmoslabs.ai/company/careers/"}', 1, 'kosmos.webp', 'ready', 'published', 'manual', '2026-06-10 05:57:38', '2026-06-10 05:57:38') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-krea', 'krea', 'www.krea.ai', 'https://www.krea.ai', 'Krea', 'AI creative suite for generating, editing, and controlling images, video, and 3D assets.', 'Creative AI gets interesting when it treats models as material instead of magic boxes. Krea puts Krea 1, video, enhancer, realtime, editing, LoRA training, and style transfer into one workspace; the app exposes prompt, model, ratio, and resolution controls before it asks for a sales call. Unlike prompt-only wrappers, the bet is that visual creators want handles they can keep adjusting. The risk is that bundling every medium can blur the point if the controls stop feeling precise.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.krea.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2025/04/07/kreas-founders-snubbed-postgrad-grants-from-the-king-of-spain-to-build-their-ai-startup-now-its-valued-at-500m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Krea: AI creative suite for generating, editing, and controlling images, video, and 3D assets.", "source_ids": ["official_site"]}, {"claim": "Krea puts Krea 1, video, enhancer, realtime, editing, LoRA training, and style transfer into one workspace; the app exposes prompt, model, ratio, and resolution controls before it asks for a sales call.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Creative teams and individual creators evaluating production workflows.", "category": "Creator Tools", "differentiation": "Krea 1 plus visual control handles", "why_now": "Recent source-backed funding and public product evidence make ai creative tools, image generation, video generation worth tracking."}, "risks": [{"claim": "The risk is that bundling every medium can blur the point if the controls stop feeling precise.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Krea 1 plus visual control handles', 'Creator Tools', 'Series B', '$47M', NULL, NULL, NULL, 'US', 'ai creative tools,image generation,video generation,design tools', 'Bain Capital Ventures, Andreessen Horowitz, Abstract Ventures', '{"github": "https://github.com/krea-ai", "twitter": "https://x.com/krea_ai", "linkedin": "https://www.linkedin.com/company/krea-ai", "careers": "https://www.krea.ai/careers"}', 1, 'krea.webp', 'ready', 'published', 'manual', '2026-04-24 16:17:19', '2026-04-24 16:17:19') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-kyber', 'kyber', 'kyber.tech', 'https://kyber.tech/', 'Kyber', 'Low-latency SDK for real-time control of robots, drones, and remote machines.', 'Remote machine control breaks when video, inputs, audio, and telemetry drift apart. Kyber says its SDK synchronizes those streams over QUIC and HTTP/3, with end-to-end encryption and latency low enough for robots, drones, vehicles, XR, and remote desktops. Unlike one-off teleoperation stacks, it is open-source infrastructure for builders. The risk is whether 8 ms-style demos survive real networks and safety-critical deployments.', '{"verified_at": "2026-06-20", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://kyber.tech/", "type": "official"}, {"id": "about_page", "label": "Official about and careers page", "url": "https://kyber.tech/about#careers", "type": "official"}, {"id": "funding_1", "label": "TechCrunch seed funding report", "url": "https://techcrunch.com/2026/06/19/he-made-your-free-video-player-run-smoothly-now-hes-doing-that-for-robots/", "type": "funding"}], "product_evidence": [{"claim": "The official site describes real-time infrastructure for machine control across robots, drones, vehicles, remote desktops, and immersive applications.", "source_ids": ["official_site"]}, {"claim": "The product page says Kyber synchronizes video, audio, control inputs, and telemetry to one clock over QUIC and HTTP/3 with end-to-end encryption.", "source_ids": ["official_site"]}, {"claim": "The about page says the team is building infrastructure for robots, drones, and autonomous systems, and lists open roles for systems and deployed engineers.", "source_ids": ["about_page"]}], "market_context": {"primary_user": "Robotics, drone, autonomous systems, remote desktop, XR, and machine-control engineering teams.", "category": "Real-time machine-control infrastructure", "differentiation": "Kyber packages synchronized media, controls, and telemetry into an open-source SDK rather than a bespoke teleoperation build for one device class.", "why_now": "Robotics and physical AI teams need remote operation loops that are lower latency and easier to integrate than custom streaming stacks."}, "risks": [{"claim": "The open question is whether low-latency control claims can hold across unpredictable field networks and safety-critical machine environments.", "basis": "VentureDex editorial assessment based on official technical claims and funding-source review."}]}', 4, 'Real-time robot control', 'DevTools', 'Seed', '$5M', NULL, NULL, NULL, 'Europe', 'robotics,developer tools,real-time,streaming,open source', 'Lightspeed Venture Partners', '{"careers": "https://kyber.tech/about#careers"}', 1, 'kyber.webp', 'ready', 'published', 'manual', '2026-06-20 06:02:12', '2026-06-20 06:02:12') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lakefusion', 'lakefusion', 'www.lakefusion.ai', 'https://www.lakefusion.ai', 'LakeFusion', 'Databricks-native master data management for golden records.', 'The interesting move is refusing to be another MDM system outside the warehouse. LakeFusion installs through AWS or Azure Marketplace, runs inside Databricks, and uses LLM plus vector matching to create governed golden records under Unity Catalog. Unlike legacy match-rule projects, the bet is zero data egress, real-time sync back to source systems, and weeks-to-value. The risk is Databricks-native being a moat only if buyers already live there.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.lakefusion.ai", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/04/3286394/0/en/LakeFusion-Raises-7-5M-Seed-Financing-to-Redefine-Master-Data-Management-MDM-Natively-on-Databricks.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes LakeFusion: Databricks-native master data management for golden records.", "source_ids": ["official_site"]}, {"claim": "LakeFusion installs through AWS or Azure Marketplace, runs inside Databricks, and uses LLM plus vector matching to create governed golden records under Unity Catalog.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "$7.5M Seed for Databricks MDM", "why_now": "Recent source-backed funding and public product evidence make data management, databricks, mdm worth tracking."}, "risks": [{"claim": "The risk is Databricks-native being a moat only if buyers already live there.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$7.5M Seed for Databricks MDM', 'SaaS', 'Seed', '$7.5M', NULL, NULL, NULL, 'US', 'data management,databricks,mdm,ai', 'Silverton Partners', '{"linkedin": "https://www.linkedin.com/company/lakefusion-ai/", "careers": "https://www.lakefusion.ai/careers"}', 1, 'lakefusion.webp', 'ready', 'published', 'manual', '2026-05-05 06:40:13', '2026-05-05 06:40:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lassie', 'lassie', 'www.lassie.ai', 'https://www.lassie.ai/', 'Lassie', 'AI agents that run medical-practice admin across payments, portals, and records.', 'Medical-practice admin matters only if it leaves the queue, not if it opens another dashboard. Lassie says its agent reconciles insurance payments across portals, records, and bank deposits for 700+ practices, while the site shows enrollment, payment setup, posting, and patient-balance workflows. Unlike a dentist-office RPA consultancy, the customer story claims 100+ hours saved per month. The risk is whether the agent generalizes beyond early reimbursement work.', '{"verified_at": "2026-06-07", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.lassie.ai/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://jobs.ashbyhq.com/lassie", "type": "official"}, {"id": "funding_1", "label": "Lassie Series A announcement", "url": "https://www.businesswire.com/news/home/20260603909717/en/Lassie-Raises-%2435M-Led-by-Andreessen-Horowitz-to-Build-AI-for-Small-Businesses-to-Run-Themselves", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Lassie as AI that runs the doctor''s office and describes autonomous enrollment, electronic-payment setup, payment posting, and patient-balance workflows.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Lassie reconciles insurance portals, records, and bank deposits for 700+ practices across 49 states.", "source_ids": ["funding_1"]}, {"claim": "The official site exposes an app login plus an Ashby careers entrance, showing production and hiring surfaces beyond a static waitlist.", "source_ids": ["official_site", "careers_page"]}], "market_context": {"primary_user": "Doctor, dental, and small medical-practice owners trying to reduce reimbursement, payment-posting, and insurance-portal admin work.", "category": "AI / ML", "differentiation": "Lassie focuses on end-to-end administrative labor in medical practices rather than a narrow claims dashboard or scheduling assistant.", "why_now": "The June 2026 Series A follows public claims of 700+ practices and 250,000 annual labor hours handled by autonomous systems."}, "risks": [{"claim": "The open question is whether the agent keeps accuracy and trust as it moves beyond early reimbursement and payment-posting workflows.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '700-practice admin agent', 'AI / ML', 'Series A', '$35M', NULL, NULL, NULL, 'US', 'ai agents,healthcare,practice management,payments,automation', 'Andreessen Horowitz', '{"careers": "https://jobs.ashbyhq.com/lassie"}', 1, 'lassie.webp', 'ready', 'published', 'manual', '2026-06-07 06:05:50', '2026-06-07 06:05:50') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-layup-parts', 'layup-parts', 'fiber.layupparts.com', 'https://fiber.layupparts.com/login', 'Layup Parts', 'Digital quote-to-production workflow for custom composite parts.', 'Composite parts still move like bespoke procurement even when the CAD file is ready. The surviving official surface is FiberPortal, a customer login for the quote-to-production flow, while TechCrunch''s June 2 Series A report frames the company around an Amazon-like marketplace for composite parts. Unlike a generic machine-shop marketplace, it narrows the promise to carbon-fiber and fiberglass parts. The risk is thinner public product evidence while the marketing site is disabled.', '{"verified_at": "2026-06-07", "sources": [{"id": "fiberportal_login", "label": "Official FiberPortal customer login", "url": "https://fiber.layupparts.com/login", "type": "official"}, {"id": "funding_1", "label": "Layup Parts Series A article", "url": "https://techcrunch.com/2026/06/02/ex-anduril-engineer-raises-42m-to-build-the-amazon-of-composite-parts/", "type": "funding"}], "product_evidence": [{"claim": "The official FiberPortal login exposes a production customer app surface separate from a static marketing page.", "source_ids": ["fiberportal_login"]}, {"claim": "The funding article frames Layup Parts around a marketplace for custom composite parts rather than a generic machine-shop directory.", "source_ids": ["funding_1"]}, {"claim": "The TechCrunch source ties the company to quote-to-production demand for carbon-fiber and fiberglass components.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Aerospace, defense, motorsports, and advanced-manufacturing engineers ordering custom carbon-fiber or fiberglass parts.", "category": "Marketplace", "differentiation": "Layup Parts joins quoting software, material inventory, and in-house composite manufacturing instead of acting as a generic supplier directory.", "why_now": "Defense and advanced-manufacturing demand is pushing buyers to shorten custom-part procurement cycles while preserving traceability and quality."}, "risks": [{"claim": "The open question is whether the software-led quoting flow can scale without factory capacity becoming the bottleneck.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Composite quoting portal', 'Marketplace', 'Series A', '$42M', NULL, NULL, NULL, 'US', 'manufacturing,composites,marketplace,aerospace,defense', 'Marlinspike', NULL, 1, 'layup-parts.webp', 'ready', 'published', 'manual', '2026-06-07 06:05:50', '2026-06-07 06:05:50') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-leaf', 'leaf', 'withleaf.io', 'https://withleaf.io/', 'Leaf', 'Farm-data infrastructure that cleans and structures agribusiness data.', 'The sharp part is treating farm data like payments data: invisible infrastructure with clear downstream value. Leaf connects OEMs, imagery, weather, soil labs, and farm management systems, then standardizes field data for dashboards, reports, AI, insurance, and product models; its funding source says it processes 20% of global crop acres annually. Unlike generic agtech dashboards, it is the plumbing other agribusiness tools build on. The risk is provider integrations and data rights.', '{"verified_at": "2026-06-12", "sources": [{"id": "official_site", "label": "Official company site", "url": "https://withleaf.io/", "type": "official"}, {"id": "connect_page", "label": "Official Leaf Connect page", "url": "https://withleaf.io/platforms/connect", "type": "product"}, {"id": "funding_1", "label": "Leaf Series B announcement", "url": "https://www.prnewswire.com/news-releases/leaf-raises-13m-series-b-to-bring-ai-to-agribusiness-302795837.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Leaf as a data and intelligence platform for agribusiness marketing, product, R&D, and commercial teams.", "source_ids": ["official_site"]}, {"claim": "Leaf says it connects OEMs, imagery, weather, soil labs, and farm management systems, then standardizes and spatially allocates farm data.", "source_ids": ["connect_page"]}, {"claim": "The funding announcement says Leaf processes farm data covering 20% of global crop acres annually.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Agribusiness teams building marketing, insurance, product, and AI workflows on top of farm-level data.", "category": "SaaS", "differentiation": "Leaf focuses on the normalization and integration layer that other agribusiness applications need before analysis.", "why_now": "Agribusiness AI requires clean, permissioned, cross-provider field data instead of scattered OEM, weather, imagery, and lab feeds."}, "risks": [{"claim": "The open question is whether Leaf can keep data rights, provider integrations, and agribusiness buyer needs aligned at global scale.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Farm-data infrastructure', 'SaaS', 'Series B', '$13M', NULL, NULL, NULL, 'US', 'agtech,data infrastructure,api,ai,agriculture', 'Leaps by Bayer', '{"docs": "https://docs.withleaf.io/", "product": "https://withleaf.io/platforms/connect"}', 1, 'leaf.webp', 'ready', 'published', 'manual', '2026-06-12 06:00:05', '2026-06-12 06:00:05') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lexful', 'lexful', 'lexful.ai', 'https://lexful.ai/', 'Lexful', 'AI-native IT documentation and knowledge infrastructure for MSPs.', 'The sharp bet is that MSP documentation should answer tickets, not sit in a wiki. Lexful shows Ask Lex, structured asset records, PSA and RMM syncing, IT Glue or Hudu imports, an MCP endpoint, and SOC 2 Type 2 compliance. Unlike legacy folders with AI bolted on, it treats credentials, playbooks, diagrams, and client notes as agent-readable context. The risk is whether July general availability delivers the integrations promised in the funding note.', '{"verified_at": "2026-06-09", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://lexful.ai/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://lexful.ai/careers", "type": "official"}, {"id": "funding_1", "label": "Lexful seed funding announcement", "url": "https://www.globenewswire.com/news-release/2026/06/08/3308189/0/en/lexful-closes-7m-seed-round-for-next-generation-documentation-for-msps.html", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Lexful as MSP documentation that turns tribal knowledge into machine intelligence for technicians, agents, and operations teams.", "source_ids": ["official_site"]}, {"claim": "The product surface shows Ask Lex, structured assets and credentials, relationship maps, and AI-generated runbooks built from MSP documentation.", "source_ids": ["official_site"]}, {"claim": "Lexful says it syncs with PSA and RMM systems, imports from IT Glue or Hudu, and exposes a native MCP endpoint for tools such as Copilot, Claude, and RMM agents.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Lexful is SOC 2 Type 2 compliant, is available through Pax8 and Sherweb marketplaces, and is building integrations with Autotask, ConnectWise, NinjaOne, and HaloPSA.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "MSP owners, service desk leaders, and senior technicians responsible for client documentation and support workflows.", "category": "SaaS", "differentiation": "Lexful treats documentation as an agent-readable operational knowledge layer instead of a static wiki or folder system.", "why_now": "MSPs are adopting AI agents, but legacy documentation tools often lack the structured, fresh, permission-aware context those agents need."}, "risks": [{"claim": "The open question is whether July general availability delivers the promised MSP integrations while preserving permission boundaries across credentials and client records.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'MCP-native MSP docs', 'SaaS', 'Seed', '$7M', NULL, NULL, NULL, 'US', 'msp,it documentation,knowledge management,ai agents,mcp', 'Top Down Ventures, York IE', '{"careers": "https://lexful.ai/careers"}', 1, 'lexful.webp', 'ready', 'published', 'manual', '2026-06-09 05:48:20', '2026-06-09 05:48:20') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lexroom', 'lexroom', 'lexroom.ai', 'https://lexroom.ai/', 'Lexroom', 'Legal AI workspace for source-backed research, drafting, and private firm libraries.', 'Legal AI gets more credible when the source trail is the interface, not a footnote. Lexroom shows official-source research, document comparison, clause drafting, private libraries, original judgments, pricing, and more than 10,000 professional users. Unlike broad legal copilots that ask lawyers to trust a black box, it sells verifiability as the workflow.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://lexroom.ai/", "type": "official"}, {"id": "funding_1", "label": "Tech Funding News", "url": "https://techfundingnews.com/harvey-rival-lexroom-raises-50m-to-power-ai-for-europes-one-million-lawyers/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Lexroom: Legal AI workspace for source-backed research, drafting, and private firm libraries.", "source_ids": ["official_site"]}, {"claim": "Lexroom shows official-source research, document comparison, clause drafting, private libraries, original judgments, pricing, and more than 10,000 professional users.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Source-backed legal AI", "why_now": "Recent source-backed funding and public product evidence make legal ai, document drafting, research worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Source-backed legal AI', 'SaaS', 'Series B', '$50M', NULL, NULL, NULL, 'Europe', 'legal ai,document drafting,research,compliance,workflow', 'Left Lane Capital', '{"careers": "https://lexroom.ai/careers"}', 1, 'lexroom.webp', 'ready', 'published', 'manual', '2026-05-26 09:43:21', '2026-05-26 09:43:21') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lightbringer', 'lightbringer', 'www.lightbringer.com', 'https://www.lightbringer.com/', 'Lightbringer', 'AI-native patent management platform for invention intake, filing, prosecution, and strategy.', 'Patent work has always punished founders for moving fast. Lightbringer wraps idea capture, drafting, filing, office actions, competitor monitoring, and fixed-price attorney review into one product instead of another lawyer dashboard. Compared with legal AI tools built for firms, it is trying to replace the firm workflow for startups. The risk is whether quality holds when deep-tech patents get messy.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.lightbringer.com/", "type": "official"}, {"id": "official_pricing", "label": "Official pricing page", "url": "https://www.lightbringer.com/pricing/pricing", "type": "official"}, {"id": "funding_1", "label": "Lightbringer funding announcement", "url": "https://www.lightbringer.com/news-items/lightbringer-raises-10m-to-take-on-patent-attorneys-in-the-u-s-with-the-worlds-first-ai-native-patent-firm", "type": "funding"}], "product_evidence": [{"claim": "The official homepage describes a patent journey from ideation through drafting, filing, prosecution, international filing, portfolio management, and competitor monitoring.", "source_ids": ["official_site"]}, {"claim": "Lightbringer says its product combines agentic AI, expert patent attorneys, fixed pricing, a single dashboard, automated tracking, AI-guided office-action response, and SOC 2 Type 2 controls.", "source_ids": ["official_site", "official_pricing"]}, {"claim": "The official funding announcement says Lightbringer has helped more than 200 deep-tech companies across 17 countries file and manage patents globally.", "source_ids": ["funding_1"]}, {"claim": "The funding announcement says the $10M Series A was co-led by 6 Degrees Capital and Newion to support U.S. expansion and further development of the AI-powered patent platform.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Deep-tech founders, startup operators, and technical teams trying to protect inventions without running a traditional law-firm process.", "category": "LegalTech", "differentiation": "Lightbringer packages patent strategy, filing, prosecution, portfolio management, and attorney review into a productized workflow with fixed pricing rather than a billable-hours law-firm loop.", "why_now": "AI software is moving from lawyer-assist tooling into service-as-software workflows where startups expect fixed-price, faster legal operations."}, "risks": [{"claim": "The hard question is whether an AI-native patent provider can maintain attorney-grade quality across specialized deep-tech inventions as it expands into the U.S.", "basis": "VentureDex editorial assessment based on official product pages and the Series A announcement."}]}', 4, '$10M Series A for patent workflows', 'SaaS', 'Series A', '$10M', 2023, NULL, 'Malmo', 'Europe', 'legaltech,patents,ai agents,deep tech,portfolio management', '6 Degrees Capital, Newion, Luminar Ventures, Alliance VC', '{"careers": "https://www.lightbringer.com/about/career"}', 0, 'lightbringer.webp', 'ready', 'published', 'manual', '2026-06-17 05:54:00', '2026-06-17 05:54:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lighttable', 'lighttable', 'www.lighttable.ai', 'https://www.lighttable.ai/', 'LightTable', 'AI quality-control review for construction drawings, specs, and checklists.', 'The useful bet is that pre-construction review should behave more like QA than consultant folklore. LightTable lets teams upload drawings, specs, and checklists, then flags coordination issues across 35+ scopes with expert validation and a 4-hour first-findings target. Unlike legacy peer review, it ties issue history, comments, and handoff into the workflow. The risk is whether AI review stays trusted when projects move beyond early developer customers.', '{"verified_at": "2026-06-01", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.lighttable.ai/", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/27/3297492/0/en/LightTable-Secures-22-Million-Series-A-Funding-Round-Led-by-Innovation-Endeavors.html", "type": "funding"}], "product_evidence": [{"claim": "The official site says teams upload drawings, specs, and checklists so LightTable can surface coordination and constructability issues before construction starts.", "source_ids": ["official_site"]}, {"claim": "LightTable reports 20M square feet reviewed, more than $10B in project costs reviewed, and an average 4-hour time to first findings.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers, contractors, and preconstruction teams reviewing project documents before construction starts.", "category": "SaaS", "differentiation": "AI construction QA with expert validation and workflow tracking rather than one-off consultant review.", "why_now": "The May 2026 Series A led by Innovation Endeavors funds product expansion as construction teams push document review earlier."}, "risks": [{"claim": "The open question is whether expert-validated AI review maintains trust across varied project types, codes, and contractor workflows.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '20M sq ft reviewed by AI QA', 'SaaS', 'Series A', '$22M', NULL, NULL, NULL, 'US', 'construction,quality control,ai review,preconstruction,documents', 'Innovation Endeavors', '{"careers": "https://www.lighttable.ai/careers"}', 1, 'lighttable.webp', 'ready', 'published', 'manual', '2026-06-01 05:58:46', '2026-06-01 05:58:46') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-linear', 'linear', 'linear.app', 'https://linear.app', 'Linear', 'Issue tracking built for modern software teams.', 'Someone finally rebuilt project management for teams that live on the keyboard. Keyboard shortcuts, a stripped-back issue flow, and an interface that stays out of the way make it feel closer to an editor than Jira. In a market full of feature-bloated software, Linear chose speed and restraint. That trade only works if you are willing to say no more often than your competitors.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://linear.app", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2025/06/10/atlassian-rival-linear-raises-82m-at-1-25b-valuation/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Linear: Issue tracking built for modern software teams.", "source_ids": ["official_site"]}, {"claim": "Someone finally rebuilt project management for teams that live on the keyboard.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Defined a new standard for dev tools", "why_now": "Recent source-backed funding and public product evidence make project management, issue tracking, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Defined a new standard for dev tools', 'DevTools', 'Series C', '$82M', 2019, '50-100', 'San Francisco', 'US', 'project management,issue tracking,developer tools,productivity', 'Sequoia Capital, 01 Advisors, SV Angel', '{"github": "https://github.com/linear", "twitter": "https://x.com/linear", "linkedin": "https://linkedin.com/company/linear", "careers": "https://linear.app/careers"}', 1, 'linear.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-liquid-instruments', 'liquid-instruments', 'www.liquidinstruments.com', 'https://www.liquidinstruments.com', 'Liquid Instruments', 'Software-defined test instruments for engineering labs.', 'This is what test equipment looks like when software wins over the bench rack. Liquid Instruments turns Moku hardware into 15+ instruments, switches setups in seconds, and lets teams build custom measurement systems with FPGA-backed processing. Unlike another oscilloscope vendor, it treats instrumentation as a reconfigurable platform. The question is whether AI customization becomes a workflow, not just a lab upgrade.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.liquidinstruments.com", "type": "official"}, {"id": "funding_1", "label": "Liquid Instruments", "url": "https://liquidinstruments.com/news-updates/series-c/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Liquid Instruments: Software-defined test instruments for engineering labs.", "source_ids": ["official_site"]}, {"claim": "Liquid Instruments turns Moku hardware into 15+ instruments, switches setups in seconds, and lets teams build custom measurement systems with FPGA-backed processing.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "15+ instruments in one Moku", "why_now": "Recent source-backed funding and public product evidence make test equipment, instrumentation, fpga worth tracking."}, "risks": [{"claim": "The question is whether AI customization becomes a workflow, not just a lab upgrade.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '15+ instruments in one Moku', 'Other', 'Series C', '$50M', NULL, NULL, NULL, 'US', 'test equipment,instrumentation,fpga,engineering tools', 'Keysight Technologies', '{"careers": "https://www.liquidinstruments.com/company/careers/"}', 1, 'liquid-instruments.webp', 'ready', 'published', 'manual', '2026-05-03 06:28:30', '2026-05-03 06:28:30') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-magnitude', 'magnitude', 'magnitude.ai', 'https://magnitude.ai/', 'Magnitude', 'AI workforce for third-party and Nth-party risk assessments, monitoring, and remediation.', 'Vendor risk is usually a spreadsheet pretending to be a control plane. Magnitude turns TPRM into seven agents for intake, assessment, Nth-party monitoring, vendor follow-up, and remediation, with cited evidence behind decisions. Unlike compliance dashboards that freeze risk at questionnaire time, it assumes suppliers and AI tools keep changing. The open question is whether CISOs want agents to chase vendors before auditors demand it.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://magnitude.ai/", "type": "official"}, {"id": "official_platform", "label": "Official platform page", "url": "https://magnitude.ai/platform", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire funding announcement", "url": "https://www.globenewswire.com/news-release/2026/06/16/3312413/0/en/magnitude-launches-from-stealth-with-10m-seed-funding-and-introduces-the-first-autonomous-ai-workforce-to-enable-third-party-risk-management-teams-in-the-mythos-era.html", "type": "funding"}], "product_evidence": [{"claim": "The official homepage describes a multi-agent platform that continuously assesses products, monitors risk, and remediates issues across third- and Nth-parties.", "source_ids": ["official_site"]}, {"claim": "Magnitude names specialized agents for intake, autonomous assessments, continuous monitoring, Nth-party monitoring, vendor engagement, and risk remediation.", "source_ids": ["official_site", "official_platform"]}, {"claim": "The official site says every decision cites its source and reasoning, and that policies, corrections, and fine-tuning stay inside the customer environment.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Magnitude launched from stealth with $10M seed funding led by Ballistic Ventures for autonomous third-party risk management teams.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "CISOs, GRC leaders, vendor-risk teams, and security analysts responsible for third-party and Nth-party exposure.", "category": "Third-Party Risk Management", "differentiation": "Magnitude makes vendor-risk work agentic and evidence-grounded, pairing continuous risk monitoring with automated vendor follow-up and remediation tracking.", "why_now": "AI vendors, software dependencies, and supplier chains are changing faster than point-in-time questionnaires, making continuous assessment more credible than annual review cycles."}, "risks": [{"claim": "The risk is that security teams may keep agents in recommendation mode if vendor communications and remediation tasks require too much trust to automate.", "basis": "VentureDex editorial assessment based on official product evidence and seed funding coverage."}]}', 4, '$10M seed for TPRM agents', 'SaaS', 'Seed', '$10M', NULL, NULL, 'San Francisco', 'US', 'third-party risk,grc,cybersecurity,ai agents,vendor risk', 'Ballistic Ventures', '{"careers": "https://magnitude.ai/careers"}', 0, 'magnitude.webp', 'ready', 'published', 'manual', '2026-06-17 05:54:00', '2026-06-17 05:54:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-manifest-os', 'manifest-os', 'manifestos.com', 'https://manifestos.com', 'Manifest OS', 'AI-native legal-services platform for fixed-fee immigration firms.', 'Someone finally attacked legal AI from the business model, not the Word add-in. Manifest OS powers immigration firms with fixed-fee pricing, a client portal, AI Drafter, AI Case Evaluation, and 3,000+ handled engagements. Unlike Harvey-style copilot tools, the bet is to operate the service stack and reinvest firm profits into R&D. The risk is bar-by-bar regulation slowing the model outside Arizona.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://manifestos.com", "type": "official"}, {"id": "funding_1", "label": "Business Wire", "url": "https://natlawreview.com/press-releases/manifest-os-raises-60m-scale-worlds-first-ai-native-law-firm-model", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Manifest OS: AI-native legal-services platform for fixed-fee immigration firms.", "source_ids": ["official_site"]}, {"claim": "Manifest OS powers immigration firms with fixed-fee pricing, a client portal, AI Drafter, AI Case Evaluation, and 3,000+ handled engagements.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "$60M Series A, 3,000+ engagements", "why_now": "Recent source-backed funding and public product evidence make legal tech, ai agents, immigration worth tracking."}, "risks": [{"claim": "The risk is bar-by-bar regulation slowing the model outside Arizona.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$60M Series A, 3,000+ engagements', 'Other', 'Series A', '$60M', NULL, NULL, NULL, 'US', 'legal tech,ai agents,immigration,services', 'Menlo Ventures', '{"linkedin": "https://www.linkedin.com/company/manifest-os/", "careers": "https://manifestos.com/careers"}', 1, 'manifest-os.webp', 'ready', 'published', 'manual', '2026-05-05 06:40:13', '2026-05-05 06:40:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-modal', 'modal', 'modal.com', 'https://modal.com/', 'Modal', 'Serverless compute platform for AI, GPU, sandbox, training, and data workloads.', 'The bet is that AI infrastructure should feel like importing a function, not reserving a cluster. Modal shows Python-defined cloud environments, docs, pricing, inference, training, sandboxes, 1000+ GPU autoscaling, and customer proof from Runway, Suno, and Physical Intelligence. Unlike cloud consoles built around machines, it makes the code boundary the control plane.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://modal.com/", "type": "official"}, {"id": "funding_1", "label": "Modal", "url": "https://modal.com/blog/modal-series-c", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Modal: Serverless compute platform for AI, GPU, sandbox, training, and data workloads.", "source_ids": ["official_site"]}, {"claim": "Modal shows Python-defined cloud environments, docs, pricing, inference, training, sandboxes, 1000+ GPU autoscaling, and customer proof from Runway, Suno, and Physical Intelligence.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Serverless GPU infra for AI", "why_now": "Recent source-backed funding and public product evidence make ai infrastructure, gpu, serverless worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Serverless GPU infra for AI', 'DevTools', 'Series C', '$355M', NULL, NULL, NULL, 'US', 'ai infrastructure,gpu,serverless,developer tools,data workloads', 'General Catalyst, Redpoint Ventures', '{"careers": "https://modal.com/careers"}', 1, 'modal.webp', 'ready', 'published', 'manual', '2026-05-26 09:43:21', '2026-05-26 09:43:21') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-moment-energy', 'moment-energy', 'www.momentenergy.com', 'https://www.momentenergy.com', 'Moment Energy', 'Second-life EV battery storage systems for commercial sites.', 'The better climate bet is not another new battery chemistry; it is making retired EV packs insurable infrastructure. Moment Energy leads with Luna BESS, UL 1974 and UL 9540A certifications, supply ties to Mercedes-Benz and Nissan, and an Austin factory plan. Unlike generic grid-storage pitches, the product choice is narrow: own the battery management layer so old packs can safely serve data centers and industrial sites.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.momentenergy.com", "type": "official"}, {"id": "funding_1", "label": "PRNewswire", "url": "https://www.prnewswire.com/news-releases/moment-energy-raises-us40m-series-b-to-build-the-worlds-largest-second-life-battery-factory-302762579.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Moment Energy: Second-life EV battery storage systems for commercial sites.", "source_ids": ["official_site"]}, {"claim": "Moment Energy leads with Luna BESS, UL 1974 and UL 9540A certifications, supply ties to Mercedes-Benz and Nissan, and an Austin factory plan.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Climate, infrastructure, or operations teams evaluating measurable sustainability workflows.", "category": "Climate / Sustainability", "differentiation": "Certified second-life BESS", "why_now": "Recent source-backed funding and public product evidence make battery storage, climate, energy infrastructure worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Certified second-life BESS', 'Climate / Sustainability', 'Series B', '$40M+', NULL, NULL, NULL, 'Global / Remote', 'battery storage,climate,energy infrastructure,ev batteries', 'Evok Innovations, Liberty Mutual Investments, W23 Global Fund, Acario', '{"twitter": "https://twitter.com/moment_energy", "linkedin": "https://ca.linkedin.com/company/momentenergy", "careers": "https://www.momentenergy.com/join-us"}', 1, 'moment-energy.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-moment', 'moment', 'moment.com', 'https://moment.com', 'Moment', 'AI operating system for investment managers, advisors, portfolios, and trades.', 'The sharp bet is replacing the investment stack''s point tools instead of adding another advisor chatbot. Moment''s memo shows agents for proposals, restrictions, cash redemption, trade ideas, execution quality, reconciliation failures, and source data. Unlike generic wealth copilots, it is built around auditable portfolio actions. The risk is whether large firms let the OS become the workflow of record.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://moment.com", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/19/3297569/0/en/Moment-Raises-78-Million-as-Largest-Wealth-Firms-Standardize-on-its-AI-Operating-System-for-Investment-Management.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Moment: AI operating system for investment managers, advisors, portfolios, and trades.", "source_ids": ["official_site"]}, {"claim": "Moment''s memo shows agents for proposals, restrictions, cash redemption, trade ideas, execution quality, reconciliation failures, and source data.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "AI OS for portfolio work", "why_now": "Recent source-backed funding and public product evidence make fintech, investment management, ai agents worth tracking."}, "risks": [{"claim": "The risk is whether large firms let the OS become the workflow of record.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI OS for portfolio work', 'Fintech', 'Series C', '$78M', NULL, NULL, NULL, 'US', 'fintech,investment management,ai agents,wealthtech', 'Index Ventures, Andreessen Horowitz', '{"careers": "https://moment.com/careers"}', 1, 'moment.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-monk', 'monk', 'monk.com', 'https://monk.com', 'Monk', 'AI accounts receivable platform for invoices, collections, cash application, and disputes.', 'The smart move is treating accounts receivable as customer infrastructure, not back-office nagging. Monk handles contract-to-cash work like invoice creation, collections, cash application, portal uploads, PO mismatches, and disputes, with reported 40% lower DSO. Unlike generic finance automation, the product is built around the ugly exceptions that actually delay cash. The risk is that services-heavy onboarding hides how much of the product is software.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://monk.com", "type": "official"}, {"id": "funding_1", "label": "Monk", "url": "https://monk.com/blog/monk-raises-25m", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Monk: AI accounts receivable platform for invoices, collections, cash application, and disputes.", "source_ids": ["official_site"]}, {"claim": "The smart move is treating accounts receivable as customer infrastructure, not back-office nagging.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "AR edge cases, not reminders", "why_now": "Recent source-backed funding and public product evidence make accounts receivable, finance automation, ai agents worth tracking."}, "risks": [{"claim": "The risk is that services-heavy onboarding hides how much of the product is software.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AR edge cases, not reminders', 'Fintech', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'accounts receivable,finance automation,ai agents,b2b', 'Footwork', '{"careers": "https://monk.com/careers"}', 1, 'monk.webp', 'ready', 'published', 'manual', '2026-05-02 09:59:18', '2026-05-02 09:59:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-nanoclaw', 'nanoclaw', 'nanoclaw.dev', 'https://nanoclaw.dev/', 'NanoClaw', 'Container-isolated personal AI agent with messaging channels and per-agent workspaces.', 'The smart bet is shrinking personal agents until the security model is legible. NanoClaw exposes a Node host, per-agent Docker containers, per-session SQLite files, multi-channel skills, and Agent Vault credential injection. Unlike OpenClaw-style agents that sit on the host, it makes isolation the default product surface. The risk is whether implementation services pull it away from the open-source simplicity that made it spread.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://nanoclaw.dev/", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/20/nanoclaw-creator-turns-down-20m-buyout-offer-raises-12m-seed-instead/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes NanoClaw: Container-isolated personal AI agent with messaging channels and per-agent workspaces.", "source_ids": ["official_site"]}, {"claim": "NanoClaw exposes a Node host, per-agent Docker containers, per-session SQLite files, multi-channel skills, and Agent Vault credential injection.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Per-agent Docker isolation", "why_now": "Recent source-backed funding and public product evidence make ai agents, developer tools, security worth tracking."}, "risks": [{"claim": "The risk is whether implementation services pull it away from the open-source simplicity that made it spread.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Per-agent Docker isolation', 'DevTools', 'Seed', '$12M', NULL, NULL, NULL, 'US', 'ai agents,developer tools,security,open source', 'Valley Capital Partners', '{"github": "https://github.com/nanocoai/nanoclaw", "twitter": "https://x.com/Gavriel_Cohen"}', 1, 'nanoclaw.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-nectar-social', 'nectar-social', 'www.nectarsocial.com', 'https://www.nectarsocial.com', 'Nectar Social', 'AI social operating system for community management, listening, and attribution.', 'Someone finally treated social replies as checkout infrastructure instead of brand theater. Nectar shows AI agents for DMs, comments, creator workflows, Reddit/Meta data, 95% untagged conversations, and revenue attribution in one workspace. Unlike Hootsuite-style schedulers, it bets that the community manager''s inbox is where demand is created. The hard part is keeping brand voice from turning into customer-service mush.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.nectarsocial.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/16/marketing-operating-system-nectar-social-raises-30m-series-a-in-round-led-by-menlo/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Nectar Social: AI social operating system for community management, listening, and attribution.", "source_ids": ["official_site"]}, {"claim": "Nectar shows AI agents for DMs, comments, creator workflows, Reddit/Meta data, 95% untagged conversations, and revenue attribution in one workspace.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "95% untagged social coverage", "why_now": "Recent source-backed funding and public product evidence make social commerce, ai agents, community management worth tracking."}, "risks": [{"claim": "The hard part is keeping brand voice from turning into customer-service mush.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '95% untagged social coverage', 'SaaS', 'Series A', '$30M', NULL, NULL, NULL, 'US', 'social commerce,ai agents,community management,marketing analytics', 'Menlo Ventures', '{"linkedin": "https://www.linkedin.com/company/nectar-ai", "careers": "https://jobs.ashbyhq.com/nectar-social"}', 1, 'nectar-social.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-neuraltrust', 'neuraltrust', 'neuraltrust.ai', 'https://neuraltrust.ai/', 'NeuralTrust', 'Platform for discovering, governing, and securing AI agents across enterprise systems.', 'Agent security is moving from prompt filtering to asset inventory. NeuralTrust gives teams TrustGate, TrustGuard, and TrustLens to find agents, broker LLM and MCP calls, enforce policies, and block risky tool use. Unlike appsec tools built around human-written code, this assumes autonomous agents will cross models, data, identities, and services. The hard part is proving it can cover the long tail of internal agents.', '{"verified_at": "2026-06-18", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://neuraltrust.ai/", "type": "official"}, {"id": "official_docs", "label": "Official documentation", "url": "https://docs.neuraltrust.ai/", "type": "product"}, {"id": "funding_1", "label": "Official funding announcement", "url": "https://neuraltrust.ai/news/neuraltrust-raises-20m", "type": "funding"}], "product_evidence": [{"claim": "The official site positions NeuralTrust as a centralized platform to discover and secure all AI agents in an enterprise.", "source_ids": ["official_site"]}, {"claim": "The homepage describes discovery of deployed agents, connected tools, execution workflows, reasoning, planning, and action execution.", "source_ids": ["official_site"]}, {"claim": "The docs describe TrustGate, TrustGuard, TrustLens, policy controls, agent inventory, and MCP gateway deployment paths.", "source_ids": ["official_docs"]}, {"claim": "The official funding post reports a $20M round led by Alstin Capital to expand the AI and agent security platform.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Security teams, AI platform teams, and enterprise architects responsible for agent governance and tool access.", "category": "AI agent security", "differentiation": "NeuralTrust combines agent discovery, runtime policy enforcement, MCP gateway controls, and red-team style testing for AI systems.", "why_now": "Autonomous agents are gaining access to internal tools faster than traditional appsec and IAM workflows can model them."}, "risks": [{"claim": "The risk is that agent inventory coverage depends on enterprises routing enough model and tool traffic through NeuralTrust controls.", "basis": "VentureDex editorial assessment based on official product and documentation review."}]}', 5, '$20M seed for AI-agent security', 'SaaS', 'Seed', '$20M', NULL, NULL, 'Barcelona / London', 'Europe', 'ai security,ai agents,mcp,governance,cybersecurity', 'Alstin Capital', '{"docs": "https://docs.neuraltrust.ai/", "careers": "https://neuraltrust.ai/careers"}', 1, 'neuraltrust.webp', 'ready', 'published', 'manual', '2026-06-18 14:59:42', '2026-06-18 14:59:42') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-niteshift', 'niteshift', 'niteshift.dev', 'https://niteshift.dev/', 'Niteshift', 'Full-stack cloud runtimes where coding agents can verify PRs.', 'The bet is that coding agents need production-like environments, not another chat box. Niteshift reads repo docs, CI, Docker, secrets, and services, then runs agents against browsers, APIs, DB state, logs, and eval scripts before attaching PR evidence. Unlike laptop worktrees or single-vendor agents, it treats verification capacity as cloud infrastructure. The risk is whether teams will trust long-running agents with broad repo access.', '{"verified_at": "2026-06-12", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://niteshift.dev/", "type": "official"}, {"id": "funding_1", "label": "Niteshift seed announcement", "url": "https://niteshift.dev/blog/introducing-niteshift", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Niteshift as a full-stack cloud for coding agents, with setup generated from repo docs, CI, Docker, secrets, and services.", "source_ids": ["official_site"]}, {"claim": "The product surface says agents can verify browser, API, database, log, and eval-script evidence before attaching PR proof.", "source_ids": ["official_site"]}, {"claim": "Niteshift lists Claude Code, Codex, OpenCode, and Pi as supported agent choices rather than tying users to one model workflow.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Engineering teams adopting coding agents across production codebases.", "category": "DevTools", "differentiation": "Niteshift moves verification and full-stack runtime setup into managed cloud sandboxes rather than leaving agents inside local worktrees.", "why_now": "Coding agents can make larger changes, but teams still need repeatable environments and merge-ready evidence."}, "risks": [{"claim": "The open question is whether engineering teams will grant long-running agents enough repo and runtime access to make the cloud model useful.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Agent verification cloud', 'DevTools', 'Seed', '$7M', NULL, NULL, NULL, 'US', 'devtools,coding agents,cloud sandboxes,agent infrastructure,developer productivity', 'Greylock', '{"docs": "https://docs.niteshift.dev/", "pricing": "https://niteshift.dev/pricing"}', 1, 'niteshift.webp', 'ready', 'published', 'manual', '2026-06-12 06:00:05', '2026-06-12 06:00:05') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ocean', 'ocean', 'ocean.security', 'https://ocean.security/platform', 'Ocean', 'Agentic email security that investigates messages before they reach the inbox.', 'The sharp idea is moving phishing triage before the inbox instead of polishing the abuse queue. Ocean''s Ray engine coordinates link, identity, file, financial, and quarantine agents, then returns an explainable verdict to employees across Microsoft 365 and Google Workspace. Unlike SEG filters that score and shrug, it tries to investigate every email as a live case. The buyer risk is trusting an agent between fraud and false positive.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://ocean.security/platform", "type": "official"}, {"id": "funding_1", "label": "CTech", "url": "https://www.calcalistech.com/ctechnews/article/sj59xf5jml", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Ocean: Agentic email security that investigates messages before they reach the inbox.", "source_ids": ["official_site"]}, {"claim": "Ocean''s Ray engine coordinates link, identity, file, financial, and quarantine agents, then returns an explainable verdict to employees across Microsoft 365 and Google Workspace.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Agent swarm before inbox", "why_now": "Recent source-backed funding and public product evidence make cybersecurity, email security, ai agents worth tracking."}, "risks": [{"claim": "The buyer risk is trusting an agent between fraud and false positive.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Agent swarm before inbox', 'AI / ML', 'Series A', '$20M', NULL, NULL, NULL, 'Global / Remote', 'cybersecurity,email security,ai agents,phishing', 'Lightspeed Venture Partners', '{"careers": "https://ocean.security/company/careers"}', 1, 'ocean.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-offroad', 'offroad', 'offroad.ai', 'https://offroad.ai/', 'Offroad', 'Agentic identity security for users, service accounts, OAuth apps, and AI agents.', 'Identity teams are buried under findings from IdPs, SaaS apps, tickets, and endpoint tools. Offroad turns that sprawl into agents that discover, investigate, and remediate risk across users, service accounts, OAuth apps, and AI agents. Unlike another dashboard, it also ships OhAuth, a 2,349-app public OAuth catalog. The risk is whether autonomous remediation clears enterprise approval chains.', '{"verified_at": "2026-06-06", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://offroad.ai/", "type": "official"}, {"id": "ohauth_catalog", "label": "OhAuth public OAuth catalog", "url": "https://ohauth.ai/", "type": "product"}, {"id": "oauth_report", "label": "Offroad OAuth risk report", "url": "https://offroad.ai/blog/oauthreport-2026", "type": "product"}, {"id": "funding_1", "label": "Offroad seed funding article", "url": "https://startuprise.io/offroad-raises-7m-in-seed-funding-led-by-ibex-investors/", "type": "funding"}], "product_evidence": [{"claim": "The official site presents Discover, Investigate, and Remediate agents for identity risk across human users, service accounts, OAuth applications, machine identities, and AI agents.", "source_ids": ["official_site"]}, {"claim": "OhAuth exposes a public catalog for OAuth apps across Google Workspace, GitHub, Slack, Zoom, Atlassian, Microsoft 365, Salesforce, and other ecosystems.", "source_ids": ["ohauth_catalog"]}, {"claim": "Offroad''s OAuth report lists over-permissioned apps, dead publisher domains, buyable domains, and AI apps with broad write access as risk categories.", "source_ids": ["oauth_report"]}], "market_context": {"primary_user": "CISOs and identity-security teams handling SaaS sprawl, OAuth grants, service accounts, and AI-agent access.", "category": "SaaS", "differentiation": "Offroad combines agentic investigation and remediation with a public OAuth-risk catalog rather than only alerting on identity posture.", "why_now": "The June 2026 seed round coincides with enterprises granting broader SaaS and AI-agent permissions across fragmented identity systems."}, "risks": [{"claim": "The open question is whether autonomous identity remediation can move fast while still satisfying approval, audit, and ownership requirements.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Identity agents plus OAuth catalog', 'SaaS', 'Seed', '$7M', NULL, NULL, NULL, 'US', 'identity security,oauth,ai agents,saas security,remediation', 'Ibex Investors, Skywell Capital Partners', NULL, 1, 'offroad.webp', 'ready', 'published', 'manual', '2026-06-06 05:56:19', '2026-06-06 05:56:19') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-olyzon', 'olyzon', 'www.olyzon.tv', 'https://www.olyzon.tv/', 'Olyzon', 'Agentic decision layer for connected-TV planning, activation, and measurement.', 'The bet is that CTV buying broke at the decision layer, not the media pipes. Olyzon maps inventory, scores programs, adapts creative, activates across DSPs and publishers, and claims +20% brand lift plus 15-30% mid-funnel improvement. Unlike panel-style measurement vendors, it tries to turn context, reach, and proof into one operating loop. The risk is whether agencies let an agentic layer sit above their existing stack.', '{"verified_at": "2026-06-01", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.olyzon.tv/", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/sir-martin-sorrells-s4s-ventures-leads-olyzons-10m-series-a-to-build-the-agentic-platform-for-ctv-302782399.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes an agentic layer connected to DSPs, SSPs, and direct publishers that maps inventory, scores programs, activates plans, and proves outcomes.", "source_ids": ["official_site"]}, {"claim": "Olyzon presents context transparency, deduplicated reach, outcome accountability, AdCP compatibility, and impact metrics including +20% brand lift and +15-30% mid-funnel improvement.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Agencies, brands, and trading desks buying connected-TV media across fragmented inventory sources.", "category": "SaaS", "differentiation": "Agentic decisioning layer above existing CTV pipes instead of a single measurement, DSP, or inventory product.", "why_now": "The May 2026 Series A led by S4S Ventures supports US and EMEA expansion as CTV buying shifts from manual planning into AI-assisted workflows."}, "risks": [{"claim": "The open question is whether agencies allow an agentic layer to sit above existing planning, activation, and measurement stacks.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$10M Series A for CTV agents', 'SaaS', 'Series A', '$10M', NULL, NULL, NULL, 'Global / Remote', 'adtech,connected tv,media planning,measurement,agents', 'S4S Ventures', '{"linkedin": "https://www.linkedin.com/company/olyzon/", "careers": "https://www.linkedin.com/company/olyzon/jobs/"}', 1, 'olyzon.webp', 'ready', 'published', 'manual', '2026-06-01 05:58:46', '2026-06-01 05:58:46') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-openobserve', 'openobserve', 'openobserve.ai', 'https://openobserve.ai/', 'OpenObserve', 'Open-source observability platform for logs, metrics, traces, and AI SRE.', 'The interesting move is compressing the observability stack before adding AI SRE. OpenObserve already unifies logs, metrics, traces, RUM, alerts, dashboards, and object-storage economics, then layers anomaly detection and LLM observability on the same data. Unlike AI wrappers over Datadog-style sprawl, it sells one open-source control plane. The risk is whether low-cost infrastructure can support enterprise-grade incident automation.', '{"verified_at": "2026-06-02", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://openobserve.ai/", "type": "official"}, {"id": "funding_1", "label": "OpenObserve announcement", "url": "https://openobserve.ai/blog/series-a-announcement/", "type": "funding"}], "product_evidence": [{"claim": "The official site positions OpenObserve as an open-source, petabyte-scale observability platform for logs, metrics, and traces.", "source_ids": ["official_site"]}, {"claim": "The product navigation exposes logs, metrics, traces, pipelines, alerts, dashboards, LLM observability, AI Assistant, AI SRE, incidents, and an MCP server.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Platform, SRE, and DevOps teams managing high-volume telemetry.", "category": "DevTools", "differentiation": "Unified open-source telemetry storage and workflow surface with AI SRE layered onto the same observability data.", "why_now": "The 2026 Series A and Observability 3.0 launch target teams trying to reduce Datadog-style cost while adding AI-assisted incident workflows."}, "risks": [{"claim": "The open question is whether lower-cost open-source telemetry infrastructure can earn enterprise trust for automated incident response.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Open-source observability plus AI SRE', 'DevTools', 'Series A', '$10M', NULL, NULL, NULL, 'US', 'observability,logs,metrics,traces,ai sre,open source', 'Nexus Venture Partners, Dell Technologies Capital', '{"careers": "https://openobserve.ai/careers/"}', 1, 'openobserve.webp', 'ready', 'published', 'manual', '2026-06-02 05:53:31', '2026-06-02 05:53:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-openrouter', 'openrouter', 'openrouter.ai', 'https://openrouter.ai/', 'OpenRouter', 'Unified API gateway for hundreds of AI models, routing, fallbacks, SDKs, and agent tooling.', 'The bet is that model choice should be a runtime decision, not a vendor marriage. OpenRouter exposes hundreds of models through one `/api/v1/chat/completions` endpoint, SDKs, fallbacks, provider routing, model variants, and agent tooling. Unlike teams hard-coding a single lab, it turns the model layer into a market with controls for cost, latency, and availability.', '{"verified_at": "2026-05-27", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://openrouter.ai/", "type": "official"}, {"id": "docs_quickstart", "label": "OpenRouter quickstart docs", "url": "https://openrouter.ai/docs/quickstart", "type": "product"}, {"id": "models_catalog", "label": "OpenRouter models catalog", "url": "https://openrouter.ai/models", "type": "product"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/26/openrouter-more-than-doubles-valuation-to-1-3b-in-a-year/", "type": "funding"}], "product_evidence": [{"claim": "Quickstart docs describe a unified API for hundreds of AI models through one endpoint with automatic fallbacks and cost-aware selection.", "source_ids": ["docs_quickstart"]}, {"claim": "Docs and product navigation show chat completions, Client SDKs, Agent SDK, OpenAI SDK compatibility, routing controls, and a public models catalog.", "source_ids": ["docs_quickstart", "models_catalog"]}], "market_context": {"primary_user": "Developers and AI product teams routing model calls across providers.", "category": "DevTools", "differentiation": "Runtime model routing across hundreds of providers rather than a single-model integration.", "why_now": "TechCrunch''s May 26, 2026 Series B report says CapitalG led the round as inference and agent workloads push teams toward swappable model gateways."}, "risks": [{"claim": "The moat depends on developers valuing neutral routing enough to resist direct provider discounts, native cloud integrations, or model-lab lock-in.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Multi-model API gateway', 'DevTools', 'Series B', '$113M', NULL, NULL, NULL, 'US', 'ai models,api,gateway,routing,developer tools', 'CapitalG', '{"careers": "https://openrouter.ai/careers"}', 1, 'openrouter.webp', 'ready', 'published', 'manual', '2026-05-27 06:15:57', '2026-05-27 06:15:57') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-origin-lab', 'origin-lab', 'originlab.ai', 'https://originlab.ai', 'Origin Lab', 'Licensed game-engine data for AI world models and robotics simulation.', 'The interesting bet is that world models need game-engine state, not scraped video. Origin Lab captures HUD-free gameplay with depth, action, camera, scene metadata, 20+ categories, 50+ licensed titles, and same-day API access for evals. Compared with web video datasets, this has rights provenance and physics-adjacent telemetry. The hard part is whether game worlds transfer to messy real-world robotics.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://originlab.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/13/origin-lab-raises-8m-to-help-video-game-companies-sell-data-to-world-model-builders/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Origin Lab: Licensed game-engine data for AI world models and robotics simulation.", "source_ids": ["official_site"]}, {"claim": "Origin Lab captures HUD-free gameplay with depth, action, camera, scene metadata, 20+ categories, 50+ licensed titles, and same-day API access for evals.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Game-engine data for world models", "why_now": "Recent source-backed funding and public product evidence make world models, training data, video games worth tracking."}, "risks": [{"claim": "The hard part is whether game worlds transfer to messy real-world robotics.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Game-engine data for world models', 'AI / ML', 'Seed', '$8M', NULL, NULL, NULL, 'US', 'world models,training data,video games,synthetic data', 'Lightspeed Venture Partners', NULL, 0, 'origin-lab.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-outmarket', 'outmarket', 'outmarket.ai', 'https://outmarket.ai', 'Outmarket', 'AI workflow platform for insurance brokerages.', 'The smart move is treating insurance brokerage as document ops, not generic CRM automation. Outmarket shows quote comparison, gap analysis, ACORD forms, AMS360/Applied Epic integrations, 250+ agencies, and 12-15 hours saved per person each week. Unlike broad AI copilots, the bet is that brokers will trust software embedded in policy workflows. The risk is whether specialty lines keep needing human edge cases.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://outmarket.ai", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/outmarket-ai-raises-17m-series-a-to-power-the-intelligence-era-of-insurance-302770379.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Outmarket: AI workflow platform for insurance brokerages.", "source_ids": ["official_site"]}, {"claim": "Outmarket shows quote comparison, gap analysis, ACORD forms, AMS360/Applied Epic integrations, 250+ agencies, and 12-15 hours saved per person each week.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "250+ agencies, $17M Series A", "why_now": "Recent source-backed funding and public product evidence make insurance, ai workflows, brokerages worth tracking."}, "risks": [{"claim": "The risk is whether specialty lines keep needing human edge cases.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '250+ agencies, $17M Series A', 'Fintech', 'Series A', '$17M', NULL, NULL, NULL, 'US', 'insurance,ai workflows,brokerages,document automation', 'Permanent Capital Ventures', '{"careers": "https://outmarket.ai/careers"}', 1, 'outmarket.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pace', 'pace', 'withpace.com', 'https://withpace.com/', 'Pace', 'AI operations platform that turns insurance SOPs into agent-run workflows.', 'Insurance ops is a good place to test whether agents can do work, not just answer tickets. Pace turns SOPs into workflows that read documents, update legacy systems, route exceptions, and resolve more than 90% of some cases without human touch. Unlike horizontal copilots, it is built around Guidewire, Duck Creek, Vertafore, ACORD forms, and claims queues. The risk is whether carrier-specific edge cases eat the margin.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://withpace.com/", "type": "official"}, {"id": "product_page", "label": "Pace product page", "url": "https://withpace.com/product", "type": "product"}, {"id": "funding_1", "label": "Forbes Series B report", "url": "https://www.forbes.com/sites/annatong/2026/05/27/thrive-and-sequoia-back-pace-with-46-million-to-automate-insurances-back-office/?ss=small-business-taxes", "type": "funding"}], "product_evidence": [{"claim": "The official site says Pace lets insurers build, deploy, and manage AI agents that run document, workflow, and customer-channel operations end to end.", "source_ids": ["official_site"]}, {"claim": "The product page lists agentic workflow orchestration, observability, enterprise integrations, and controls for SOP-driven insurance operations.", "source_ids": ["product_page"]}, {"claim": "The public site names insurance use cases including submission intake, life claim support, NIGO checks, policy review, FNOL automation, and core-system integrations.", "source_ids": ["official_site", "product_page"]}], "market_context": {"primary_user": "Insurance operations, claims, underwriting, and IT teams automating carrier workflows.", "category": "AI / ML", "differentiation": "Insurance-native agent workflows and carrier-system integrations instead of a horizontal support or document copilot.", "why_now": "The May 27, 2026 Series B co-led by Thrive and Sequoia backs expansion of production AI workflows for insurance operations."}, "risks": [{"claim": "The risk is whether carrier-specific exceptions, legacy-system variance, and compliance review slow deployments enough to dilute automation gains.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Insurance agents in production', 'AI / ML', 'Series B', '$46M', NULL, NULL, NULL, 'US', 'insurance,ai agents,operations,workflow automation,claims', 'Thrive Capital, Sequoia Capital', '{"product": "https://withpace.com/product"}', 1, 'pace.webp', 'ready', 'published', 'manual', '2026-05-31 06:05:47', '2026-05-31 06:05:47') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-parallel-web-systems', 'parallel-web-systems', 'parallel.ai', 'https://parallel.ai', 'Parallel Web Systems', 'Web search, extraction, monitoring, and research APIs for AI agents.', 'The sharper bet is that AI agents need web infrastructure, not another consumer search box. Parallel exposes Search, Extract, Task, FindAll, Chat, and Monitor APIs, plus OpenAPI, Python, and TypeScript SDKs. Unlike browser wrappers that pretend pages are stable, this treats the web as a programmatic substrate with benchmarks and case studies attached. The risk is that model providers pull the same interfaces into their own platforms.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://parallel.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/29/parallel-web-systems-hits-2b-valuation-five-months-after-its-last-big-raise/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Parallel Web Systems: Web search, extraction, monitoring, and research APIs for AI agents.", "source_ids": ["official_site"]}, {"claim": "VentureDex product review notes that unlike browser wrappers that pretend pages are stable, this treats the web as a programmatic substrate with benchmarks and case studies attached.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Web APIs for AI agents", "why_now": "Recent source-backed funding and public product evidence make ai agents, web search, api worth tracking."}, "risks": [{"claim": "The risk is that model providers pull the same interfaces into their own platforms.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Web APIs for AI agents', 'DevTools', 'Series B', '$100M', 2023, '10-30', 'San Francisco', 'US', 'ai agents,web search,api,developer tools', 'Sequoia Capital, Index Ventures, Khosla Ventures', '{"github": "https://github.com/parallel-web", "twitter": "https://x.com/p0", "linkedin": "https://www.linkedin.com/company/parallel-web/", "careers": "https://parallel.ai/careers"}', 1, 'parallel-web-systems.webp', 'ready', 'published', 'manual', '2026-05-02 09:59:18', '2026-05-02 09:59:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-parasail', 'parasail', 'parasail.io', 'https://parasail.io', 'Parasail', 'Serverless and dedicated GPU inference for AI teams.', 'The practical bet is inference without the cloud procurement tax. Parasail leads with no quotas, no long contracts, up to 30x lower pricing, and docs for Serverless, Dedicated endpoints, Batch, Responses API, and billing APIs. Compared to renting raw GPU boxes, it sells a model-running surface that can scale from free credits to 500B+ daily tokens. The open question is whether this stays cheaper once the largest clouds copy the packaging.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://parasail.io", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/15/parasail-raises-32m-to-feed-tokenmaxxing-ai-developers/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Parasail: Serverless and dedicated GPU inference for AI teams.", "source_ids": ["official_site"]}, {"claim": "Parasail leads with no quotas, no long contracts, up to 30x lower pricing, and docs for Serverless, Dedicated endpoints, Batch, Responses API, and billing APIs.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "500B+ tokens served daily", "why_now": "Recent source-backed funding and public product evidence make gpu cloud, inference, ai infrastructure worth tracking."}, "risks": [{"claim": "The open question is whether this stays cheaper once the largest clouds copy the packaging.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '500B+ tokens served daily', 'DevTools', 'Series A', '$32M', 2023, '10-30', 'San Francisco', 'US', 'gpu cloud,inference,ai infrastructure,developer tools', 'Touring Capital, Kindred Ventures, Basis Set, Samsung Next', '{"twitter": "https://x.com/parasail_io", "linkedin": "https://www.linkedin.com/company/parasail-io/", "careers": "https://job-boards.greenhouse.io/parasail"}', 1, 'parasail.webp', 'ready', 'published', 'manual', '2026-05-02 09:59:18', '2026-05-02 09:59:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-perplexity', 'perplexity', 'perplexity.ai', 'https://perplexity.ai', 'Perplexity', 'AI-powered answer engine that searches the web.', 'Answer-first search should have existed years ago. Perplexity makes the core interaction brutally simple: ask a question, get a synthesized answer with sources, not ten blue links and ad clutter. That is a sharp product bet against the browsing-heavy search interface. The open question is whether that habit expands beyond power users.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://perplexity.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2024/01/04/ai-powered-search-engine-perplexity-ai-now-valued-at-520m-raises-70m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Perplexity: AI-powered answer engine that searches the web.", "source_ids": ["official_site"]}, {"claim": "Answer-first search should have existed years ago.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "The Google killer that might actually be", "why_now": "Recent source-backed funding and public product evidence make ai search, answer engine, web search worth tracking."}, "risks": [{"claim": "The open question is whether that habit expands beyond power users.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'The Google killer that might actually be', 'AI / ML', 'Series B', '$73.6M', 2022, '100-200', 'San Francisco', 'US', 'ai search,answer engine,web search,artificial intelligence', 'IVP, NEA, Databricks Ventures, Jeff Bezos', '{"twitter": "https://x.com/perabordar", "linkedin": "https://linkedin.com/company/perplexity-ai"}', 1, 'perplexity.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-phoenixai', 'phoenixai', 'www.phoenixdata.ai', 'https://www.phoenixdata.ai/', 'PhoenixAI', 'Real-time analytical database built for agentic AI workloads.', 'The useful move is reframing analytics latency as an agent problem, not a dashboard problem. PhoenixAI exposes sub-second SQL on live and historical data, Kafka/Iceberg/Delta Lake integrations, 10K+ concurrent queries, SOC 2 controls, and customer case studies from Coinbase, Conductor, and Demandbase. Unlike batch-first warehouses, it is built for unplanned machine queries. The risk is whether ''agentic database'' stays a category or becomes sharper OLAP positioning.', '{"verified_at": "2026-06-12", "sources": [{"id": "official_site", "label": "Official company site", "url": "https://www.phoenixdata.ai/", "type": "official"}, {"id": "product_page", "label": "Official product page", "url": "https://www.phoenixdata.ai/product", "type": "product"}, {"id": "careers_page", "label": "Official careers page", "url": "https://www.phoenixdata.ai/careers", "type": "official"}, {"id": "funding_1", "label": "PhoenixAI Series B announcement", "url": "https://www.phoenixdata.ai/newsroom/phoenixai-raises-led-by-sky-capital-to-power-agentic-ai.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes PhoenixAI as an analytical database for agentic AI that answers live-data SQL queries in sub-second time.", "source_ids": ["official_site"]}, {"claim": "The product surface lists Kafka, Iceberg, Delta Lake, SOC 2 controls, row-level security, audit logging, and data masking.", "source_ids": ["product_page"]}, {"claim": "The official careers page confirms a static hiring surface without requiring VentureDex to scrape roles, counts, locations, or compensation.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Data infrastructure teams serving AI agents, customer analytics, and high-concurrency internal data products.", "category": "DevTools", "differentiation": "PhoenixAI emphasizes live operational queries and agent concurrency instead of scheduled warehouse dashboards.", "why_now": "AI agents create unpredictable query demand against fresh enterprise data rather than the fixed reporting patterns warehouses were tuned for."}, "risks": [{"claim": "The open question is whether buyers treat agent-facing analytics as a new database category or as faster OLAP positioning.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Live SQL for agents', 'DevTools', 'Series B', '$80M', NULL, NULL, NULL, 'US', 'database,real-time analytics,ai agents,data infrastructure,enterprise data', 'Sky9 Capital', '{"docs": "https://docs.phoenixdata.ai/", "pricing": "https://www.phoenixdata.ai/pricing", "careers": "https://www.phoenixdata.ai/careers"}', 1, 'phoenixai.webp', 'ready', 'published', 'manual', '2026-06-12 06:00:05', '2026-06-12 06:00:05') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-picogrid', 'picogrid', 'picogrid.com', 'https://picogrid.com/', 'Picogrid', 'Open integration layer connecting defense sensors, autonomy systems, and command software.', 'The bet is that defense autonomy needs one integration layer before it needs more isolated hardware. Picogrid connects sensors, unmanned systems, C2 software, edge compute, and vendor systems through Legion API and Orion C2; its Series A post cites 100+ integrated defense systems. Unlike bespoke primes, the product is interoperability itself. The risk is whether procurement cycles can keep up with field demand.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://picogrid.com/", "type": "official"}, {"id": "docs_legion", "label": "Legion API docs", "url": "https://docs.picogrid.com/", "type": "product"}, {"id": "funding_1", "label": "Picogrid", "url": "https://picogrid.com/newsroom/picogrid-raises-usd45m-series-a-to-build-the-open-integration-layer-for-modern-defense", "type": "funding"}], "product_evidence": [{"claim": "Picogrid''s announcement says its integration ecosystem spans more than 100 defense systems across vendors including Skydio, Northrop Grumman, Echodyne, CX2, and Neros.", "source_ids": ["funding_1"]}, {"claim": "The Legion docs expose API surfaces for entities, feed definitions, feed data, integrations, WebRTC, tasking, tracks, permissions, and organization management.", "source_ids": ["docs_legion"]}], "market_context": {"primary_user": "Defense operators and vendors integrating sensors, unmanned platforms, command software, and edge systems.", "category": "Other", "differentiation": "Hardware-agnostic integration infrastructure instead of one-off mission-specific system stitching.", "why_now": "The May 29, 2026 Series A led by Bessemer funds product expansion and deployments with US and allied forces."}, "risks": [{"claim": "The risk is whether defense procurement and deployment timelines can move quickly enough for a platform-style integration layer.", "basis": "VentureDex editorial assessment based on official product and funding-source review."}]}', 5, 'Defense integration layer', 'Other', 'Series A', '$45M', NULL, NULL, NULL, 'US', 'defense,autonomy,api,command and control,systems integration', 'Bessemer Venture Partners', '{"careers": "https://picogrid.com/careers"}', 1, 'picogrid.webp', 'ready', 'published', 'manual', '2026-05-31 02:16:09', '2026-05-31 02:16:09') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pit', 'pit', 'pit.com', 'https://pit.com', 'Pit', 'AI-built internal software for enterprise workflows.', 'The interesting bet is that enterprise software should be generated around the workflow, not bought as another SaaS shelf. Pit Studio maps messy processes, while Pit Cloud promises governance, audit trails, SSO, and tenant isolation for the custom apps it builds. Compared with no-code builders or agent sandboxes, this is closer to a forward-deployed product team. The risk is that every bespoke workflow can become consulting debt.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://pit.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/07/voi-founders-new-ai-startup-pit-has-become-the-latest-rising-star-out-of-stockholm/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Pit: AI-built internal software for enterprise workflows.", "source_ids": ["official_site"]}, {"claim": "Pit Studio maps messy processes, while Pit Cloud promises governance, audit trails, SSO, and tenant isolation for the custom apps it builds.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "$16M seed for AI-built ops software", "why_now": "Recent source-backed funding and public product evidence make enterprise ai, workflow automation, internal tools worth tracking."}, "risks": [{"claim": "The risk is that every bespoke workflow can become consulting debt.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$16M seed for AI-built ops software', 'SaaS', 'Seed', '$16M', NULL, NULL, NULL, 'Europe', 'enterprise ai,workflow automation,internal tools,operations', 'Andreessen Horowitz, Lakestar', NULL, 1, 'pit.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pivot', 'pivot', 'home.pivotapp.ai', 'https://home.pivotapp.ai', 'Pivot', 'AI procurement OS for intake, committed spend, workflows, and negotiation.', 'The bet is turning procurement into a governed operating layer instead of a nicer intake form. Pivot exposes request workflows, committed-spend visibility, AI Studio, ERP connections, and source-to-pay automation for buyers like DoorDash and Lemonade. Unlike point tools that stop at approvals, it tries to keep finance discipline attached to every request. The risk is whether legacy procurement data is clean enough for agents to act.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://home.pivotapp.ai", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/21/3299278/0/en/pivot-raises-40-million-series-b-to-replace-legacy-procurement-software-with-an-enterprise-ai-operating-system.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Pivot: AI procurement OS for intake, committed spend, workflows, and negotiation.", "source_ids": ["official_site"]}, {"claim": "Pivot exposes request workflows, committed-spend visibility, AI Studio, ERP connections, and source-to-pay automation for buyers like DoorDash and Lemonade.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Procurement agents with controls", "why_now": "Recent source-backed funding and public product evidence make procurement, ai agents, erp worth tracking."}, "risks": [{"claim": "The risk is whether legacy procurement data is clean enough for agents to act.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Procurement agents with controls', 'SaaS', 'Series B', '$40M', NULL, NULL, NULL, 'US', 'procurement,ai agents,erp,spend management', 'Forestay Capital, Notion Capital', NULL, 1, 'pivot.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ploy', 'ploy', 'ploy.ai', 'https://ploy.ai/', 'Ploy', 'AI growth platform that operates website-led marketing workflows.', 'The useful bet behind the $27M seed is that the website should become an operating surface, not a brochure. Ploy Web, Grow, and Ads build pages, identify visitors, run ABM and ad loops, patch SEO issues, and sync signals back to CRM systems like HubSpot. Compared with another website builder, it tries to own the work after launch. The risk is whether marketers trust autonomous changes when brand judgment still matters.', '{"verified_at": "2026-06-22", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://ploy.ai/", "type": "official"}, {"id": "official_blog", "label": "Ploy launch post", "url": "https://ploy.ai/blog/ploy-raises-27m", "type": "official"}, {"id": "funding_1", "label": "PR Newswire seed announcement", "url": "https://www.prnewswire.com/news-releases/ploy-raises-27m-to-turn-your-companys-website-into-your-hardest-working-employee-302803231.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Ploy Web, Ploy Grow, and Ploy Ads as coordinated agents for building pages, identifying visitors, creating campaigns, attributing pipeline, and syncing intent signals to CRM workflows.", "source_ids": ["official_site"]}, {"claim": "The official product surface exposes feature pages for AI website building, visitor identification, account-based marketing, analytics, answer-engine optimization, hosting, integrations, and Ploybooks.", "source_ids": ["official_site"]}, {"claim": "The launch post says Ploy agents design pages, write copy, run campaigns, optimize performance, and sync data back to CRM, with examples from Hex, Clay, Tonik, and TNT Growth.", "source_ids": ["official_blog"]}], "market_context": {"primary_user": "Founders, growth operators, marketing teams, and agencies running website-led acquisition.", "category": "Marketing automation", "differentiation": "Ploy treats the website as a continuously operated growth system with agents that ship pages and act on traffic, SEO, ad, and CRM signals.", "why_now": "AI search and agent browsing make owned website content more important, while small growth teams are trying to ship more campaigns without adding web, design, and analytics headcount."}, "risks": [{"claim": "The open question is whether teams will allow agents to change pages, copy, ads, and outreach without diluting brand control or creating noisy campaigns.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$27M seed, live growth agents', 'SaaS', 'Seed', '$27M', NULL, NULL, NULL, 'US', 'marketing automation,website ops,ai agents,growth,seo', 'First Round Capital, Y Combinator', '{"careers": "https://ploy.ai/careers"}', 1, 'ploy.webp', 'ready', 'published', 'manual', '2026-06-22 05:51:32', '2026-06-22 05:51:32') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-poetic', 'poetic', 'poetic.com', 'https://poetic.com/', 'Poetic', 'AI system for turning enterprise procedures into governed automation.', 'The useful bet is that brittle enterprise procedures can become supervised software loops rather than ticket queues. Poetic shows procedure ingestion, expert-feedback learning, recovery when systems change, and published 99%/500,000 process metrics. Unlike RPA tools, it frames reliability around rules and exceptions. The risk is how much autonomy regulated teams will allow near KYC, fraud, and dispute decisions.', '{"verified_at": "2026-06-11", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://poetic.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://poetic.com/careers", "type": "official"}, {"id": "funding_1", "label": "Poetic Series A funding announcement", "url": "https://www.prnewswire.com/news-releases/poetic-raises-50m-series-a-to-automate-the-worlds-most-complex-enterprise-processes-with-reliable-ai-302796939.html", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Poetic as software that learns business rules and follows them while handling end-to-end processes.", "source_ids": ["official_site"]}, {"claim": "The product surface describes uploading procedures, learning from expert feedback, and recovering when systems change.", "source_ids": ["official_site"]}, {"claim": "Poetic publishes process metrics including 99% quality auto-decisioning, 100% process adherence, and 500,000 disputes handled.", "source_ids": ["official_site"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Operations, compliance, support, and risk teams running repeatable enterprise procedures with exceptions.", "category": "AI / ML", "differentiation": "Poetic anchors automation in documented procedures and expert feedback rather than generic task chat.", "why_now": "Enterprises are trying to automate more regulated, multi-step workflows without losing auditability around rules and exceptions."}, "risks": [{"claim": "The open question is how much autonomous process execution regulated enterprises will approve near KYC, fraud, or dispute decisions.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Process automation agent', 'AI / ML', 'Series A', '$50M', NULL, NULL, NULL, 'US', 'ai agents,process automation,enterprise software,compliance workflows,operations', 'Kleiner Perkins', '{"careers": "https://poetic.com/careers"}', 1, 'poetic.webp', 'ready', 'published', 'manual', '2026-06-11 06:04:13', '2026-06-11 06:04:13') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pointfive', 'pointfive', 'www.pointfive.biz', 'https://www.pointfive.biz/', 'PointFive', 'Cloud efficiency posture management for AI and cloud spend.', 'The useful bet is that cloud waste is an engineering workflow, not a FinOps spreadsheet. PointFive shows DeepWaste detections, resource attribution, Jira, ServiceNow, Slack, and Teams workflows, verified savings, and one-click remediation across AWS, Azure, GCP, Kubernetes, Snowflake, and Databricks. Unlike dashboard-first cost tools, it pushes fixes to the people who own the resource. The risk is whether engineers accept automated savings work when performance tradeoffs get messy.', '{"verified_at": "2026-06-09", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.pointfive.biz/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://www.pointfive.biz/careers.html", "type": "official"}, {"id": "funding_1", "label": "PointFive Series B funding article", "url": "https://www.calcalistech.com/ctechnews/article/sjpjbnnwzl", "type": "funding"}, {"id": "investor_1", "label": "Accel investment note", "url": "https://www.accel.com/news/usd1-trilliom-of-ai-and-cloud-spend-will-need-to-be-optimised-our-investment-in-pointfive", "type": "funding"}], "product_evidence": [{"claim": "The official site positions PointFive as cloud efficiency posture management that continuously measures, contextualizes, and improves cloud efficiency.", "source_ids": ["official_site"]}, {"claim": "The product workflow shows ownership attribution, DeepWaste monitoring, contextual waste review, Jira, ServiceNow, Slack, and Teams workflows, and one-click remediation.", "source_ids": ["official_site"]}, {"claim": "The official site lists coverage across AWS, Azure, GCP, Kubernetes, Snowflake, and Databricks, including verified savings and optimization actions.", "source_ids": ["official_site"]}, {"claim": "Accel describes PointFive detecting hundreds of inefficiency types, creating multiple optimization opportunities each week, and adding Snowflake, Databricks, and AI-specific cost signals.", "source_ids": ["investor_1"]}], "market_context": {"primary_user": "FinOps, platform engineering, and infrastructure leaders responsible for cloud and AI spend.", "category": "SaaS", "differentiation": "PointFive turns cloud waste into engineer-owned remediation tickets and one-click fixes instead of stopping at reporting dashboards.", "why_now": "AI workloads, token pricing, GPU usage, and multi-cloud sprawl are making cloud cost governance an operational engineering problem."}, "risks": [{"claim": "The open question is whether engineers trust automated remediation enough when savings trade off against latency, reliability, or workload ownership boundaries.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}, {"claim": "Vendor-reported savings and return-on-investment claims may not generalize across enterprises with less mature tagging, ownership, or platform-engineering practices.", "basis": "VentureDex editorial assessment based on official product evidence and investor-source review."}]}', 4, 'Cloud waste to tickets', 'SaaS', 'Series B', '$60M', NULL, NULL, NULL, 'US', 'cloud cost,finops,ai infrastructure,engineering workflow,cloud optimization', 'Accel', '{"linkedin": "https://www.linkedin.com/company/pointfive/", "careers": "https://www.pointfive.biz/careers.html"}', 1, 'pointfive.webp', 'ready', 'published', 'manual', '2026-06-09 05:48:20', '2026-06-09 05:48:20') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pramaana-labs', 'pramaana-labs', 'pramaanalabs.ai', 'https://pramaanalabs.ai/', 'Pramaana Labs', 'Formal-verification layer for high-stakes AI answers in tax, law, medicine, and safety.', 'The useful bet is that some AI answers should not ship until they can be checked like software. Pramaana turns tax codes, clinical guidelines, legal rules, and safety constraints into machine-checkable logic, then refuses answers it cannot prove. Unlike generic RAG wrappers that cite a source and hope the model behaved, this treats correctness as a compiler problem. The risk is whether domain formalization scales faster than consulting work.', '{"verified_at": "2026-06-18", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://pramaanalabs.ai/", "type": "official"}, {"id": "official_funding_note", "label": "Official funding note", "url": "https://pramaanalabs.ai/blog/we-raised-27m-to-build-a-compiler-for-mission-critical-ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch funding coverage", "url": "https://techcrunch.com/2026/06/17/pramaana-labs-raises-27-million-seed-round-from-khosla-ventures-to-bring-formal-verification-to-ai/", "type": "funding"}], "product_evidence": [{"claim": "The official site says Pramaana turns tax codes, clinical guidelines, legal rules, and safety constraints into machine-checkable logic.", "source_ids": ["official_site"]}, {"claim": "The product page describes a stack that extracts domain knowledge, creates formal representations, and verifies outputs with provers and solvers.", "source_ids": ["official_site"]}, {"claim": "The official funding note frames the product as a compiler for mission-critical AI, not a general chatbot layer.", "source_ids": ["official_funding_note"]}, {"claim": "TechCrunch reports a $27M seed round led by Khosla Ventures for applying formal verification to AI systems.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "AI teams, domain experts, and regulated-enterprise operators who need auditable answers in high-stakes workflows.", "category": "AI verification infrastructure", "differentiation": "Pramaana applies formal methods to AI outputs so answers can be traced, challenged, and proved instead of merely cited.", "why_now": "Enterprises are putting AI into tax, clinical, legal, and safety workflows where plausible answers are not enough."}, "risks": [{"claim": "The open question is whether enough domain knowledge can be formalized quickly without turning each deployment into bespoke consulting.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$27M seed for provable AI', 'AI / ML', 'Seed', '$27M', 2025, NULL, 'San Francisco', 'US', 'ai verification,formal methods,regulated ai,enterprise ai,ai safety', 'Khosla Ventures', NULL, 1, 'pramaana-labs.webp', 'ready', 'published', 'manual', '2026-06-18 14:59:42', '2026-06-18 14:59:42') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-probably', 'probably', 'www.probably.dev', 'https://www.probably.dev/', 'Probably', 'Local-first data agent that checks every answer against deterministic validators.', 'The useful bet is that a data agent should be less charming than a spreadsheet and more accountable than a chatbot. Probably runs locally, connects CSV, Parquet, Snowflake, BigQuery, Postgres, and more, then checks answers against deterministic validators and computation traces. Instead of asking the model to sound confident, it makes the system show its math. The risk is whether a desktop-first analysis robot can replace the messy trust people place in data teams.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.probably.dev/", "type": "official"}, {"id": "official_docs", "label": "Official documentation", "url": "https://www.probably.dev/docs/", "type": "official"}, {"id": "funding_1", "label": "TechCrunch funding report", "url": "https://techcrunch.com/2026/06/16/probably-raises-9m-to-build-a-more-reliable-kind-of-ai/", "type": "funding"}], "product_evidence": [{"claim": "The official homepage describes Probably as a secure local app for accurate data analysis using natural language, with downloads for macOS, Windows, and Linux.", "source_ids": ["official_site"]}, {"claim": "The product page says Probably supports local CSV, JSON, Parquet, and spreadsheet files, plus warehouses including Snowflake, BigQuery, Postgres, MySQL, MariaDB, ClickHouse, and RisingWave.", "source_ids": ["official_site"]}, {"claim": "Probably says every agent action is run through deterministic validators and outputs are checked against computation traces before an answer is accepted.", "source_ids": ["official_site"]}, {"claim": "The official docs position Probably as a local-first data agent that operates over raw data sources and centers speed, accuracy, verifiability, and security.", "source_ids": ["official_docs"]}, {"claim": "The funding report says Probably raised $9M in seed funding from Andreessen Horowitz to build more reliable AI systems that catch hallucinations before users see them.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Data analysts, data scientists, business operators, and engineering teams that need natural-language analysis over local files and warehouses.", "category": "Data Analysis AI", "differentiation": "Probably narrows the agent surface to verifiable data work, pairing local execution and warehouse connectors with deterministic validation rather than a general chat interface.", "why_now": "Companies are pushing AI into analysis workflows while still needing reproducible numbers, audit trails, and lower token costs for precision-sensitive work."}, "risks": [{"claim": "The open question is whether a desktop-first analysis agent can earn enough trust from data teams that already rely on notebooks, BI tools, and internal review habits.", "basis": "VentureDex editorial assessment based on official product evidence, official docs, and current funding coverage."}]}', 5, '$9M seed for verified data analysis', 'AI / ML', 'Seed', '$9M', NULL, NULL, NULL, 'US', 'data analysis,ai agents,local first,analytics,verification', 'Andreessen Horowitz', NULL, 1, 'probably.webp', 'ready', 'published', 'manual', '2026-06-16 16:27:39', '2026-06-16 16:27:39') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-probook', 'probook', 'www.probook.ai', 'https://www.probook.ai/', 'Probook', 'AI operating system for home-service dispatch, intake, and customer messaging.', 'The sharp bet is that dispatch is the brain of home services, not a back-office calendar. Probook starts with routing technicians, then pulls intake, customer messaging, data cleaning, outbound, and booking cleanup into the same context layer. Compared with a voice-agent wrapper, it owns the decision that decides revenue, ETA, and customer experience. The risk is whether the in-person deployment model scales without becoming services-heavy.', '{"verified_at": "2026-06-24", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.probook.ai/", "type": "official"}, {"id": "official_platform", "label": "Probook platform page", "url": "https://www.probook.ai/platform", "type": "product"}, {"id": "funding_1", "label": "GlobeNewswire Series A and seed announcement", "url": "https://www.globenewswire.com/news-release/2026/06/23/3316215/0/en/probook-raises-40m-from-andreessen-horowitz-and-sequoia-to-scale-the-ai-operating-system-for-home-services.html", "type": "funding"}], "product_evidence": [{"claim": "The official homepage positions Probook as an AI operating system for home services with dispatch as the core workflow.", "source_ids": ["official_site"]}, {"claim": "The platform page describes automated board filling, lead capture, booking cleanup, dispatch support, customer updates, and chat replies.", "source_ids": ["official_platform"]}, {"claim": "The funding release says Probook is already used across hundreds of locations by home-service operators such as Del-Air and Peterman Brothers.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Home-service operators that manage technician dispatch, intake, booking quality, and customer follow-up.", "category": "Vertical AI", "differentiation": "Probook is built around the dispatch decision loop rather than a point voice agent, chat widget, or field-service calendar.", "why_now": "Home-service teams face high call volume, labor constraints, and tighter ETA expectations while AI voice and workflow agents can now act across intake, routing, and customer messaging."}, "risks": [{"claim": "The open question is whether Probook can scale field-heavy customer deployments without turning the software motion into a services business.", "basis": "VentureDex editorial assessment based on official product pages and the funding announcement."}]}', 4, '$40M Series A for dispatch OS', 'SaaS', 'Series A', '$40M', NULL, NULL, NULL, 'US', 'home services,dispatch,field service,ai agents,vertical software', 'Andreessen Horowitz, Sequoia Capital', '{"careers": "https://www.probook.ai/company#open-roles"}', 1, 'probook.webp', 'ready', 'published', 'manual', '2026-06-24 06:00:32', '2026-06-24 06:00:32') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-prosper-ai', 'prosper-ai', 'www.getprosper.ai', 'https://www.getprosper.ai/', 'Prosper AI', 'Voice AI platform for patient scheduling, benefits checks, and billing.', 'The useful wedge is that Prosper treats the clinic phone queue as one operating system, not a scheduling bot. Its agents book visits, verify benefits, call payers when APIs fail, collect billing context, and write back to EHR or PMS systems. The contrast with thin voice demos is breadth: one workflow spans patient and insurer calls. The risk is whether accuracy holds across the long tail of payer rules and clinic edge cases.', '{"verified_at": "2026-06-23", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.getprosper.ai/", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire Series A announcement", "url": "https://www.globenewswire.com/news-release/2026/06/22/3315343/0/en/prosper-ai-raises-30m-from-andreessen-horowitz-to-scale-the-first-ai-platform-to-run-the-entire-patient-journey.html", "type": "funding"}, {"id": "investor_note", "label": "Andreessen Horowitz investment note", "url": "https://a16z.com/announcement/investing-in-prosper-ai/", "type": "funding"}], "product_evidence": [{"claim": "The official site presents one platform replacing scheduling, benefits verification, and patient billing, with agents that book, reschedule, cancel, collect intake, recover slots, and update the EHR.", "source_ids": ["official_site"]}, {"claim": "The site says Prosper calls payers directly when API eligibility checks fail, navigates IVR and live representatives, and writes coverage or billing results back into the EHR or PMS.", "source_ids": ["official_site"]}, {"claim": "The a16z note says Prosper handles patient, provider, payor, pharmacy, and pharma conversations in one system while writing structured data into practice tools.", "source_ids": ["investor_note"]}], "market_context": {"primary_user": "Outpatient groups, specialty practices, health systems, and EHR or revenue-cycle partners.", "category": "Healthcare operations automation", "differentiation": "Prosper expands beyond inbound scheduling into insurance eligibility, payer calls, prior authorization, billing questions, and write-back into clinical operations systems.", "why_now": "Provider groups face heavy call volumes and payer friction while voice AI is becoming reliable enough to handle structured but high-variance administrative conversations."}, "risks": [{"claim": "The open question is whether Prosper can keep accuracy and escalation quality high across payer-specific rules, specialty-specific workflows, and messy patient billing cases.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$30M Series A, end-to-end calls', 'HealthTech', 'Series A', '$30M', 2023, NULL, 'New York', 'US', 'healthcare ai,voice agents,patient access,billing,ehr', 'Andreessen Horowitz, Base10, Emergence Capital, Y Combinator, Company Ventures', '{"careers": "https://www.getprosper.ai/careers"}', 1, 'prosper-ai.webp', 'ready', 'published', 'manual', '2026-06-23 05:54:27', '2026-06-23 05:54:27') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-qodo', 'qodo', 'www.qodo.ai', 'https://www.qodo.ai', 'Qodo', 'AI code review, testing, and governance for engineering teams.', 'Most AI coding products still want to be copilots; the cleaner bet is fixing the review bottleneck instead. Qodo leads with 856.5K VS Code installs, 625K JetBrains installs, and a workflow spanning IDE, PR, CLI, and rules. That review-first posture feels more durable than one more generator wrapper, because teams adopting AI fastest mostly need help trusting what already got written. The risk is that model vendors eventually bundle enough verification to squeeze the middle layer.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.qodo.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/03/30/qodo-bets-on-code-verification-as-ai-coding-scales-raises-70m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Qodo: AI code review, testing, and governance for engineering teams.", "source_ids": ["official_site"]}, {"claim": "Qodo leads with 856.5K VS Code installs, 625K JetBrains installs, and a workflow spanning IDE, PR, CLI, and rules.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Review-first AI coding workflow", "why_now": "Recent source-backed funding and public product evidence make developer tools, code review, ai coding worth tracking."}, "risks": [{"claim": "The risk is that model vendors eventually bundle enough verification to squeeze the middle layer.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Review-first AI coding workflow', 'DevTools', 'Series B', '$70M', 2022, NULL, 'New York', 'US', 'developer tools,code review,ai coding,software quality', 'Qumra Capital, Maor Ventures, Phoenix Venture Partners, S Ventures, Square Peg, Susa Ventures, TLV Partners, Vine Ventures', '{"github": "https://github.com/Codium-ai", "twitter": "https://x.com/QodoAI", "linkedin": "https://www.linkedin.com/company/qodoai", "careers": "https://www.qodo.ai/careers/"}', 1, 'qodo.webp', 'ready', 'published', 'manual', '2026-04-20 09:56:11', '2026-04-20 09:56:11') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-qorelo', 'qorelo', 'qorelo.com', 'https://qorelo.com/', 'Qorelo', 'AI delivery layer for SAP migrations, Fit-Gap work, and post-go-live change requests.', 'SAP migrations usually turn expert memory into workshop debris; this treats the delivery method itself as software. The product maps ECC documents, transcripts, Z-objects, Fit-Gap decisions, RICEFW stories, and hypercare tickets into Activate-phase agents. The bet is not another copilot beside SAP, but a project memory that survives consultants. The risk is whether its claimed 40-45% speed gains hold beyond early enterprise pilots.', '{"verified_at": "2026-06-15", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://qorelo.com/", "type": "official"}, {"id": "funding_1", "label": "TFN funding report", "url": "https://techfundingnews.com/qorelo-raises-3-5m-sap-migration-automation-seed/", "type": "funding"}], "product_evidence": [{"claim": "The official homepage positions Qorelo as an AI engine for modern SAP delivery and says it stays embedded through discovery, fit-to-standard, build, cutover, and hypercare.", "source_ids": ["official_site"]}, {"claim": "The product copy says Qorelo ingests ECC enhancement documents, functional specs, Z-object registers, historical BRDs, and transcripts into a queryable migration knowledge base.", "source_ids": ["official_site"]}, {"claim": "The site describes Fit-Gap and build outputs including RICEFW-classified user stories, configuration guides, Fit-Gap logs, Jira tickets, and hypercare change-request handling.", "source_ids": ["official_site"]}, {"claim": "The funding report says the company is using seed capital to expand its SAP migration automation product after early enterprise pilots.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "SAP program leads, transformation offices, systems integrators, and enterprise IT teams running ECC-to-S/4HANA migrations.", "category": "Enterprise AI Delivery Software", "differentiation": "Qorelo focuses on the SAP delivery method itself, turning implementation artifacts and workshop output into agents for Fit-Gap, RICEFW, Jira, Confluence, Miro, and hypercare workflows.", "why_now": "Large enterprises face S/4HANA migration pressure while specialist SAP delivery capacity remains expensive, making reusable migration memory more valuable."}, "risks": [{"claim": "The open question is whether Qorelo''s claimed speed improvements repeat outside early SAP migration pilots and across more heterogeneous integrator delivery teams.", "basis": "VentureDex editorial assessment based on official product evidence and current seed funding coverage."}]}', 4, '$3.5M seed for SAP delivery', 'SaaS', 'Seed', '$3.5M', NULL, NULL, NULL, 'Europe', 'sap,erp migration,ai agents,enterprise software,consulting', 'HPI Ventures, Caesar Ventures', '{"careers": "https://jobs.ashbyhq.com/qorelo"}', 1, 'qorelo.webp', 'ready', 'published', 'manual', '2026-06-15 05:52:33', '2026-06-15 05:52:33') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-quantware', 'quantware', 'quantware.com', 'https://quantware.com', 'QuantWare', 'Commercial QPUs, peripherals, and foundry services for quantum builders.', 'The sharper quantum bet is not selling one more lab chip; it is turning QPUs into a manufacturable supply chain. QuantWare sells A-Line, D-Line, peripherals, foundry, and packaging services, and says it has shipped to 50+ customers across 20 countries. Unlike full-stack quantum computer builders, VIO is a component-platform wager: own the processor architecture other teams scale on. The risk is that the 10,000-qubit 2028 promise still has to survive physics and factory reality.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://quantware.com", "type": "official"}, {"id": "funding_1", "label": "Bloomberg", "url": "https://www.bloomberg.com/news/articles/2026-05-05/intel-capital-backs-quantum-computing-chips-startup-quantware", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes QuantWare: Commercial QPUs, peripherals, and foundry services for quantum builders.", "source_ids": ["official_site"]}, {"claim": "QuantWare sells A-Line, D-Line, peripherals, foundry, and packaging services, and says it has shipped to 50+ customers across 20 countries.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "Open QPU supply chain", "why_now": "Recent source-backed funding and public product evidence make quantum, hardware, qpu worth tracking."}, "risks": [{"claim": "The risk is that the 10,000-qubit 2028 promise still has to survive physics and factory reality.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Open QPU supply chain', 'Other', 'Series B', '$178M', NULL, NULL, NULL, 'Europe', 'quantum,hardware,qpu,semiconductors', 'Intel Capital, IQT, ETF Partners, FORWARD.one, Invest-NL Deep Tech Fund, InnovationQuarter Capital, Ground State Ventures, Graduate Ventures', '{"linkedin": "https://www.linkedin.com/company/quantware", "careers": "https://quantware.com/careers"}', 1, 'quantware.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-quartermaster', 'quartermaster', 'www.quartermaster.us', 'https://www.quartermaster.us/', 'Quartermaster', 'SmartMast sensors and AI turn commercial vessels into a maritime awareness network.', 'The useful bet is turning ordinary ships into a sensing network instead of selling another fleet dashboard. Quartermaster puts SmartMast cameras, radios, geolocation, and AI on 600+ vessels, then shows verified HD video, alerts, and real-time tracking. Compared with AIS pings, the product captures what ships actually see. The risk is whether network coverage scales faster than hardware installation drag.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.quartermaster.us/", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/20/this-startup-raised-43m-to-build-a-hive-mind-for-ships/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Quartermaster: SmartMast sensors and AI turn commercial vessels into a maritime awareness network.", "source_ids": ["official_site"]}, {"claim": "Quartermaster puts SmartMast cameras, radios, geolocation, and AI on 600+ vessels, then shows verified HD video, alerts, and real-time tracking.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "600+ ships sensing oceans", "why_now": "Recent source-backed funding and public product evidence make maritime, sensors, ai worth tracking."}, "risks": [{"claim": "The risk is whether network coverage scales faster than hardware installation drag.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '600+ ships sensing oceans', 'Other', 'Series A', '$43M', NULL, NULL, NULL, 'US', 'maritime,sensors,ai,transportation', 'First Round Capital, Quiet Capital', '{"careers": "https://jobs.ashbyhq.com/quartermaster"}', 1, 'quartermaster.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-radixark', 'radixark', 'www.radixark.com', 'https://www.radixark.com', 'RadixArk', 'Open inference and training infrastructure for frontier AI.', 'The useful bet is that AI infra should be shared infrastructure, not private lab plumbing. RadixArk starts from SGLang for inference and Miles for post-training, with SGLang already powering trillions of tokens daily across teams like Google, NVIDIA, Oracle, AMD, LinkedIn, and xAI. Compared with another closed model platform, this is a tools-and-runtime company. The risk is turning open-source gravity into a managed product without slowing the community.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.radixark.com", "type": "official"}, {"id": "funding_1", "label": "RadixArk", "url": "https://www.radixark.com/blog/radixark-launches-100m-seed", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes RadixArk: Open inference and training infrastructure for frontier AI.", "source_ids": ["official_site"]}, {"claim": "RadixArk starts from SGLang for inference and Miles for post-training, with SGLang already powering trillions of tokens daily across teams like Google, NVIDIA, Oracle, AMD, LinkedIn, and xAI.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "$100M seed for SGLang infra", "why_now": "Recent source-backed funding and public product evidence make ai infrastructure, inference, open source worth tracking."}, "risks": [{"claim": "The risk is turning open-source gravity into a managed product without slowing the community.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$100M seed for SGLang infra', 'DevTools', 'Seed', '$100M', NULL, NULL, NULL, 'US', 'ai infrastructure,inference,open source,developer tools', 'Accel, Spark Capital, NVentures, Salience Capital, A&E Investment, HOF Capital, Walden Catalyst, AMD, LDVP, WTT Fubon Family, MediaTek, Databricks', '{"github": "https://github.com/radixark", "careers": "https://job-boards.greenhouse.io/radixark"}', 1, 'radixark.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-rely', 'rely', 'tryrely.ai', 'https://tryrely.ai', 'Rely', 'AI diligence automation for multifamily lease, vendor, utility, and financial audits.', 'This is deal-room software with the spreadsheet pain left in view. Rely ingests multifamily leases, vendor contracts, utilities, and financial files, then exports source-linked audit tables in under 30 minutes for most reviews. Unlike generic document AI, it bets on one messy asset class and one due-diligence workflow. The open question is whether lenders and operators trust the model when a single bad cell changes a deal.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://tryrely.ai", "type": "official"}, {"id": "funding_1", "label": "Commercial Observer", "url": "https://commercialobserver.com/2026/05/multifamily-deal-diligence-rely-fundraise/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Rely: AI diligence automation for multifamily lease, vendor, utility, and financial audits.", "source_ids": ["official_site"]}, {"claim": "Rely ingests multifamily leases, vendor contracts, utilities, and financial files, then exports source-linked audit tables in under 30 minutes for most reviews.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Under-30-minute audits", "why_now": "Recent source-backed funding and public product evidence make proptech, due diligence, document ai worth tracking."}, "risks": [{"claim": "The open question is whether lenders and operators trust the model when a single bad cell changes a deal.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Under-30-minute audits', 'SaaS', 'Seed', '$4.5M', NULL, NULL, NULL, 'US', 'proptech,due diligence,document ai,multifamily', '2048 Ventures', '{"careers": "https://jobs.gem.com/rely"}', 1, 'rely.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-resend', 'resend', 'resend.com', 'https://resend.com', 'Resend', 'Email API for developers. Beautiful, simple, reliable.', 'Transactional email used to feel like plumbing you tolerated, not a product you enjoyed. Resend changed that with a cleaner API surface and React Email as a companion project. That pairing reveals the bet: email delivery and email design should live in the same developer workflow. It feels closer to Stripe-grade DX than legacy SMTP tooling.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://resend.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2023/07/18/developer-focused-email-platform-resend-raises-3m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Resend: Email API for developers. Beautiful, simple, reliable.", "source_ids": ["official_site"]}, {"claim": "Resend changed that with a cleaner API surface and React Email as a companion project.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "DX that makes you jealous", "why_now": "Recent source-backed funding and public product evidence make email, api, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'DX that makes you jealous', 'DevTools', 'Seed', '$3M', 2022, '10-30', 'San Francisco', 'US', 'email,api,developer tools,transactional email', 'Y Combinator, SV Angel, Dylan Field', '{"github": "https://github.com/resend", "twitter": "https://x.com/resabordar", "linkedin": "https://linkedin.com/company/resend", "careers": "https://resend.com/careers"}', 1, 'resend.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-respond-io', 'respond-io', 'respond.io', 'https://respond.io/', 'Respond.io', 'Customer conversation platform for chats, calls, email, CRM context, and AI agents.', 'The bet is that messaging is not support; it is the revenue interface. Respond.io pulls WhatsApp, calls, email, CRMs, and AI agents into one inbox so a customer can move channels without restarting the relationship. Compared with chatbot-first tools, the product keeps the human sales motion visible. The risk is whether mid-market teams see enough process change to switch from the stacks they already duct-taped together.', '{"verified_at": "2026-06-17", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://respond.io/", "type": "official"}, {"id": "official_ai_agents", "label": "Official AI Agents page", "url": "https://respond.io/ai-agents", "type": "official"}, {"id": "funding_1", "label": "Respond.io Series B announcement", "url": "https://respond.io/blog/respond-io-raises-62-million-series-b", "type": "funding"}], "product_evidence": [{"claim": "The official homepage says Respond.io unifies customer chats, calls, emails, and CRM context in a team inbox with native lead management.", "source_ids": ["official_site"]}, {"claim": "The official site exposes AI Agent workflows for answering enquiries, routing buyers, recommending products, booking appointments, and updating CRMs across customer channels.", "source_ids": ["official_site", "official_ai_agents"]}, {"claim": "Respond.io publishes customer-case evidence for appointment booking, conversion, response-speed, visa-inquiry, and WhatsApp sales workflows using the platform and AI Agents.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Respond.io raised a $62.5M Series B led by Camber Partners to expand the customer conversation management platform for mid-market B2C businesses.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Mid-market B2C sales, support, and revenue teams managing high-volume conversations across messaging, calls, and CRM systems.", "category": "Customer Conversation Management", "differentiation": "Respond.io treats messaging channels as revenue operations infrastructure, combining unified inbox, AI agents, calls, lead management, and CRM context rather than a standalone chatbot surface.", "why_now": "Customer acquisition and support are moving into WhatsApp, social messaging, and AI-handled conversations, creating pressure for one accountable conversation record across channels."}, "risks": [{"claim": "The main risk is that customer conversation management becomes a crowded CRM and support-suite feature instead of a durable standalone buying category.", "basis": "VentureDex editorial assessment based on official product evidence and Series B coverage."}]}', 4, '$62.5M Series B for chat-led sales', 'SaaS', 'Series B', '$62.5M', NULL, NULL, 'Kuala Lumpur', 'China / Asia', 'customer conversations,ai agents,whatsapp,crm,sales automation', 'Camber Partners, Endeavor Catalyst', '{"careers": "https://respond.io/careers"}', 0, 'respond-io.webp', 'ready', 'published', 'manual', '2026-06-17 05:54:00', '2026-06-17 05:54:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-reveng-ai', 'reveng-ai', 'reveng.ai', 'https://reveng.ai/', 'RevEng.AI', 'AI binary analysis platform for reverse engineering and malware analysis.', 'The sharper move is checking the binary that actually ships, not the repository everyone hopes matches it. RevEng.AI''s BinNet analyzes executables, firmware, and third-party artifacts, with IDA Pro, Ghidra, and CLI plugins for reverse engineers. Unlike source-code scanners, it treats compiled software as the source of truth. The risk is whether defense-grade binary analysis can become a normal release gate for commercial teams.', '{"verified_at": "2026-06-01", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://reveng.ai/", "type": "official"}, {"id": "funding_1", "label": "NATO Innovation Fund", "url": "https://www.nif.fund/news/nato-innovation-fund-leads-15-million-reveng-ai-round-to-verify-the-security-and-integrity-of-ai-generated-software/", "type": "funding"}], "product_evidence": [{"claim": "The official site describes BinNet as a proprietary AI model for understanding the semantics of binary machine code and verifying software supply-chain integrity.", "source_ids": ["official_site"]}, {"claim": "RevEng.AI exposes IDA Pro, Ghidra, and CLI integrations so reverse engineers can analyze GNU/Linux, Windows, and Android binaries inside existing workflows.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Reverse engineers, malware analysts, and software supply-chain security teams.", "category": "DevTools", "differentiation": "Binary-first AI analysis for shipped artifacts rather than source-only scanning.", "why_now": "The May 2026 Series A led by NATO Innovation Fund arrives as governments and enterprises harden supply chains against malicious and unverifiable binaries."}, "risks": [{"claim": "The open question is whether binary analysis can move from specialist reverse-engineering teams into standard CI and release workflows.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'BinNet for binary analysis', 'DevTools', 'Series A', '$15M', NULL, NULL, NULL, 'Europe', 'cybersecurity,binary analysis,reverse engineering,supply chain,malware', 'NATO Innovation Fund', NULL, 1, 'reveng-ai.webp', 'ready', 'published', 'manual', '2026-06-01 05:58:46', '2026-06-01 05:58:46') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-rivvun-ai', 'rivvun-ai', 'rivvun.ai', 'https://rivvun.ai/', 'Rivvun AI', 'Agentic P&L execution layer for enterprise spend and revenue leakage.', 'The bet is that enterprise AI should recover money, not summarize meetings. Rivvun connects contract, invoice, procurement, CRM, and ERP evidence, then runs 2 agent families for Spend Assurance and Margin Defense with governed fixes and audit trails. Unlike post-quarter finance forensics, it tries to catch rebates, pricing gaps, and settlement issues before they become write-offs. The risk is proving autonomous corrections across messy enterprise policies.', '{"verified_at": "2026-06-12", "sources": [{"id": "official_site", "label": "Official company site", "url": "https://rivvun.ai/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://rivvun.ai/careers/", "type": "official"}, {"id": "funding_1", "label": "Rivvun AI seed funding coverage", "url": "https://economictimes.indiatimes.com/tech/funding/rivvun-ai-raises-7-55-million-led-by-sitara-capital-3one4-capital/articleshow/131636944.cms", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Rivvun as an agentic execution layer for detecting spend leakage, margin erosion, and revenue leakage.", "source_ids": ["official_site"]}, {"claim": "Rivvun describes Spend Assurance and Margin Defense agents for invoice assessment, rebates, pricing enforcement, and commitments.", "source_ids": ["official_site"]}, {"claim": "The official product surface cites outcomes including $70M spend reduction identified and 300% ROI on royalty governance.", "source_ids": ["official_site"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}], "market_context": {"primary_user": "Finance, procurement, commercial, and revenue operations teams managing contract, invoice, pricing, and settlement controls.", "category": "Fintech", "differentiation": "Rivvun focuses agents on recoverable P&L leakage and governed corrective action instead of finance summaries.", "why_now": "Large companies have enough operational data for AI agents to inspect spend and margin leaks, but still need audit trails for corrections."}, "risks": [{"claim": "The open question is whether autonomous corrections can work across inconsistent policies, supplier data, and enterprise approval rules.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'P&L leakage agents', 'Fintech', 'Seed', '$7.55M', NULL, NULL, NULL, 'Global / Remote', 'fintech,enterprise ai,procurement,revenue recovery,agentic workflows', 'Sitara Capital, 3one4 Capital', '{"careers": "https://rivvun.ai/careers/", "linkedin": "https://www.linkedin.com/company/rivvun/", "twitter": "https://x.com/rivvunai"}', 1, 'rivvun-ai.webp', 'ready', 'published', 'manual', '2026-06-12 06:00:05', '2026-06-12 06:00:05') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-runlayer', 'runlayer', 'www.runlayer.com', 'https://www.runlayer.com/', 'Runlayer', 'Enterprise AI control plane for governed agent access, MCPs, and audit.', 'The useful move is treating AI adoption as infrastructure, not a pile of chat licenses. Runlayer gives employees a sanctioned agent catalog, MCP gateway, scoped permissions, audit logs, shadow-AI discovery, runtime checks, and spend visibility across tools like Claude, ChatGPT, Cursor, and Agentforce. Compared with locking AI down, the bet is that the approved path has to be easier than the workaround. The risk is whether neutral control stays neutral once every platform ships guardrails.', '{"verified_at": "2026-06-25", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.runlayer.com/", "type": "official"}, {"id": "official_blog", "label": "Runlayer Series A announcement", "url": "https://www.runlayer.com/blog/series-A-30m-fundraise-felicis-khosla", "type": "official"}, {"id": "funding_1", "label": "Fortune Series A funding report", "url": "https://fortune.com/2026/06/24/exclusive-vinod-khosla-felicis-runlayer-nanit-30-million-enterprise-ai/", "type": "funding"}, {"id": "funding_2", "label": "PR Newswire Series A announcement", "url": "https://www.prnewswire.com/news-releases/runlayer-raises-30m-series-a-to-help-enterprises-go-all-in-on-ai-302809271.html", "type": "funding"}], "product_evidence": [{"claim": "The homepage describes an AI enablement layer with a company catalog, 18,000+ MCPs, internal MCP publishing, a governed gateway, and employee-created AI coworkers.", "source_ids": ["official_site"]}, {"claim": "The product surface lists shadow-AI discovery, access and action governance, runtime security, audit logs, and spend visibility across enterprise AI tools.", "source_ids": ["official_site"]}, {"claim": "The Series A announcement frames Runlayer as a governed control plane for agent use, with customers including Jane, AngelList, Homebase, Lemonade, dbt Labs, and Justworks.", "source_ids": ["official_blog", "funding_1", "funding_2"]}], "market_context": {"primary_user": "CIOs, security teams, AI transformation leaders, and platform teams rolling out approved AI agents across a company.", "category": "Enterprise AI governance", "differentiation": "Runlayer combines sanctioned agent discovery, MCP access, runtime controls, permissions, audit, and spend tracking instead of offering only a gateway or security checklist.", "why_now": "Enterprises are moving from scattered AI experimentation to agent workflows that touch internal systems, which makes identity, audit, access, and runtime control urgent."}, "risks": [{"claim": "The open question is whether Runlayer can remain the neutral control layer as AI platforms add their own governance, audit, and agent-management controls.", "basis": "VentureDex editorial assessment based on the official product surface and funding-source review."}]}', 4, '$30M Series A for AI control', 'DevTools', 'Series A', '$30M', NULL, NULL, NULL, 'US', 'ai agents,governance,mcp,security,enterprise ai', 'Felicis Ventures, Khosla Ventures', '{"linkedin": "https://www.linkedin.com/company/runlayer/", "twitter": "https://x.com/runlayer", "careers": "https://www.runlayer.com/careers"}', 1, 'runlayer.webp', 'ready', 'published', 'manual', '2026-06-25 05:55:07', '2026-06-25 05:55:07') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-sandstone', 'sandstone', 'sandstone.com', 'https://sandstone.com/', 'Sandstone', 'Legal relationship management software for in-house counsel.', 'The useful bet is that in-house legal teams need relationship memory, not another contract inbox. Sandstone shows intake, matter tracking, document review, legal research, and work across more than 100 integrated tools. Unlike e-billing or CLM systems, it centers the counsel-client relationship and its history. The risk is whether legal teams keep enough clean context in one place for the AI layer to stay useful.', '{"verified_at": "2026-06-10", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://sandstone.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://sandstone.com/careers", "type": "official"}, {"id": "official_news", "label": "Official Series A announcement", "url": "https://sandstone.com/blog/sandstone-announces-series-a", "type": "official"}, {"id": "funding_1", "label": "Sandstone Series A funding article", "url": "https://techcrunch.com/2026/06/09/sandstone-raises-30m-to-bring-ai-to-in-house-legal-teams/", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Sandstone as legal relationship management software built for in-house counsel and internal business clients.", "source_ids": ["official_site"]}, {"claim": "The product surface shows legal intake, matter tracking, document review, legal research, communication, and task execution inside one workflow.", "source_ids": ["official_site"]}, {"claim": "Sandstone says the system works with more than 100 integrated tools, including Microsoft 365, Google Workspace, Slack, CLM, and e-billing systems.", "source_ids": ["official_site"]}, {"claim": "The funding article says Sandstone raised a $30M Series A led by Lightspeed to bring AI to in-house legal teams.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "In-house legal teams managing business requests, matters, documents, and legal knowledge across multiple internal tools.", "category": "SaaS", "differentiation": "Sandstone frames legal operations around counsel-client relationship context rather than isolated contracts, tickets, or billing workflows.", "why_now": "Corporate legal teams are under pressure to answer more requests with fewer lawyers, while AI can turn matter history and documents into reusable context."}, "risks": [{"claim": "The open question is whether customers can keep legal context current enough across many systems for AI work products to remain reliable.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Legal relationship memory', 'SaaS', 'Series A', '$30M', NULL, NULL, NULL, 'US', 'legaltech,in-house counsel,ai agents,workflow automation,knowledge management', 'Lightspeed Venture Partners', '{"careers": "https://sandstone.com/careers", "press": "https://sandstone.com/blog/sandstone-announces-series-a"}', 1, 'sandstone.webp', 'ready', 'published', 'manual', '2026-06-10 05:57:38', '2026-06-10 05:57:38') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-saris', 'saris', 'saris.ai', 'https://saris.ai/', 'Saris', 'AI workflow agents for lending, compliance, and operations at banks and credit unions.', 'The bet is that bank AI works only when workflow execution and human oversight ship together. Saris targets 50-step lending, compliance, and operations work, with official examples citing 70% task automation and 9.8x cost reduction per workflow. Unlike screenshot-driven RPA, its investor note describes native desktop bindings and self-healing agents. The risk is whether regulated buyers convert fast pilots into standard operating infrastructure.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://saris.ai/", "type": "official"}, {"id": "funding_1", "label": "Business Wire", "url": "https://www.businesswire.com/news/home/20260528291475/en/Saris-Raises-%2428.8-Million-to-Scale-Agentic-Workflow-Automation-for-Financial-Institutions", "type": "funding"}, {"id": "investor_note", "label": "8VC investment note", "url": "https://www.8vc.com/resources/announcing-our-investment-in-saris-ai", "type": "funding"}], "product_evidence": [{"claim": "The official site says Saris automates multi-step lending, compliance, and operational workflows while keeping human approval and audit trails in place.", "source_ids": ["official_site"]}, {"claim": "8VC describes native desktop bindings, self-healing agents, 50-plus-step lending workflows, and 90-day customer go-lives without dedicated implementation engineering.", "source_ids": ["investor_note"]}], "market_context": {"primary_user": "Banks and credit unions trying to automate manual back-office lending, compliance, and operations work.", "category": "Fintech", "differentiation": "Banking-specific agent workflows that execute across legacy systems under human supervision.", "why_now": "The May 28, 2026 Series A led by 8VC funds expansion across more financial institutions and integrations."}, "risks": [{"claim": "The open question is whether regulated financial institutions can scale deployment without slow security and procurement cycles.", "basis": "VentureDex editorial assessment based on official product and investor-source review."}]}', 4, 'Bank back-office AI agents', 'Fintech', 'Series A', '$28.8M', NULL, NULL, NULL, 'US', 'banking,ai agents,lending,compliance,workflow automation', '8VC', NULL, 1, 'saris.webp', 'ready', 'published', 'manual', '2026-05-31 02:16:09', '2026-05-31 02:16:09') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-scispot', 'scispot', 'www.scispot.com', 'https://www.scispot.com/', 'Scispot', 'AI-native lab operating layer for LIMS, inventory, integrations, and Scibot.', 'Lab software usually makes scientists choose between notebook, LIMS, and inventory systems. Scispot''s bet is one operating layer: LabOS, sample traceability, GLUE integrations, Scibot, API, Python SDK, and CLI in the same surface. Unlike point ELNs, it sells the connective tissue. The risk is whether every lab''s messy instruments can really fit the model.', '{"verified_at": "2026-06-05", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.scispot.com/", "type": "official"}, {"id": "funding_1", "label": "Scispot Series A announcement", "url": "https://www.prnewswire.com/news-releases/scispot-raises-8m-series-a-to-help-life-sciences-labs-move-faster-302790717.html", "type": "funding"}], "product_evidence": [{"claim": "The official site shows LabOS, alt-LIMS, inventory management, GLUE integrations, and Scibot as connected lab-operation modules.", "source_ids": ["official_site"]}, {"claim": "The product surface advertises API, JupyterHub, Python SDK, and CLI access for code-first lab automation.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Biotech, diagnostics, genomics, testing, and CRO lab teams running sample-heavy operations.", "category": "HealthTech", "differentiation": "Scispot combines LIMS-like traceability, inventory, integrations, AI search, and code interfaces rather than selling a single lab notebook.", "why_now": "The June 2026 Series A arrives as labs look for auditable automation across instruments, samples, reports, and scientific data systems."}, "risks": [{"claim": "The open question is whether one operating layer can absorb the custom instruments and workflows inside every specialized lab.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'LabOS with AI assistant', 'HealthTech', 'Series A', '$8M', NULL, NULL, NULL, 'Global / Remote', 'life sciences,lab operations,lims,inventory,ai assistant', 'Avenue Growth Partners', '{"careers": "https://www.scispot.com/careers"}', 1, 'scispot.webp', 'ready', 'published', 'manual', '2026-06-05 05:53:18', '2026-06-05 05:53:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-scotch', 'scotch', 'scotchpos.com', 'https://scotchpos.com/', 'Scotch', 'Liquor-retail POS and back office for inventory, invoices, ordering, and payments.', 'Liquor stores are a better wedge than generic retail sounds. Scotch starts with case breaks, 30-distributor invoices, offline checkout, age checks, ordering, receiving, and margin dashboards. Unlike restaurant POS software retrofitted for bottle shops, it encodes the awkward unit economics of liquor retail. The risk is whether a vertical POS can keep its edge once incumbents copy the obvious workflows.', '{"verified_at": "2026-06-05", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://scotchpos.com/", "type": "official"}, {"id": "product_page", "label": "Liquor store POS product page", "url": "https://scotchpos.com/liquor-store-pos-system/", "type": "product"}, {"id": "funding_1", "label": "Scotch Series A announcement", "url": "https://www.prnewswire.com/news-releases/scotch-raises-20m-series-a-to-modernize-liquor-stores-surpasses-1b-in-payment-volume-302790781.html", "type": "funding"}], "product_evidence": [{"claim": "The official site presents POS, payments, inventory, ordering, receiving, analytics, invoice reading, and offline selling as core surfaces.", "source_ids": ["official_site"]}, {"claim": "The liquor-store product page describes case-break tracking, distributor invoice automation, shrinkage reports, age verification, and AI ordering tools.", "source_ids": ["product_page"]}], "market_context": {"primary_user": "Independent and multi-store liquor retailers managing high-SKU inventory, checkout, compliance, and distributor workflows.", "category": "SaaS", "differentiation": "Scotch narrows POS around liquor-specific units, invoices, compliance, and ordering instead of broad restaurant or general-retail workflows.", "why_now": "The June 2026 Series A follows more than $1B in annual gross payment volume and gives the company capital to expand a vertical retail operating system."}, "risks": [{"claim": "The open question is whether vertical depth remains durable if broad POS incumbents clone the highest-value liquor workflows.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Liquor-specific POS', 'SaaS', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'retail,pos,liquor stores,inventory,payments', 'VMG Partners', NULL, 1, 'scotch.webp', 'ready', 'published', 'manual', '2026-06-05 05:53:18', '2026-06-05 05:53:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-scout-space', 'scout-space', 'www.scout.space', 'https://www.scout.space', 'Scout Space', 'In-space sensors and autonomy software for orbital awareness.', 'The sharp part is that space awareness needs distributed eyes in orbit, not only bigger ground systems. Scout Space sells Owl sensors, mission autonomy software, edge processing, and data tools for operators, and this round funds a 2,600-square-foot Virginia facility. Compared with a pure satellite builder, it is trying to become the sensing layer other spacecraft can carry. The risk is that government demand may hide how repeatable the commercial workflow is.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.scout.space", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/scout-space-raises-18m-series-a-to-scale-space-domain-awareness-capabilities-and-expand-manufacturing-in-northern-virginia-302760326.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Scout Space: In-space sensors and autonomy software for orbital awareness.", "source_ids": ["official_site"]}, {"claim": "Scout Space sells Owl sensors, mission autonomy software, edge processing, and data tools for operators, and this round funds a 2,600-square-foot Virginia facility.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "$18M Series A for orbital sensors", "why_now": "Recent source-backed funding and public product evidence make space, orbital awareness, sensors worth tracking."}, "risks": [{"claim": "The risk is that government demand may hide how repeatable the commercial workflow is.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$18M Series A for orbital sensors', 'Other', 'Series A', '$18M', NULL, NULL, NULL, 'US', 'space,orbital awareness,sensors,autonomy', 'Washington Harbour Partners, Virginia Innovation Partnership Corporation, Noblis Ventures, Decisive Point, Fusion Fund', '{"linkedin": "https://www.linkedin.com/company/scoutdotspace", "careers": "https://www.scout.space/careers"}', 1, 'scout-space.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-sea12', 'sea12', 'www.sea12.co', 'https://www.sea12.co/', 'Sea12', 'AI workflow orchestration platform for heavy-industry back-office operations.', 'The interesting part is the refusal to sell another chat layer to heavy industry. Sea12 Orchestrator connects enterprise data, turns natural-language requests into tasks, and publishes docs for schemas, processes, triggers, and data flow. The steel-order quickstart is a good signal: the product is aimed at quoting, invoices, and departmental work that usually sits in email and spreadsheets. The risk is whether custom services hide how much of the platform is repeatable.', '{"verified_at": "2026-06-23", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.sea12.co/", "type": "official"}, {"id": "official_docs", "label": "Sea12 documentation", "url": "https://docs.sea12.co/docs/quickstart", "type": "official"}, {"id": "funding_1", "label": "The SaaS News Series A coverage", "url": "https://www.thesaasnews.com/news/sea12-raises-25m-series-a/", "type": "funding"}, {"id": "funding_2", "label": "citybiz company profile", "url": "https://www.citybiz.co/article/863009/sea12-gains-25m-to-push-back-office-ai-operations/", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Sea12 Orchestrator as workflow orchestration that integrates data across the enterprise to automate departmental flows for construction, logistics, manufacturing, and facilities management.", "source_ids": ["official_site"]}, {"claim": "The official documentation exposes product concepts including schemas, processes, nodes, execution, triggers, authentication, testing, collections, and API reference.", "source_ids": ["official_docs"]}, {"claim": "The quickstart walks through a steel order quoting system that monitors Gmail, extracts structured order data, calculates a quote, and replies to the same thread.", "source_ids": ["official_docs"]}], "market_context": {"primary_user": "Operations leaders in steel, construction, logistics, manufacturing, and facilities management teams with document-heavy back offices.", "category": "Workflow automation", "differentiation": "Sea12 focuses on departmental workflows in heavy industry instead of generic chat, with a product model that combines schemas, processes, triggers, and integrations.", "why_now": "LLM extraction and workflow tooling can now turn email, invoices, quotes, and internal documents into repeatable operations for sectors that still rely on manual back-office routing."}, "risks": [{"claim": "The open question is whether early custom-services work has become a repeatable platform rather than bespoke automation sold one customer at a time.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$25M Series A, heavy-industry ops', 'SaaS', 'Series A', '$25M', 2024, NULL, 'New York', 'US', 'workflow automation,industrial ops,documents,ai agents,back office', 'Caffeinated Capital', '{"careers": "https://www.sea12.co/careers"}', 1, 'sea12.webp', 'ready', 'published', 'manual', '2026-06-23 05:54:27', '2026-06-23 05:54:27') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-secludy', 'secludy', 'secludy.com', 'https://secludy.com', 'Secludy', 'Privacy-safe synthetic data for regulated AI training.', 'The bet is that regulated AI teams need usable fake data, not another masking rulebook. Secludy shows differential-privacy presets, text and table anonymization examples, canary PII leakage tests, self-hosted VPC/on-prem deployment, and a claimed under-1-hour setup. Unlike legacy masking, it tries to preserve model utility while moving sensitive records out of scope. The risk is that privacy budgets become another specialist bottleneck.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://secludy.com", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/13/3294051/0/en/secludy-raises-4m-to-safely-unlock-proprietary-data-for-genai.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Secludy: Privacy-safe synthetic data for regulated AI training.", "source_ids": ["official_site"]}, {"claim": "Secludy shows differential-privacy presets, text and table anonymization examples, canary PII leakage tests, self-hosted VPC/on-prem deployment, and a claimed under-1-hour setup.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$4M seed for DP synthetic data", "why_now": "Recent source-backed funding and public product evidence make synthetic data, privacy, ai training worth tracking."}, "risks": [{"claim": "The risk is that privacy budgets become another specialist bottleneck.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$4M seed for DP synthetic data', 'AI / ML', 'Seed', '$4M', NULL, NULL, NULL, 'US', 'synthetic data,privacy,ai training,regulated data', 'Impression Ventures', NULL, 1, 'secludy.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-sekai', 'sekai', 'sekaiapp.com', 'https://sekaiapp.com/about', 'Sekai', 'AI-powered interactive mini-app platform for create-play-remix content.', 'The bet is that AI app creation becomes a consumer content format, not just a developer tool. Sekai lets users create, play, and remix mini apps from prompts, with iOS and Android distribution plus public examples like quizzes, cards, and utilities. Unlike web IDEs that end at deploy, it ties generation to social reuse. The risk is whether 15M creations convert into durable creator behavior after novelty fades.', '{"verified_at": "2026-06-02", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://sekaiapp.com/about", "type": "official"}, {"id": "funding_1", "label": "Axios", "url": "https://www.axios.com/2026/06/01/sekai-mini-app-startup-funding", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Sekai as an AI-powered platform where users create, play, and remix interactive mini-apps that open instantly from shared links.", "source_ids": ["official_site"]}, {"claim": "The product page shows iOS and Android distribution plus examples of playable mini-apps, app-store reviews, and community remix behavior.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Mobile creators and consumers who want to generate and share playable interactive content.", "category": "Creator Tools", "differentiation": "Prompted generation is tied to playable, shareable mini-apps rather than static media or developer-only app builders.", "why_now": "The June 2026 Series A comes as consumer AI creation shifts from text and images toward generated interactive experiences."}, "risks": [{"claim": "The open question is whether mini-app creation produces durable creator retention after early novelty and viral sharing effects fade.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Prompted mini-app creation', 'Creator Tools', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'mini apps,creator tools,ai generation,mobile apps,remix', 'Khosla Ventures, Connect Ventures', '{"careers": "https://sekaiapp.com/careers"}', 1, 'sekai.webp', 'ready', 'published', 'manual', '2026-06-02 05:53:31', '2026-06-02 05:53:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-seltz', 'seltz', 'seltz.ai', 'https://seltz.ai/', 'Seltz', 'Web-knowledge API that returns source-backed context for AI agents.', 'The sharp bet is that AI agents need search results shaped for machines, not blue links for people. Seltz exposes Python, Node, and cURL quickstarts, ranks passages instead of pages, and says it owns the crawler, index, retrieval models, and ranking stack. Compared with SERP APIs or brittle scrapers, the wager is full-pipeline control for fresh, citable context. The risk is whether a small team can keep enough coverage against Google, Exa, Parallel, and lab-owned crawlers.', '{"verified_at": "2026-06-25", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://seltz.ai/", "type": "official"}, {"id": "official_docs", "label": "Seltz documentation", "url": "https://docs.seltz.ai/", "type": "product"}, {"id": "funding_1", "label": "Fortune seed funding report", "url": "https://fortune.com/2026/06/24/exclusive-seltz-a-startup-rebuilding-web-search-for-ai-agents-raises-12-5-million-in-seed-funding/", "type": "funding"}], "product_evidence": [{"claim": "The homepage describes a Web Knowledge API for AI agents and exposes a direct Try the API call to action.", "source_ids": ["official_site"]}, {"claim": "The official quickstart shows Python, Node, and cURL examples for querying the web knowledge endpoint and returning context with source URLs.", "source_ids": ["official_site", "official_docs"]}, {"claim": "The FAQ says Seltz differs from SERP APIs and scraping tools by controlling crawling, indexing, retrieval models, passage ranking, and context packaging for LLM apps.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI infrastructure teams building agents, RAG systems, research workflows, and LLM applications that need fresh web context with citations.", "category": "AI search infrastructure", "differentiation": "Seltz sells machine-shaped context rather than search-result pages, with its own crawler, index, retrieval model, and passage-ranking layer.", "why_now": "Agent builders need current web evidence at inference time, while consumer search pages, scraping stacks, and raw SERP APIs are awkward inputs for automated reasoning."}, "risks": [{"claim": "The open question is whether Seltz can maintain enough index freshness, coverage, and source quality against larger search incumbents and AI-lab-owned crawlers.", "basis": "VentureDex editorial assessment based on the official product surface and funding-source review."}]}', 4, '$12.5M Seed for agent search', 'DevTools', 'Seed', '$12.5M', NULL, NULL, NULL, 'Europe', 'ai agents,search api,web data,retrieval,rag', 'B Capital', '{"github": "https://github.com/seltz-ai/", "linkedin": "https://www.linkedin.com/company/seltz/", "twitter": "https://x.com/seltz_ai", "careers": "https://seltz-ai.notion.site/careers-at-seltz"}', 1, 'seltz.webp', 'ready', 'published', 'manual', '2026-06-25 05:55:07', '2026-06-25 05:55:07') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shapes', 'shapes', 'talk.shapes.inc', 'https://talk.shapes.inc', 'Shapes', 'Social AI chat app where people and bots share group conversations.', 'Most AI companion apps trap users in one-on-one confession booths; this points the format back toward messy group chat. The public surface shows 300+ models, message counts like 86.8K on individual characters, and mobile app links instead of a blank waitlist. That choice makes AI feel closer to Discord roleplay than a therapist clone. The hard part is moderation: social AI gets more interesting exactly where it gets harder to keep safe.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://talk.shapes.inc", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/29/meet-shapes-the-app-bringing-humans-and-ai-into-the-same-group-chats/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Shapes: Social AI chat app where people and bots share group conversations.", "source_ids": ["official_site"]}, {"claim": "Most AI companion apps trap users in one-on-one confession booths; this points the format back toward messy group chat.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "AI companions in group chat", "why_now": "Recent source-backed funding and public product evidence make social ai, chat, consumer worth tracking."}, "risks": [{"claim": "The hard part is moderation: social AI gets more interesting exactly where it gets harder to keep safe.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI companions in group chat', 'AI / ML', 'Seed', '$8M', 2023, '10-30', 'San Francisco', 'US', 'social ai,chat,consumer,ai companions', 'Lightspeed Venture Partners, Betaworks, Hartbeat Ventures, The Games Fund', '{"careers": "https://shapes.inc/jobs"}', 1, 'shapes.webp', 'ready', 'published', 'manual', '2026-05-02 09:59:18', '2026-05-02 09:59:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shyld-ai', 'shyld-ai', 'www.shyld.ai', 'https://www.shyld.ai', 'Shyld AI', 'Physical AI agents for hospital operations and disinfection.', 'The real bet is that hospital AI should act in the room, not sit in the chart. Shyld AI shows 3D LiDAR, radar, infrared sensing, edge GPUs, UV-C cycles, and a Stanford-linked 93% contamination reduction claim. Unlike ambient scribes, this is physical AI that changes OR turnover and infection-control workflows. The risk is whether hospital deployment speed matches the clinical evidence.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.shyld.ai", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/14/3295222/0/en/shyld-ai-raises-13-4m-to-expand-active-ai-across-u-s-hospitals.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Shyld AI: Physical AI agents for hospital operations and disinfection.", "source_ids": ["official_site"]}, {"claim": "Shyld AI shows 3D LiDAR, radar, infrared sensing, edge GPUs, UV-C cycles, and a Stanford-linked 93% contamination reduction claim.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "93% contamination reduction", "why_now": "Recent source-backed funding and public product evidence make hospital operations, physical ai, infection control worth tracking."}, "risks": [{"claim": "The risk is whether hospital deployment speed matches the clinical evidence.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '93% contamination reduction', 'HealthTech', 'Seed', '$13.4M', NULL, NULL, NULL, 'US', 'hospital operations,physical ai,infection control,edge ai', 'Aulis Capital', NULL, 1, 'shyld-ai.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-socket', 'socket', 'socket.dev', 'https://socket.dev', 'Socket', 'Supply-chain security that blocks malicious open-source packages before install.', 'The interesting bet is moving supply-chain defense into the package-install path instead of another alert queue. Socket ships a GitHub app, CLI firewall, and reachability analysis that can block malicious npm packages before they land. Unlike SCA tools that mostly rank CVEs, it treats package behavior as the product surface. The risk is whether security teams trust a blocker in every developer workflow.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://socket.dev", "type": "official"}, {"id": "funding_1", "label": "Cooley", "url": "https://www.cooley.com/news/coverage/2026/2026-05-20-socket-raises-%2460-million-series-c-at-%241-billion-valuation", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Socket: Supply-chain security that blocks malicious open-source packages before install.", "source_ids": ["official_site"]}, {"claim": "Socket ships a GitHub app, CLI firewall, and reachability analysis that can block malicious npm packages before they land.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Install-time package firewall", "why_now": "Recent source-backed funding and public product evidence make cybersecurity, developer tools, supply chain worth tracking."}, "risks": [{"claim": "The risk is whether security teams trust a blocker in every developer workflow.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Install-time package firewall', 'DevTools', 'Series C', '$60M', NULL, NULL, NULL, 'US', 'cybersecurity,developer tools,supply chain,open source', 'Thrive Capital', NULL, 1, 'socket.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-stilta', 'stilta', 'www.stilta.com', 'https://www.stilta.com', 'Stilta', 'AI agents for patent invalidity, infringement, and freedom-to-operate analysis.', 'The smart move is treating patent analysis as evidence mapping, not legal chat. Stilta breaks work into infringement, invalidity, and FTO modules, then maps claim elements to patents, scientific literature, and archived web sources. Unlike generic legal copilots, it narrows the agent to questions attorneys already know how to audit. The risk is whether benchmark recall survives hostile expert review.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.stilta.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/19/legal-tech-announced-stilta-announces-10m-seed-backed-by-yc-and-a16z-months-after-launch/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Stilta: AI agents for patent invalidity, infringement, and freedom-to-operate analysis.", "source_ids": ["official_site"]}, {"claim": "Stilta breaks work into infringement, invalidity, and FTO modules, then maps claim elements to patents, scientific literature, and archived web sources.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Patent claim evidence maps", "why_now": "Recent source-backed funding and public product evidence make legal tech, patents, ai agents worth tracking."}, "risks": [{"claim": "The risk is whether benchmark recall survives hostile expert review.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Patent claim evidence maps', 'AI / ML', 'Seed', '$10.5M', NULL, NULL, NULL, 'Europe', 'legal tech,patents,ai agents,litigation', 'Andreessen Horowitz, Y Combinator', NULL, 1, 'stilta.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-stitch', 'stitch', 'www.stitch.co', 'https://www.stitch.co', 'Stitch', 'Financial infrastructure OS for banks and fintechs.', 'The interesting move is treating bank modernization as a system-of-record problem, not a prettier payments API. Stitch exposes lending, cards, deposits, ledgers, applications, and live loan UI states, with $5B transacted in six months. Unlike point fintech rails, the bet is one stack that can be adopted module by module. The hard part is selling core infrastructure without inheriting every legacy edge case.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.stitch.co", "type": "official"}, {"id": "funding_1", "label": "Stitch", "url": "https://www.stitch.co/press/stitch-raises-25m-series-a-led-by-andreessen-horowitz", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Stitch: Financial infrastructure OS for banks and fintechs.", "source_ids": ["official_site"]}, {"claim": "Stitch exposes lending, cards, deposits, ledgers, applications, and live loan UI states, with $5B transacted in six months.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$5B transacted in six months", "why_now": "Recent source-backed funding and public product evidence make financial infrastructure, core banking, ledgers worth tracking."}, "risks": [{"claim": "The hard part is selling core infrastructure without inheriting every legacy edge case.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$5B transacted in six months', 'Fintech', 'Series A', '$25M', NULL, NULL, NULL, 'Global / Remote', 'financial infrastructure,core banking,ledgers,cards,lending', 'Andreessen Horowitz', '{"careers": "https://www.stitch.co/careers"}', 1, 'stitch.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-stratusgrid', 'stratusgrid', 'stratusgrid.com', 'https://stratusgrid.com/', 'StratusGrid', 'Multi-agent platform that verifies and executes cloud infrastructure optimizations.', 'Cloud cost tools usually stop at dashboards; this one wants permission to change the infra. Stratusphere shows AWS/Azure agents, policy simulation, blast-radius analysis, rollback, audit trails, and executive P&L dashboards. Unlike FinOps reporting that leaves engineers with tickets, the bet is verified execution under guardrails. The question is whether enterprises let it close the loop.', '{"verified_at": "2026-06-13", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://stratusgrid.com/", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/stratusgrid-raises-3m-seed-round-to-advance-ai-driven-cloud-infrastructure-optimization-302788056.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Stratusphere as a multi-agent platform that observes environments, simulates plans under policy, and executes safe changes across AWS and Azure.", "source_ids": ["official_site"]}, {"claim": "The official product copy shows closed-loop opportunity surfacing, approval, execution, rollback, auditability, blast-radius analysis, and executive dashboards for cloud savings and risk reduction.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Stratusphere identifies, approves, executes, and verifies cloud infrastructure optimizations.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Cloud platform, FinOps, security, and engineering leaders trying to turn cloud recommendations into safe production changes.", "category": "DevTools", "differentiation": "StratusGrid positions the product around policy-safe execution and verification rather than visibility-only optimization dashboards.", "why_now": "AI workloads are increasing infrastructure cost and change complexity, making verified cloud optimization a sharper problem than another reporting layer."}, "risks": [{"claim": "Outcome-based cloud automation depends on customers trusting the approval and rollback loop enough to let agents make real infrastructure changes.", "basis": "VentureDex editorial assessment based on official product evidence and the funding source''s emphasis on verified execution."}]}', 4, '$3M seed for cloud agents', 'DevTools', 'Seed', '$3M', NULL, NULL, NULL, 'US', 'cloud infrastructure,finops,ai agents,devops,automation', 'Dogwood Ventures', '{"careers": "https://stratusgrid.com/careers"}', 1, 'stratusgrid.webp', 'ready', 'published', 'manual', '2026-06-13 05:49:00', '2026-06-13 05:49:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-structured-ai', 'structured-ai', 'getstructured.ai', 'https://getstructured.ai/', 'Structured AI', 'AI drawing-review agents for construction QA/QC, code checks, and coordination gaps.', 'Construction AI often chases jobsite cameras; this starts where errors are cheaper: the PDF drawing set. Structured AI scans 2D construction documents for clashes, code gaps, dimensions, specs, and RFI-ready fixes before a senior engineer reviews them. The bet is spell-check for MEP and structural plans, not another project dashboard. The risk is adoption friction inside firms already standardized on Bluebeam/Revit/Procore.', '{"verified_at": "2026-06-15", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://getstructured.ai/", "type": "official"}, {"id": "official_compare", "label": "Official comparison page", "url": "https://getstructured.ai/compare/", "type": "official"}, {"id": "official_blog", "label": "Official seed announcement", "url": "https://getstructured.ai/blog/structured-ai-4-2m-seed-round/", "type": "official"}, {"id": "yc_company", "label": "Y Combinator company profile", "url": "https://www.ycombinator.com/companies/structured-ai", "type": "official"}, {"id": "funding_1", "label": "ENR funding report", "url": "https://www.enr.com/articles/63139-construction-quality-startup-structured-ai-raises-42m-seed-round", "type": "funding"}], "product_evidence": [{"claim": "The official site describes automated construction drawing review for QA/QC, coordination issues, code concerns, and senior-engineer review workflows.", "source_ids": ["official_site"]}, {"claim": "The comparison page says the product works directly from 2D PDFs, without a BIM model or platform migration, and supports 2D clash detection, code compliance, RFI generation, revision comparison, dimensional verification, and specification analysis.", "source_ids": ["official_compare"]}, {"claim": "The official seed announcement says Structured AI caught more than 400 issues in a 1,000-page drawing set and traces findings back to code citations, drawing pages, and locations.", "source_ids": ["official_blog"]}, {"claim": "The YC profile describes the company as an AI workforce for construction design engineering focused on QA/QC over technical documents and drawings.", "source_ids": ["yc_company"]}], "market_context": {"primary_user": "Construction engineers, design reviewers, MEP coordinators, and QA/QC teams reviewing drawing sets before construction.", "category": "Construction Technology", "differentiation": "Structured AI focuses on pre-construction document intelligence, scanning ordinary PDF drawing sets and routing findings into familiar Bluebeam, Revit, Procore, Autodesk Construction Cloud, SharePoint, and Google Drive workflows.", "why_now": "Construction teams are under pressure to catch coordination and compliance errors earlier while drawing volumes and revision cycles keep growing."}, "risks": [{"claim": "The open question is whether teams already standardized on Bluebeam, Revit, Procore, and Autodesk workflows will trust AI-generated findings enough to change QA habits.", "basis": "VentureDex editorial assessment based on official product evidence, official seed materials, and current funding coverage."}]}', 4, '$4.2M seed for drawing QA', 'SaaS', 'Seed', '$4.2M', NULL, NULL, NULL, 'US', 'construction,ai agents,qa,qc,drawing review,compliance', 'FCVC, Y Combinator', '{"careers": "https://getstructured.ai/careers/"}', 1, 'structured-ai.webp', 'ready', 'published', 'manual', '2026-06-15 05:52:33', '2026-06-15 05:52:33') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-subtle-medical', 'subtle-medical', 'subtlemedical.com', 'https://subtlemedical.com/', 'Subtle Medical', 'AI medical-imaging software that accelerates MRI and PET acquisition workflows.', 'Radiology AI is useful only when it changes scanner throughput, not when it adds another viewer. Subtle Medical’s public site shows vendor-neutral MRI and PET software, SubtleHD(MR), SubtleSYNTH, SubtleALIGN, and SubtleHD(PET), with scan-time claims up to 80%. Unlike a single-model radiology point tool, it is building an imaging layer across acquisition and enhancement workflows. The risk is regulatory and hospital rollout drag as the platform expands across MRI, PET, and CT.', '{"verified_at": "2026-06-07", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://subtlemedical.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://subtlemedical.com/careers/", "type": "official"}, {"id": "funding_1", "label": "Subtle Medical Series C announcement", "url": "https://www.prnewswire.com/news-releases/subtle-medical-secures-33-million-in-growth-capital-led-by-morgan-stanley-expansion-capital-and-appoints-industry-veteran-ohad-arazi-as-ceo-302788005.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes vendor-neutral AI software for MRI and PET, including SubtleHD(MR), SubtleSYNTH, SubtleALIGN, SubtleHD(PET), AiMIFY, and SubtleGAD.", "source_ids": ["official_site"]}, {"claim": "The public site shows before-and-after imaging examples and scan-time reduction claims, including up to 80% faster MRI workflows.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Subtle Medical is deployed on more than 1,300 scanners across hospitals and imaging centers globally.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Radiology departments, imaging-center operators, and health systems trying to improve scanner throughput and image quality.", "category": "HealthTech", "differentiation": "Subtle Medical works as an acquisition and image-enhancement layer across existing scanners rather than a replacement imaging workstation.", "why_now": "Imaging backlogs, scanner capacity constraints, and enterprise demand for clinically validated AI make acceleration software newly strategic."}, "risks": [{"claim": "The open question is whether regulatory coverage, hospital procurement cycles, and modality expansion slow adoption as the platform moves across MRI, PET, and CT.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'MRI scans up to 80% faster', 'HealthTech', 'Series C', '$33M', NULL, NULL, NULL, 'US', 'radiology,medical imaging,ai software,mri,pet', 'Morgan Stanley Expansion Capital', '{"careers": "https://subtlemedical.com/careers/"}', 1, 'subtle-medical.webp', 'ready', 'published', 'manual', '2026-06-07 06:05:50', '2026-06-07 06:05:50') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-supabase', 'supabase', 'supabase.com', 'https://supabase.com', 'Supabase', 'The open source Firebase alternative.', 'The clever part is not calling itself an open-source Firebase alternative. The clever part is turning Postgres into the center of an entire developer stack: auth, storage, realtime, and edge functions. Where most backend platforms hide the database behind abstractions, Supabase leans into it. That makes the product more opinionated and easier to reason about than a generic backend cloud.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://supabase.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2022/05/10/supabase-raises-80m-series-b-for-its-open-source-firebase-alternative/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Supabase: The open source Firebase alternative.", "source_ids": ["official_site"]}, {"claim": "Where most backend platforms hide the database behind abstractions, Supabase leans into it.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Postgres as a platform", "why_now": "Recent source-backed funding and public product evidence make database, open source, backend worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Postgres as a platform', 'DevTools', 'Series B', '$80M', 2020, '100-200', 'Singapore', 'Global / Remote', 'database,open source,backend,postgres,firebase alternative', 'Felicis Ventures, Coatue Management, Y Combinator', '{"github": "https://github.com/supabase", "twitter": "https://x.com/supabase", "linkedin": "https://linkedin.com/company/supabase", "careers": "https://supabase.com/careers"}', 0, 'supabase.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-synera', 'synera', 'www.synera.io', 'https://www.synera.io', 'Synera', 'Agent platform for engineering workflows across CAD, FEA, costing, and reporting tools.', 'The interesting bet is that engineers do not need another copilot; they need a workbench where agents can operate CAD, FEA, cost, and reporting tools. Synera connects 80+ hardware-engineering systems with a node-based editor, 3D viewer, custom nodes, Python scripts, and token licensing. Unlike generic AI-for-manufacturing pitches, this starts from the messy CAx toolchain. The risk is that enterprise deployment turns the agents into services work.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.synera.io", "type": "official"}, {"id": "funding_1", "label": "Synera", "url": "https://www.synera.io/press/synera-raises-40m-series-b-to-scale-agentic-ai-engineering-for-global-manufacturers", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Synera: Agent platform for engineering workflows across CAD, FEA, costing, and reporting tools.", "source_ids": ["official_site"]}, {"claim": "Synera connects 80+ hardware-engineering systems with a node-based editor, 3D viewer, custom nodes, Python scripts, and token licensing.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Agents across 80+ engineering tools", "why_now": "Recent source-backed funding and public product evidence make engineering, ai agents, cad worth tracking."}, "risks": [{"claim": "The risk is that enterprise deployment turns the agents into services work.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Agents across 80+ engineering tools', 'SaaS', 'Series B', '$40M', NULL, NULL, NULL, 'Europe', 'engineering,ai agents,cad,industrial software', 'Revaia', '{"careers": "https://www.synera.io/careers"}', 1, 'synera.webp', 'ready', 'published', 'manual', '2026-05-02 09:59:18', '2026-05-02 09:59:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-taktile', 'taktile', 'www.taktile.com', 'https://www.taktile.com/', 'Taktile', 'Agentic decision platform for regulated banking and insurance workflows.', 'The interesting choice is putting AI agents where mistakes are expensive, then surrounding them with rules and review. Taktile shows Agent Manager, Decision Engine, Case Manager, Context Layer, KYC, onboarding, credit, AML, fraud, underwriting, claims, traceability, and third-party data integrations. Compared with generic copilots, the bet is auditable agents for regulated decisions. The risk is whether banks let autonomous workflows cross from recommendations into approvals.', '{"verified_at": "2026-06-25", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.taktile.com/", "type": "official"}, {"id": "official_announcement", "label": "Taktile Series C announcement", "url": "https://taktile.com/articles/taktile-secures-110m-in-goldman-sachs-led-series-c-to-power-ai-transformation-in-financial-institutions", "type": "official"}, {"id": "official_docs", "label": "Taktile product documentation", "url": "https://docs.taktile.com/", "type": "product"}, {"id": "funding_1", "label": "Fortune Series C funding report", "url": "https://fortune.com/2026/06/24/exclusive-taktile-goldman-sachs-ai-bank-insurance-funding/", "type": "funding"}], "product_evidence": [{"claim": "The official product navigation exposes AI Agent Manager, Decision Engine, Case Manager, Data Orchestration, Enterprise-Grade Infrastructure, Agent Library, and Data Marketplace modules.", "source_ids": ["official_site"]}, {"claim": "The site maps Taktile to banking and insurance workflows including onboarding, credit, AML and compliance, fraud, underwriting, and claims.", "source_ids": ["official_site", "official_announcement"]}, {"claim": "The announcement says customers combine AI agents, rules, context, and human oversight to automate decisions, with Mercury, Monzo, Faire, and Pleo cited as customers.", "source_ids": ["official_announcement"]}], "market_context": {"primary_user": "Financial-services risk, credit, fraud, compliance, insurance, and operations teams that need controlled decision automation.", "category": "Financial decision automation", "differentiation": "Taktile packages agents, rules, context, data integrations, case review, and traceability for high-liability financial workflows rather than broad employee productivity.", "why_now": "Banks and insurers are moving from AI pilots toward production workflows, but regulated decisions still require explainability, review, and auditable controls."}, "risks": [{"claim": "The open question is how quickly regulated customers will allow autonomous workflows to move from recommendations into approvals and customer-facing outcomes.", "basis": "VentureDex editorial assessment based on the official product surface and funding-source review."}]}', 4, '$110M Series C for decision AI', 'Fintech', 'Series C', '$110M', NULL, NULL, NULL, 'Europe', 'financial services,decisioning,ai agents,aml,underwriting', 'Goldman Sachs Alternatives', '{"linkedin": "https://www.linkedin.com/company/taktile1/", "twitter": "https://twitter.com/taktileorg", "careers": "https://www.taktile.com/careers"}', 1, 'taktile.webp', 'ready', 'published', 'manual', '2026-06-25 05:55:07', '2026-06-25 05:55:07') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-terra-ai', 'terra-ai', 'www.terraai.com', 'https://www.terraai.com/', 'Terra AI', 'Frontier AI platform for subsurface exploration decisions.', 'The bet is that natural-resource exploration should price uncertainty before it drills. Terra AI gives mining and reservoir teams a model-driven way to quantify subsurface risk, compare exploration paths, and ask sharper economic questions. Unlike generic geospatial dashboards, it narrows AI to the expensive moment where a wrong drill target burns capital. The risk is whether proprietary field data coverage keeps pace with customer expectations.', '{"verified_at": "2026-06-04", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.terraai.com/", "type": "official"}, {"id": "funding_1", "label": "Terra AI Series A announcement", "url": "https://www.terraai.com/blog-post/building-the-ai-native-platform-for-subsurface-modeling", "type": "funding"}], "product_evidence": [{"claim": "The official site says Terra AI works with mining and reservoir companies to accelerate subsurface exploration.", "source_ids": ["official_site"]}, {"claim": "The product copy emphasizes quantifying exploration uncertainty and supporting economic decisions before teams commit capital.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Mining, reservoir, geothermal, and carbon-storage teams making capital-intensive exploration decisions.", "category": "AI / ML", "differentiation": "Terra AI focuses on uncertainty modeling and project economics for subsurface teams rather than broad geospatial visualization.", "why_now": "The June 2026 Series A arrives as critical-mineral, energy, geothermal, and carbon-storage projects demand better early exploration decisions."}, "risks": [{"claim": "The open question is whether proprietary field-data coverage can keep pace with customer expectations across resource types.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Subsurface uncertainty engine', 'AI / ML', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'natural resources,subsurface ai,mining,reservoirs,exploration', 'Khosla Ventures', '{"careers": "https://www.terraai.com/careers"}', 1, 'terra-ai.webp', 'ready', 'published', 'manual', '2026-06-04 05:59:59', '2026-06-04 05:59:59') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-texture', 'texture', 'www.texturehq.com', 'https://www.texturehq.com', 'Texture', 'Grid operating system for DER visibility, dispatch, telemetry, and settlements.', 'The smart bet is making grid operations a live data system instead of another utility dashboard. Texture models source AMI and SCADA data across devices, meters, transformers, and feeders, then runs dispatch, telemetry, notifications, and settlement workflows. Unlike generic climate SaaS, the product is tied to utility operations and VPP fleets. The risk is integration drag across every local grid stack.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.texturehq.com", "type": "official"}, {"id": "funding_1", "label": "Texture", "url": "https://www.texturehq.com/blog/texture-series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Texture: Grid operating system for DER visibility, dispatch, telemetry, and settlements.", "source_ids": ["official_site"]}, {"claim": "Texture models source AMI and SCADA data across devices, meters, transformers, and feeders, then runs dispatch, telemetry, notifications, and settlement workflows.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Climate, infrastructure, or operations teams evaluating measurable sustainability workflows.", "category": "Climate / Sustainability", "differentiation": "Live grid operations OS", "why_now": "Recent source-backed funding and public product evidence make energy, grid operations, climate worth tracking."}, "risks": [{"claim": "The risk is integration drag across every local grid stack.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Live grid operations OS', 'Climate / Sustainability', 'Series A', '$12.5M', NULL, NULL, NULL, 'US', 'energy,grid operations,climate,utility software', 'VoLo Earth Ventures, Equal Ventures', '{"careers": "https://www.texturehq.com/careers"}', 1, 'texture.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-timefold', 'timefold', 'timefold.ai', 'https://timefold.ai/', 'Timefold', 'Scheduling-optimization APIs for routing, shifts, pickups, and task planning.', 'The refreshing choice is to make scheduling a solver API instead of another planner screen. Timefold accepts JSON, returns optimized routes or shifts, and exposes APIs for field service, workforce, pickup-and-delivery, and task scheduling with weighted constraints. Compared with LLM-generated schedules, the bet is deterministic optimization that survives labor rules and disruptions. The risk is whether buyers see it as infrastructure or a feature inside their FSM or WFM suite.', '{"verified_at": "2026-06-24", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://timefold.ai/", "type": "official"}, {"id": "official_docs", "label": "Timefold documentation", "url": "https://docs.timefold.ai/", "type": "product"}, {"id": "official_blog", "label": "Timefold Series A blog post", "url": "https://timefold.ai/blog/timefold-raises-series-a", "type": "official"}, {"id": "funding_1", "label": "Tech.eu Series A report", "url": "https://tech.eu/2026/06/23/timefold-raises-13m-series-a-to-scale-scheduling-optimisation-infrastructure/", "type": "funding"}], "product_evidence": [{"claim": "The homepage describes vehicle-routing and shift-scheduling APIs for field service and workforce management.", "source_ids": ["official_site"]}, {"claim": "The product navigation exposes field-service routing, employee shift scheduling, pickup-and-delivery routing, and task scheduling APIs.", "source_ids": ["official_site", "official_docs"]}, {"claim": "The documentation positions Timefold as an API-driven optimization layer that accepts operational inputs and returns schedules or routes.", "source_ids": ["official_docs"]}], "market_context": {"primary_user": "Software teams embedding routing, workforce scheduling, and operations planning into enterprise applications.", "category": "Developer infrastructure", "differentiation": "Timefold packages constraint-based scheduling as APIs instead of requiring teams to build solver logic or ship another planner UI.", "why_now": "Field service, logistics, and workforce software teams need faster replanning as labor rules, service windows, fuel costs, and customer expectations change in real time."}, "risks": [{"claim": "The open question is whether Timefold becomes a durable infrastructure layer or gets bundled by field-service and workforce suites.", "basis": "VentureDex editorial assessment based on official product docs and funding-source review."}]}', 4, '$13M Series A for solver APIs', 'DevTools', 'Series A', '$13M', NULL, NULL, NULL, 'Europe', 'scheduling,optimization,apis,field service,workforce management', 'Alstin Capital', '{"careers": "https://jobs.timefold.ai/"}', 1, 'timefold.webp', 'ready', 'published', 'manual', '2026-06-24 06:00:32', '2026-06-24 06:00:32') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-trackk', 'trackk', 'trackk.in', 'https://trackk.in', 'Trackk', 'Stock discovery and trading app for first-time Indian investors.', 'Retail investing apps usually hide complexity behind confetti; this one tries to make discovery the product. Trackk shows prompt-based Trackk Nest screeners, IPO verdicts, single-screen trading, SEBI registration, and 4.7/4.6 app-store ratings. Unlike broker clones built for power users, the bet is that first-time Indian investors need explainable search before execution. The risk is whether F&O ambition nudges beginners toward speculation.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://trackk.in", "type": "official"}, {"id": "funding_1", "label": "Entrackr funding report", "url": "https://entrackr.com/news/trading-app-trackk-raises-fresh-funds-from-lightspeed-and-info-edge-ventures-11846086", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Trackk: Stock discovery and trading app for first-time Indian investors.", "source_ids": ["official_site"]}, {"claim": "Trackk shows prompt-based Trackk Nest screeners, IPO verdicts, single-screen trading, SEBI registration, and 4.7/4.6 app-store ratings.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "Seed for Gen Z investing app", "why_now": "Recent source-backed funding and public product evidence make investing, wealthtech, stock discovery worth tracking."}, "risks": [{"claim": "The risk is whether F&O ambition nudges beginners toward speculation.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Seed for Gen Z investing app', 'Fintech', 'Seed', '$3.7M', NULL, NULL, NULL, 'China / Asia', 'investing,wealthtech,stock discovery,fintech,india', 'Lightspeed', NULL, 1, 'trackk.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-trajectory', 'trajectory', 'trajectory.ai', 'https://trajectory.ai/', 'Trajectory', 'Continual-learning platform that turns product usage into better AI behavior.', 'The sharp angle is post-training from live product usage, not another eval dashboard. Trajectory''s 4-step platform instruments customer workflows, captures traces and corrections, and trains improvements back into prompts, harnesses, and models. Unlike static fine-tuning projects, it is framed around Clay, Decagon, and Harvey use cases. The risk is whether continual learning becomes infrastructure or remains bespoke research service work.', '{"verified_at": "2026-06-02", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://trajectory.ai/", "type": "official"}, {"id": "funding_1", "label": "not a company", "url": "https://www.notacompany.com/fundraising-feed/trajectory-raises-15m-seed", "type": "funding"}], "product_evidence": [{"claim": "The official site says Trajectory turns real product usage into AI that continuously improves.", "source_ids": ["official_site"]}, {"claim": "The platform section describes a lightweight SDK that captures traces, corrections, re-prompts, and edits, then helps teams observe, steer, learn, and deploy.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI product teams that need model behavior to improve from live customer workflows.", "category": "AI / ML", "differentiation": "Feedback from actual product usage becomes a continual-learning loop rather than a static evaluation report.", "why_now": "The 2026 seed round backs infrastructure for AI teams moving from launch-time prompting into ongoing behavior improvement."}, "risks": [{"claim": "The open question is whether continual-learning workflows become standard product infrastructure or stay tied to bespoke AI research engagements.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Continual learning from usage', 'AI / ML', 'Seed', '$15M', NULL, NULL, NULL, 'US', 'continual learning,ai infrastructure,product usage,model behavior,agents', 'Conviction', '{"careers": "https://jobs.ashbyhq.com/trajectory"}', 1, 'trajectory.webp', 'ready', 'published', 'manual', '2026-06-02 05:53:31', '2026-06-02 05:53:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-tribal', 'tribal', 'www.gotribal.ai', 'https://www.gotribal.ai/', 'Tribal', 'Metadata-native AI agents for governed enterprise app changes inside systems of record.', 'The sharp bet is that enterprise AI builders need system context before code generation. Tribal maps metadata, permissions, dependencies, and business rules, then wraps changes with approval flows, audit, impact analysis, and 10x backlog claims. Unlike vibe-coding tools, it treats governance as part of the build surface. The risk is whether every customer''s metadata graph becomes a bespoke services project.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.gotribal.ai/", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/20/3298634/0/en/Tribal-Raises-10M-Seed-to-Bring-Context-Aware-AI-Agents-to-Enterprise-Systems.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Tribal: Metadata-native AI agents for governed enterprise app changes inside systems of record.", "source_ids": ["official_site"]}, {"claim": "Tribal maps metadata, permissions, dependencies, and business rules, then wraps changes with approval flows, audit, impact analysis, and 10x backlog claims.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "10x faster backlog work", "why_now": "Recent source-backed funding and public product evidence make enterprise ai, metadata, salesforce worth tracking."}, "risks": [{"claim": "The risk is whether every customer''s metadata graph becomes a bespoke services project.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '10x faster backlog work', 'SaaS', 'Seed', '$10M', NULL, NULL, NULL, 'US', 'enterprise ai,metadata,salesforce,governance', 'Team8', NULL, 1, 'tribal.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-triomics', 'triomics', 'triomics.com', 'https://triomics.com/', 'Triomics', 'Oncology AI platform for trial matching, visit prep, and cancer-center workflows.', 'The useful bet is that oncology AI should live inside the chart, not beside it. Triomics screens every visit against every trial, cites matches back to pathology and note evidence, drafts visit notes in physician formats, and reports 70% less record-review time in case studies. Unlike generic clinical copilots, it is aimed at cancer-center workflows. The risk is whether hospital deployment pace can match the product ambition.', '{"verified_at": "2026-05-31", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://triomics.com/", "type": "official"}, {"id": "cancer_centers", "label": "Triomics cancer-center product page", "url": "https://triomics.com/cancer-centers", "type": "product"}, {"id": "resources", "label": "Triomics resources page", "url": "https://triomics.com/resources", "type": "product"}, {"id": "funding_1", "label": "TechCrunch Series B report", "url": "https://techcrunch.com/2026/05/27/triomics-nabs-22m-to-bring-oncology-specific-ai-to-cancer-centers/", "type": "funding"}], "product_evidence": [{"claim": "The official site presents oncology workflows for trial matching, visit prep, chart review, patient summaries, and cancer-center operations.", "source_ids": ["official_site", "cancer_centers"]}, {"claim": "Triomics case-study content reports 70% less time per patient record for trial matching, with matches cited back to pathology, biomarkers, and notes.", "source_ids": ["resources"]}, {"claim": "The funding source says Triomics automates clinical trial matching, appointment prep, and cancer registry reporting for cancer centers.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Cancer centers, oncologists, clinical-trial teams, and oncology administrators handling dense patient records.", "category": "HealthTech", "differentiation": "Oncology-specific workflow automation and cited chart evidence instead of generic clinical summarization.", "why_now": "The May 27, 2026 Series B led by Battery Ventures funds adoption of oncology AI across health systems and cancer networks."}, "risks": [{"claim": "The risk is whether hospital deployment cycles, EHR integration, and clinical validation keep pace with oncology-workflow demand.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Cancer-trial workflow AI', 'HealthTech', 'Series B', '$22M', NULL, NULL, NULL, 'US', 'oncology,clinical trials,health ai,ehr,care workflows', 'Battery Ventures', '{"cancer_centers": "https://triomics.com/cancer-centers", "resources": "https://triomics.com/resources", "careers": "https://triomics.com/careers"}', 1, 'triomics.webp', 'ready', 'published', 'manual', '2026-05-31 06:05:47', '2026-05-31 06:05:47') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-truefan-ai', 'truefan-ai', 'truefan.ai', 'https://truefan.ai/', 'TrueFan AI', 'Enterprise AI video platform for avatar-led personalized campaigns and training.', 'Personalized video is usually a services bottleneck, not a software habit. TrueFan AI publishes a studio login, enterprise campaign pages, and BFSI workflows for lead generation, referrals, training, and retention across 175+ languages from one recording. Unlike generic avatar demos, it anchors the pitch in SOC 2 and ISO 27001 claims. The risk is whether brand teams treat the output as production-grade.', '{"verified_at": "2026-06-06", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://truefan.ai/", "type": "official"}, {"id": "studio_login", "label": "TrueFan Studio login", "url": "https://studio.truefan.in/login", "type": "product"}, {"id": "bfsi_page", "label": "BFSI industry product page", "url": "https://truefan.ai/industry/powering-the-full-bfsi-journey-with-gen-ai", "type": "product"}, {"id": "funding_1", "label": "TrueFan AI Series A article", "url": "https://www.business-standard.com/companies/start-ups/ai-startup-truefan-raises-10-million-led-by-baring-pe-india-z3partners-126060400867_1.html", "type": "funding"}], "product_evidence": [{"claim": "The official site positions TrueFan AI as an enterprise platform for personalized AI videos in 175+ languages, with a single recording used across campaigns.", "source_ids": ["official_site"]}, {"claim": "The Studio login exposes a production app surface with Google, Microsoft, and email sign-in paths for creating AI avatar and personalized video workflows.", "source_ids": ["studio_login"]}, {"claim": "The BFSI page describes lead generation, cross-sell, referrals, customer retention, and training use cases plus SOC 2 and ISO 27001 security claims.", "source_ids": ["bfsi_page"]}], "market_context": {"primary_user": "Enterprise marketing, sales, training, and customer-engagement teams that need personalized video at campaign scale.", "category": "AI / ML", "differentiation": "TrueFan AI packages avatar-led localization, campaign personalization, and compliance messaging for enterprise video rather than consumer creator clips.", "why_now": "The June 2026 Series A follows enterprise adoption of AI avatars as brands try to scale video without reshooting every market or audience segment."}, "risks": [{"claim": "The open question is whether enterprise buyers will consistently approve AI-avatar output for regulated or high-trust brand communications.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 3, '175-language video engine', 'AI / ML', 'Series A', '$10M', NULL, NULL, NULL, 'China / Asia', 'ai video,avatars,marketing,training,enterprise', 'Baring Private Equity Partners India, Z3Partners', NULL, 0, 'truefan-ai.webp', 'ready', 'published', 'manual', '2026-06-06 05:56:19', '2026-06-06 05:56:19') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-tsuga', 'tsuga', 'www.tsuga.com', 'https://www.tsuga.com/', 'Tsuga', 'BYOC observability platform for logs, metrics, traces, and AI-agent telemetry.', 'The strong refusal is that customers should not ship sensitive telemetry into another vendor cloud. Tsuga runs the data plane inside the customer VPC while managing logs, metrics, traces, APM, pipelines, PII scanning, and upgrades. Compared to classic SaaS monitoring, the bet is control plus managed operations. The risk is whether forward-deployed tuning can scale beyond early enterprise accounts.', '{"verified_at": "2026-06-24", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.tsuga.com/", "type": "official"}, {"id": "official_product", "label": "Tsuga product overview", "url": "https://www.tsuga.com/product/overview", "type": "product"}, {"id": "official_agents", "label": "Agent-native observability page", "url": "https://www.tsuga.com/solutions/agent-native-observability", "type": "product"}, {"id": "official_letter", "label": "Tsuga founder funding note", "url": "https://www.tsuga.com/resources/blog/we-raised-35-million-here-is-why-and-what-it-means-", "type": "official"}, {"id": "funding_1", "label": "Tsuga Series A press release", "url": "https://www.tsuga.com/resources/blog/pr/tsuga-raises-35-million-series-a", "type": "funding"}], "product_evidence": [{"claim": "The product overview says Tsuga is a BYOC observability platform for logs, metrics, and traces that runs in the customer cloud.", "source_ids": ["official_product"]}, {"claim": "The product navigation exposes log management, application performance monitoring, metrics infrastructure, observability pipelines, and sensitive-data scanning.", "source_ids": ["official_site", "official_product"]}, {"claim": "The agent-native page and funding materials frame Tsuga around AI-era telemetry, agent loops, and observability data that should remain under customer control.", "source_ids": ["official_agents", "funding_1"]}], "market_context": {"primary_user": "Infrastructure, platform, and security teams running high-volume observability workloads in regulated or cost-sensitive environments.", "category": "Observability infrastructure", "differentiation": "Tsuga puts the data plane in the customer cloud while keeping a managed product experience for telemetry, pipelines, scanning, and tuning.", "why_now": "AI agents and autonomous deployments create more telemetry, sensitive interaction logs, and cost pressure than many third-party SaaS monitoring models were built to absorb."}, "risks": [{"claim": "The open question is whether Tsuga can keep BYOC operations simple enough as every customer environment, policy, and telemetry profile differs.", "basis": "VentureDex editorial assessment based on official product pages and the Series A materials."}]}', 4, '$35M Series A for BYOC telemetry', 'DevTools', 'Series A', '$35M', NULL, NULL, NULL, 'US', 'observability,infrastructure,byoc,ai agents,security', 'Singular', NULL, 1, 'tsuga.webp', 'ready', 'published', 'manual', '2026-06-24 06:00:32', '2026-06-24 06:00:32') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-turbo-law', 'turbo-law', 'turbolaw.ai', 'https://turbolaw.ai/', 'Turbo Law', 'AI litigation workspace connecting case facts, evidence, drafting, and strategy.', 'Defense litigation teams drown in disconnected pleadings, records, emails, and timelines. Turbo Law says its Fact Graph turns a matter into a connected representation of facts, events, records, people, and issues, and Tech.eu says it supports 1,800 active matters. Unlike document-only legal AI, the wedge is matter-level structure. The risk is whether privilege and ethical-wall controls hold across complex insurer workflows.', '{"verified_at": "2026-06-20", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://turbolaw.ai/", "type": "official"}, {"id": "funding_1", "label": "Tech.eu seed funding report", "url": "https://tech.eu/2026/06/18/revo-capital-leads-turbo-laws-38m-seed-round-to-expand-litigation-platform/", "type": "funding"}], "product_evidence": [{"claim": "The official site describes a Fact Graph that links facts, events, records, people, and issues across time and causation for litigation teams.", "source_ids": ["official_site"]}, {"claim": "The product surface describes a Unified Matter Ecosystem for documents, facts, timelines, emails, drafts, research, reports, strategy, templates, and client updates.", "source_ids": ["official_site"]}, {"claim": "Tech.eu says Turbo Law supports review, drafting, research, exposure analysis, strategy, and assistant workflows for defense law firms and insurers.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Defense law firms, insurance carriers, litigation partners, associates, and claims teams handling document-heavy matters.", "category": "Legal AI and litigation operations", "differentiation": "Turbo Law organizes each matter as a connected case graph rather than only summarizing files or providing a generic legal chatbot.", "why_now": "Litigation teams face rising document volumes and compressed response windows while insurers demand better matter visibility."}, "risks": [{"claim": "The risk is that firms may still require strict human review if privilege boundaries or ethical-wall enforcement vary by matter and client.", "basis": "VentureDex editorial assessment based on official product claims and funding-source review."}]}', 4, 'Litigation fact graph', 'SaaS', 'Seed', '$3.8M', NULL, NULL, NULL, 'US', 'legaltech,litigation,ai agents,insurance,knowledge graph', 'REVO Capital', '{"careers": "https://turbolaw.ai/careers"}', 1, 'turbo-law.webp', 'ready', 'published', 'manual', '2026-06-20 06:02:12', '2026-06-20 06:02:12') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-uncover', 'uncover', 'www.uncover.co', 'https://www.uncover.co/en-us', 'Uncover', 'Always-on marketing mix modeling and budget optimization for global brands.', 'Marketing mix modeling usually arrives as a quarterly deck after the budget fight is over. Uncover turns it into an always-on planning system with ROI 360, Budget Planner, Performance Results, and Uncovered Potential views, plus Google Meridian certification. Unlike a pure agency model, the public site and funding release frame it as recurring SaaS infrastructure for global brands. The risk is whether U.S. advertisers buy a Brazil-born MMM platform without a services-heavy sales motion.', '{"verified_at": "2026-06-07", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.uncover.co/en-us", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://careers.uncover.co/", "type": "official"}, {"id": "funding_1", "label": "Uncover Series A announcement", "url": "https://www.globenewswire.com/news-release/2026/06/03/3306227/0/en/Uncover-Raises-16-Million-to-Expand-Latin-America-s-Leading-Media-Measurement-Platform-to-The-U-S.html", "type": "funding"}], "product_evidence": [{"claim": "The official site presents Uncover as a Marketing Mix Modeling platform for global brands, with MMM Starter and platform sections for measurement teams, agencies, publishers, and brands.", "source_ids": ["official_site"]}, {"claim": "The public site exposes named product views including ROI 360, Budget Planner, Performance Results, and Uncovered Potential.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says the platform integrates with Google, TikTok, and Meta and has helped optimize more than $6 billion in media investment.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Enterprise marketing, measurement, media, and finance teams allocating budgets across online and offline channels.", "category": "SaaS", "differentiation": "Uncover packages MMM into recurring planning and optimization workflows rather than one-off measurement studies.", "why_now": "Privacy limits and fragmented media buying are pushing advertisers back toward MMM, while Google Meridian gives implementation partners a clearer platform wedge."}, "risks": [{"claim": "The open question is whether Uncover can scale in the U.S. without becoming a services-heavy analytics consultancy.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$6B MMM operating system', 'SaaS', 'Series A', '$16M', NULL, NULL, NULL, 'Latin America', 'marketing analytics,mmm,budget planning,media measurement,saas', 'Cloud9 Capital', '{"careers": "https://careers.uncover.co/"}', 1, 'uncover.webp', 'ready', 'published', 'manual', '2026-06-07 06:05:50', '2026-06-07 06:05:50') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-upriver', 'upriver', 'upriverdata.com', 'https://upriverdata.com/', 'Upriver', 'AI data engineering platform for enterprise data foundations.', 'The useful bet is that data engineering needs an agent that can inspect pipelines, not more backlog tickets. Upriver shows source discovery, lineage, code generation, quality checks, and pull-request workflows for data teams. Unlike warehouse dashboards, it works closer to the engineering loop where schemas, dbt, and repo changes happen. The risk is whether enterprises trust automated changes near production data pipelines.', '{"verified_at": "2026-06-10", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://upriverdata.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://upriverdata.com/careers", "type": "official"}, {"id": "funding_1", "label": "Upriver seed funding announcement", "url": "https://www.accessnewswire.com/newsroom/en/computers-technology-and-internet/upriver-raises-14m-to-automate-the-enterprise-data-foundation-for-1172362", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Upriver as an AI data engineering platform for automating the enterprise data foundation.", "source_ids": ["official_site"]}, {"claim": "The product surface shows source discovery, lineage, code generation, quality checks, and pull-request workflows for data teams.", "source_ids": ["official_site"]}, {"claim": "The careers page confirms an official hiring surface without requiring VentureDex to scrape roles, locations, or job counts.", "source_ids": ["careers_page"]}, {"claim": "The funding announcement says Upriver raised a $14M seed round led by Valley Capital Partners and Hetz Ventures.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Data engineering, analytics engineering, and platform teams responsible for pipelines, schemas, quality, and lineage.", "category": "DevTools", "differentiation": "Upriver moves AI into pipeline and pull-request work rather than keeping it at the observability or dashboard layer.", "why_now": "Enterprises are trying to ship AI features on data foundations that still depend on manual pipeline maintenance and schema triage."}, "risks": [{"claim": "The open question is how safely Upriver can suggest or apply changes around production data contracts, lineage, and access controls.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Data pipeline agent', 'DevTools', 'Seed', '$14M', NULL, NULL, NULL, 'US', 'data engineering,ai agents,data pipelines,devtools,analytics infrastructure', 'Valley Capital Partners, Hetz Ventures', '{"careers": "https://upriverdata.com/careers"}', 1, 'upriver.webp', 'ready', 'published', 'manual', '2026-06-10 05:57:38', '2026-06-10 05:57:38') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-val-town', 'val-town', 'val.town', 'https://val.town', 'Val Town', 'Social website and API for writing and running code.', 'Putting running code inside a social feed sounds gimmicky until you try it. Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks. That is a real bet against repo-first developer tooling. It feels closer to what Gists wanted to be than another serverless dashboard.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://val.town", "type": "official"}, {"id": "funding_1", "label": "Val Town Blog", "url": "https://blog.val.town/blog/seed/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Val Town: Social website and API for writing and running code.", "source_ids": ["official_site"]}, {"claim": "Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Code as social media", "why_now": "Recent source-backed funding and public product evidence make social coding, serverless, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Code as social media', 'DevTools', 'Seed', '$5.5M', 2022, '5-10', 'Brooklyn', 'US', 'social coding,serverless,developer tools,code sharing', 'Sequoia Capital Scout, Craft Ventures, Tom Preston-Werner', '{"github": "https://github.com/val-town", "twitter": "https://x.com/valabordar", "linkedin": "https://linkedin.com/company/val-town", "careers": "https://val.town/careers"}', 0, 'val-town.webp', 'ready', 'published', 'manual', '2026-04-18 13:28:51', '2026-04-18 13:28:51') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vapi', 'vapi', 'vapi.ai', 'https://vapi.ai', 'Vapi', 'Voice AI infrastructure for building, deploying, and managing phone agents.', 'The smart bet is that voice agents need latency infrastructure, not another bot builder. Vapi exposes call workflows, tool integrations, guardrails, SOC 2/HIPAA/PCI posture, and claims 1B calls, 2.5M+ agents, 750K developers, and sub-500ms latency. Compared with Twilio wrappers or contact-center suites, it sells the voice runtime beneath Ring-scale support. The risk is that voice AI becomes a commodity inside every CX platform.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://vapi.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/12/vapi-hits-500m-valuation-as-amazon-ring-chose-its-ai-platform-over-40-rivals/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Vapi: Voice AI infrastructure for building, deploying, and managing phone agents.", "source_ids": ["official_site"]}, {"claim": "Vapi exposes call workflows, tool integrations, guardrails, SOC 2/HIPAA/PCI posture, and claims 1B calls, 2.5M+ agents, 750K developers, and sub-500ms latency.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "1B calls on voice-agent platform", "why_now": "Recent source-backed funding and public product evidence make voice ai, ai agents, developer tools worth tracking."}, "risks": [{"claim": "The risk is that voice AI becomes a commodity inside every CX platform.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '1B calls on voice-agent platform', 'DevTools', 'Series B', '$50M', NULL, NULL, NULL, 'US', 'voice ai,ai agents,developer tools,customer support', 'Peak XV Partners', '{"careers": "https://vapi.ai/careers"}', 0, 'vapi.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vector', 'vector', 'www.vector.co', 'https://www.vector.co', 'Vector', 'Contact-level ad audiences and MCP analytics for B2B marketers.', 'The interesting choice is putting names back into ad targeting instead of hiding inside account segments. Vector shows visitor feeds, named buyer audiences, LinkedIn/Google/Reddit sync, 7.8% LinkedIn CTR, 17x ROI, and an MCP for asking campaign questions in Claude or ChatGPT. Unlike retargeting, it filters for exact ICP contacts already moving. The risk is that contact-level precision invites privacy pushback as fast as pipeline.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.vector.co", "type": "official"}, {"id": "funding_1", "label": "Vector", "url": "https://www.vector.co/blog/we-just-raised-10m-to-build-the-ai-platform-that-makes-marketers-superhuman", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Vector: Contact-level ad audiences and MCP analytics for B2B marketers.", "source_ids": ["official_site"]}, {"claim": "Vector shows visitor feeds, named buyer audiences, LinkedIn/Google/Reddit sync, 7.8% LinkedIn CTR, 17x ROI, and an MCP for asking campaign questions in Claude or ChatGPT.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "$10M Series A for Vector MCP", "why_now": "Recent source-backed funding and public product evidence make b2b marketing, advertising, mcp worth tracking."}, "risks": [{"claim": "The risk is that contact-level precision invites privacy pushback as fast as pipeline.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$10M Series A for Vector MCP', 'SaaS', 'Series A', '$10M', NULL, NULL, NULL, 'US', 'b2b marketing,advertising,mcp,marketing analytics', 'SignalFire, HubSpot Ventures', NULL, 1, 'vector.webp', 'ready', 'published', 'manual', '2026-05-18 03:08:31', '2026-05-18 03:08:31') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-verse', 'verse', 'verse.inc', 'https://verse.inc/', 'Verse', 'Energy intelligence platform accelerating data-center grid connection.', 'Power has become the bottleneck AI companies cannot hide behind software. Verse''s Aria reads market prices, weather and live asset telemetry, while Dispatch Intelligence uses on-site batteries and solar so data centers can flex the grid without slowing GPUs. Unlike curtailment tools, the product sells speed-to-power and up to 3 years faster connection. The risk is that utility approvals may still move slower than the software.', '{"verified_at": "2026-06-19", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://verse.inc/", "type": "official"}, {"id": "funding_1", "label": "Official Series B announcement", "url": "https://verse.inc/newsroom/series-b", "type": "funding"}, {"id": "official_letter", "label": "Official founders letter", "url": "https://verse.inc/company/founders-letter", "type": "official"}], "product_evidence": [{"claim": "The homepage says Verse gets data centers online up to three years faster and uses Aria to read market prices, weather, and live telemetry.", "source_ids": ["official_site"]}, {"claim": "The Series B announcement says Dispatch Intelligence orchestrates on-site energy resources alongside existing grid infrastructure.", "source_ids": ["funding_1"]}, {"claim": "The founders letter says Aria grew from contract management, PPA tools, risk management, and utility bill management for large energy users.", "source_ids": ["official_letter"]}], "market_context": {"primary_user": "Data-center developers, AI infrastructure operators, and large energy buyers waiting on grid interconnection or power capacity.", "category": "Energy infrastructure software", "differentiation": "Verse links energy market intelligence, asset telemetry, contracts, and dispatch control to shorten the path to power.", "why_now": "AI data-center demand is turning power access into a revenue bottleneck for compute-heavy companies."}, "risks": [{"claim": "The open question is whether software-driven dispatch can overcome slow utility approvals, grid constraints, and site-specific energy economics.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Speed-to-power software', 'Climate / Sustainability', 'Series B', '$54M', NULL, NULL, 'San Francisco, CA', 'US', 'energy,data centers,grid,ai infrastructure', 'Bessemer Venture Partners', '{"careers": "https://verse.inc/company/careers"}', 1, 'verse.webp', 'ready', 'published', 'manual', '2026-06-19 05:55:41', '2026-06-19 05:55:41') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vinyl-equity', 'vinyl-equity', 'www.vinylequity.com', 'https://www.vinylequity.com/', 'Vinyl Equity', 'Modern transfer agency infrastructure for private markets.', 'The useful bet is that private-market transfer work should feel like software infrastructure, not a PDF-and-email service desk. Vinyl Equity shows issuer services, registrar workflows, restricted securities, proxy and AGM tools, cap-table ingestion, and realtime reporting. Unlike legacy agents, it exposes operational controls for corporate actions. The risk is regulatory trust: issuers may still prefer incumbent transfer-agent brands.', '{"verified_at": "2026-06-10", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.vinylequity.com/", "type": "official"}, {"id": "careers_page", "label": "Official careers page", "url": "https://www.vinylequity.com/careers", "type": "official"}, {"id": "funding_1", "label": "Vinyl Equity Series A funding announcement", "url": "https://www.prnewswire.com/news-releases/vinyl-equity-raises-20-million-led-by-jump-capital-as-its-infrastructure-powers-modern-capital-markets-and-corporate-transactions-302795321.html", "type": "funding"}], "product_evidence": [{"claim": "The official site positions Vinyl Equity as modern transfer agency infrastructure for corporate transactions and capital markets.", "source_ids": ["official_site"]}, {"claim": "The product surface shows issuer services, registrar workflows, restricted securities, proxy and AGM tools, cap-table ingestion, and reporting.", "source_ids": ["official_site"]}, {"claim": "Vinyl Equity cites SOC 2 controls, more than 65k holders, and more than 40k transactions as evidence of operating maturity.", "source_ids": ["official_site"]}, {"claim": "The funding announcement says Vinyl Equity raised a $20M Series A led by Jump Capital.", "source_ids": ["funding_1"]}], "market_context": {"primary_user": "Private-company issuers, fund administrators, legal teams, and capital-markets operators managing securities records and corporate actions.", "category": "Fintech", "differentiation": "Vinyl Equity treats transfer agency as programmable infrastructure rather than a manually coordinated service desk.", "why_now": "Private markets, secondary transactions, and corporate actions are creating more demand for digital recordkeeping and compliant investor operations."}, "risks": [{"claim": "The open question is whether newer transfer-agent infrastructure can win issuer trust against incumbents with longer regulatory histories.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Transfer-agent rails', 'Fintech', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'fintech,capital markets,transfer agency,private markets,compliance', 'Jump Capital', '{"careers": "https://www.vinylequity.com/careers"}', 1, 'vinyl-equity.webp', 'ready', 'published', 'manual', '2026-06-10 05:57:38', '2026-06-10 05:57:38') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-willow', 'willow', 'withwillow.ai', 'https://withwillow.ai/', 'Willow', 'Governance layer for AI agents, MCP tools, permissions, and audit trails.', 'The useful angle is not another agent gateway; it is permissioning for the messy agents employees already bring to work. Willow maps agents, tools, MCP servers, identities, policies, and audit trails across 1000+ connectors. Unlike routing-only gateways, it tries to govern what an agent can do inside each tool. The risk is whether teams accept a control layer before shadow AI becomes painful enough.', '{"verified_at": "2026-06-05", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://withwillow.ai/", "type": "official"}, {"id": "funding_1", "label": "Willow seed announcement", "url": "https://www.prnewswire.com/news-releases/willow-raises-7m-seed-to-ensure-enterprises-can-fully-oversee-and-govern-autonomous-agents-302791492.html", "type": "funding"}], "product_evidence": [{"claim": "The official site shows discovery for AI agents, tools, and MCP servers, plus shadow AI detection and usage analytics.", "source_ids": ["official_site"]}, {"claim": "Willow describes build/runtime guards, permissioned tool access, audit trails, IdP connection, Slack/Jira/GitHub connectors, and API-to-MCP conversion.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Security, IT, compliance, and AI-platform teams letting employees use autonomous agents at work.", "category": "AI / ML", "differentiation": "Willow governs agent identity, tool permissions, MCP access, and auditability rather than only routing agent traffic.", "why_now": "The June 2026 seed round lands as enterprises discover unmanaged agents and need enforceable controls beyond policy documents."}, "risks": [{"claim": "The open question is whether teams adopt a control layer early enough, before unmanaged agent usage creates a visible incident.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Agent permission layer', 'AI / ML', 'Seed', '$7M', NULL, NULL, NULL, 'Europe', 'ai agents,security,mcp,identity,governance', 'Hetz Ventures', '{"careers": "https://withwillow.ai/careers"}', 1, 'willow.webp', 'ready', 'published', 'manual', '2026-06-05 05:53:18', '2026-06-05 05:53:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-wirobotics', 'wirobotics', 'corp.wirobotics.com', 'https://corp.wirobotics.com/en/product/allex', 'WIRobotics', 'Wearable and humanoid robots built from human movement data.', 'The real bet is that humanoids should learn from exoskeletons, not lab demos. WIRobotics has 3,000 WIM units sold, three CES awards, gait datasets from wearable robots, and ALLEX specs like 15-DoF hands, 0.5 mm repeatability, and 30 kg hook grip. Compared with blank-slate humanoid hype, this starts from human movement in the field. The risk is whether research platforms become durable products.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://corp.wirobotics.com/en/product/allex", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/wirobotics-secures-approximately-krw-100-billion-usd-68-million-series-b-funding-302772164.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes WIRobotics: Wearable and humanoid robots built from human movement data.", "source_ids": ["official_site"]}, {"claim": "WIRobotics has 3,000 WIM units sold, three CES awards, gait datasets from wearable robots, and ALLEX specs like 15-DoF hands, 0.5 mm repeatability, and 30 kg hook grip.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "3,000 WIM units, $68M Series B", "why_now": "Recent source-backed funding and public product evidence make robotics, wearables, humanoids worth tracking."}, "risks": [{"claim": "The risk is whether research platforms become durable products.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '3,000 WIM units, $68M Series B', 'Other', 'Series B', '$68M', NULL, NULL, NULL, 'China / Asia', 'robotics,wearables,humanoids,physical ai', 'JB Investment', NULL, 1, 'wirobotics.webp', 'ready', 'published', 'manual', '2026-05-25 10:27:00', '2026-05-25 10:27:00') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-zerodrift', 'zerodrift', 'www.zerodrift.ai', 'https://www.zerodrift.ai/', 'ZeroDrift', 'Compliance firewall that gates regulated AI messages before delivery.', 'Regulated AI needs a pre-send checkpoint, not another archive after the damage is done. ZeroDrift puts Anchor between agents, chat, email, docs, and marketing, with pass, rewrite, block, and escalate decisions across a public 1000 messages/day demo. Unlike monitoring tools that discover violations later, it tries to stop SEC, FINRA, HIPAA, and insurance mistakes before output leaves. The risk is whether firms trust a model-mediated gate in high-liability workflows.', '{"verified_at": "2026-06-05", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.zerodrift.ai/", "type": "official"}, {"id": "funding_1", "label": "ZeroDrift seed announcement", "url": "https://www.globenewswire.com/news-release/2026/06/02/3305264/0/en/zerodrift-raises-10m-seed-round-to-build-the-compliance-firewall-for-ai.html", "type": "funding"}], "product_evidence": [{"claim": "The official site describes Anchor as a compliance model that evaluates every AI-generated message against regulations, firm policies, restricted data rules, and customer controls.", "source_ids": ["official_site"]}, {"claim": "ZeroDrift lists pass, rewrite, block, and escalate decisions across AI agents, chat, systems, email, docs, and marketing surfaces.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Compliance officers, AI leaders, and platform teams in financial services, insurance, healthcare, and other regulated sectors.", "category": "SaaS", "differentiation": "ZeroDrift sits inline before AI communication leaves the firm, instead of reviewing archives after a regulated message has already been sent.", "why_now": "The June 2026 seed round follows a wave of enterprise AI-agent deployment where regulated communication needs real-time enforcement."}, "risks": [{"claim": "The open question is whether regulated firms trust a model-mediated enforcement layer in workflows where false blocks and false passes both carry cost.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Pre-send compliance gate', 'SaaS', 'Seed', '$10M', NULL, NULL, NULL, 'US', 'compliance,ai governance,financial services,healthcare,agents', 'Andreessen Horowitz', NULL, 1, 'zerodrift.webp', 'ready', 'published', 'manual', '2026-06-05 05:53:18', '2026-06-05 05:53:18') ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = excluded.first_seen_at, published_at = excluded.published_at, created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
