INSERT INTO weekly_issues (id, issue_number, title, editorial_intro, published_at, status) VALUES ('w-1', 1, 'The tools that changed how we build', 'For our first issue, we picked tools that changed daily software work through product choices, not just category timing. The common thread is a sharper workflow bet: keep the user''s existing context, remove one old source of friction, and make the product feel closer to the work itself.', '2026-05-25', 'published') ON CONFLICT(issue_number) DO UPDATE SET id = excluded.id, title = excluded.title, editorial_intro = excluded.editorial_intro, status = excluded.status, published_at = excluded.published_at;
INSERT INTO weekly_issues (id, issue_number, title, editorial_intro, published_at, status) VALUES ('w-2', 2, 'Where AI Has to Leave Receipts', 'This week was not about another batch of general-purpose agents. The stronger pattern was AI moving into environments where every action needs a source trail, permission boundary, audit log, or human review path: defense systems, bank workflows, litigation files, financial models, and enterprise agent security.', '2026-06-01', 'published') ON CONFLICT(issue_number) DO UPDATE SET id = excluded.id, title = excluded.title, editorial_intro = excluded.editorial_intro, status = excluded.status, published_at = excluded.published_at;
INSERT INTO weekly_issues (id, issue_number, title, editorial_intro, published_at, status) VALUES ('w-3', 3, 'AI Is Moving Into the Awkward Work', 'This week''s useful AI companies were not selling a generic assistant. They were trying to make software act inside awkward rooms: identity remediation, fresh-grocery replenishment, agent permissions, liquor-store operations, lab workflows, revenue follow-up, and enterprise video approval.', '2026-06-08', 'published') ON CONFLICT(issue_number) DO UPDATE SET id = excluded.id, title = excluded.title, editorial_intro = excluded.editorial_intro, status = excluded.status, published_at = excluded.published_at;
INSERT INTO weekly_issues (id, issue_number, title, editorial_intro, published_at, status) VALUES ('w-4', 4, 'AI Is Taking the Operations Seat', 'This issue follows AI products that move from suggestions into operational work: machine control, healthcare administration, marketing execution, grid dispatch, litigation, product planning, and freight. The common pattern is a tighter loop between evidence, action, and human handback, not an unsupported claim that autonomy is already solved.', '2026-06-24', 'published') ON CONFLICT(issue_number) DO UPDATE SET id = excluded.id, title = excluded.title, editorial_intro = excluded.editorial_intro, status = excluded.status, published_at = excluded.published_at;
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-cursor', 1, 'Strong product-shape pick: the bet is specific and visible, while the evidence boundary is product design plus sourced financing.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-linear', 2, 'High-conviction workflow pick: Linear''s product choices are clear, but quantified adoption claims should remain outside the issue unless sourced.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-perplexity', 3, 'Strong interface bet: the product change is concrete, while scale and accuracy claims need separate source-backed review.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-supabase', 4, 'Clear developer-platform pick: the Postgres-centered bet is easy to verify, while workload-level claims need case-specific evidence.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-resend', 5, 'Focused workflow pick: Resend''s API and React Email pairing is concrete, while delivery-scale claims should stay source-bound.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-picogrid', 1, 'Picogrid is the strongest pick when the question is whether defense automation needs a neutral integration layer before it needs more point hardware.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-gray-swan', 2, 'Gray Swan is compelling because it treats AI security as a live adversarial loop, not a static compliance checklist.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-geordie-ai', 3, 'Geordie AI is worth tracking because it focuses on what agents actually do with tools, permissions, and systems after deployment.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-daloopa', 4, 'Daloopa is the finance pick because the product bet is that AI answers need filing-level provenance before they need more chat.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-saris', 5, 'Saris is the banking workflow pick because it puts agent execution next to approval, audit, and legacy-system constraints.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-crimson', 6, 'Crimson is the legal pick because it treats source-backed case understanding as the product, not as a decoration around a chatbot.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-2', 'startup-canals', 7, 'Canals is the supply-chain pick because it starts with the messy transaction documents where generic automation usually breaks.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-offroad', 1, 'Offroad is the cleanest security pick here because it treats agent-era identity as an action workflow, not a static risk inventory.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-freshflow', 2, 'Freshflow earns the slot because fresh grocery is a real test of whether AI can handle perishable, local, operational decisions.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-willow', 3, 'Willow is worth tracking because agent governance becomes concrete when permissions, identities, and audit logs are first-class product objects.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-scotch', 4, 'Scotch belongs here because the best operational software often starts by taking an unfashionable vertical seriously.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-scispot', 5, 'Scispot is a good pick because lab automation only becomes useful when it connects samples, inventory, integrations, and analysis surfaces.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-airspeed', 6, 'Airspeed is notable because it tries to close the loop from customer context to revenue action instead of stopping at insight capture.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-3', 'startup-truefan-ai', 7, 'TrueFan AI is included because personalized video becomes a real product question only when distribution, approval, and compliance are part of the surface.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-kyber', 1, 'Kyber is the most infrastructure-shaped pick this week: credible public evidence for the control stack, with field reliability still the key unanswered test.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-frontier-health', 2, 'Frontier Health is compelling because it frames healthcare AI as accountable admin execution, not just patient chat or document summarization.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-gradial', 3, 'Gradial is the enterprise-software version of the theme: useful if agents can carry execution work without breaking brand governance.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-verse', 4, 'Verse is worth tracking because it treats AI infrastructure growth as a power-operations problem with software in the control loop.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-turbo-law', 5, 'Turbo Law is notable because its product evidence points at case structure, not a generic legal assistant layered over files.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-devplan', 6, 'Devplan is a strong fit for the issue because it addresses the coordination layer that gets worse when code ships faster.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-4', 'startup-cargofy', 7, 'Cargofy is interesting because it sells AI as logistics labor across messy channels, with exception handling as the real test.');
